import React, { forwardRef } from 'react';

// G7Core ņĀäņŚŁ Ļ░Øņ▓┤ņØś ņŖżĒāĆņØ╝ ĒŚ¼ĒŹ╝ ņĀæĻĘ╝
const G7Core = () => (window as any).G7Core;

export interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'success';
  size?: 'sm' | 'md' | 'lg';
}

/**
 * ĻĖ░ļ│Ė ļ▓äĒŖ╝ ņ╗┤ĒÅ¼ļäīĒŖĖ
 */
export const Button = forwardRef<HTMLButtonElement, ButtonProps>(({
  children,
  variant = 'primary',
  size = 'md',
  className = '',
  ...props
}, ref) => {
  const baseClasses = 'inline-flex items-center justify-center';

  // G7Core.style.mergeClassesļź╝ ņé¼ņÜ®ĒĢśņŚ¼ ņČ®ļÅīĒĢśļŖö Tailwind Ēü┤ļ×śņŖż ļ│æĒĢ®
  const mergedClassName = G7Core()?.style?.mergeClasses?.(baseClasses, className)
    ?? `${baseClasses} ${className}`;

  return (
    <button
      ref={ref}
      className={mergedClassName}
      {...props}
    >
      {children}
    </button>
  );
});

Button.displayName = 'Button';
