/**
 * FileDropZone ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * ĒīīņØ╝ņØä ļō£ļ×śĻĘĖ ņĢż ļō£ļĪŁĒĢśĻ▒░ļéś Ēü┤ļ”ŁĒĢśņŚ¼ ņäĀĒāØĒĢĀ ņłś ņ×łļŖö ņśüņŚŁņ×ģļŗłļŗż.
 *
 * @module composite/FileUploader/FileDropZone
 */

import React from 'react';

import { Div } from '../../basic/Div';
import { P } from '../../basic/P';
import { I } from '../../basic/I';

import { t } from './utils';

export interface FileDropZoneProps {
  /** ļō£ļ×śĻĘĖ ņśżļ▓ä ņāüĒā£ */
  isDragOver: boolean;
  /** ņČöĻ░Ć Ļ░ĆļŖź ņŚ¼ļČĆ */
  canAddMore: boolean;
  /** ĒīīņØ╝ ņ▓śļ”¼ ĒĢĖļōżļ¤¼ */
  onFiles: (files: FileList) => void;
  /** ļō£ļ×śĻĘĖ ņśżļ▓ä ņāüĒā£ ņäżņĀĢ */
  setIsDragOver: (value: boolean) => void;
  /** Input ņÜöņåī ref */
  inputRef: React.RefObject<HTMLInputElement | null>;
  /** ĒŚłņÜ® ĒÖĢņ×źņ×É */
  accept?: string;
  /** ņĄ£ļīĆ ĒīīņØ╝ ņłś */
  maxFiles: number;
  /** ņĄ£ļīĆ ĒīīņØ╝ Ēü¼ĻĖ░ (MB) */
  maxSize: number;
  /** ņ×ÉņŗØ ņÜöņåī */
  children?: React.ReactNode;
}

export const FileDropZone: React.FC<FileDropZoneProps> = ({
  isDragOver,
  canAddMore,
  onFiles,
  setIsDragOver,
  inputRef,
  accept,
  maxFiles,
  maxSize,
  children,
}) => {
  return (
    <Div
      className={`
        relative border-2 border-dashed rounded-lg transition-colors
        ${
          isDragOver
            ? 'border-blue-500 bg-blue-50 dark:bg-blue-900/20'
            : 'border-gray-300 dark:border-gray-600'
        }
      `}
      onDragOver={(e) => {
        e.preventDefault();
        if (canAddMore) setIsDragOver(true);
      }}
      onDragLeave={() => setIsDragOver(false)}
      onDrop={(e) => {
        e.preventDefault();
        setIsDragOver(false);
        if (canAddMore) {
          onFiles(e.dataTransfer.files);
        }
      }}
    >
      <input
        ref={inputRef}
        type="file"
        multiple
        accept={accept}
        onChange={(e) => e.target.files && onFiles(e.target.files)}
        className="hidden"
      />

      {/* ĒīīņØ╝ņØ┤ ņŚåņØä ļĢī: ļ╣ł ļō£ļĪŁņĪ┤ */}
      {!children && (
        <Div
          className="p-8 text-center cursor-pointer hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors"
          onClick={() => inputRef.current?.click()}
        >
          <I className="fa-solid fa-cloud-arrow-up text-4xl text-gray-400 dark:text-gray-500 mb-4" />
          <P className="text-sm text-gray-600 dark:text-gray-400">
            {t('attachment.drop_or_click')}
          </P>
          <P className="text-xs text-gray-500 dark:text-gray-500 mt-2">
            {t('attachment.upload_limit', { maxFiles, maxSize })}
            {accept && ` (${accept})`}
          </P>
        </Div>
      )}

      {/* ĒīīņØ╝ņØ┤ ņ×łņØä ļĢī: ņ×ÉņŗØ ņÜöņåī ļĀīļŹöļ¦ü */}
      {children}
    </Div>
  );
};

export default FileDropZone;