  /** ĒāŁņŚÉ Ēæ£ņŗ£ĒĢĀ ņĄ£ļīĆ Ļ▓īņŗ£ĒīÉ ņłś */
  maxVisibleBoards?: number;
  /** ļ¬©ļ░öņØ╝ ļ®öļē┤ ņŚ┤ĻĖ░ ņĮ£ļ░▒ */
