// eslint-disable-next-line @typescript-eslint/no-explicit-any
const G7Core = (window as any).G7Core;

/**
 * ĒīīņØ╝ Ēü¼ĻĖ░ļź╝ ņØĮĻĖ░ ņē¼ņÜ┤ ĒśĢņŗØņ£╝ļĪ£ ļ│ĆĒÖśĒĢ®ļŗłļŗż.
 */
export const formatFileSize = (bytes: number): string => {
  const units = ['B', 'KB', 'MB', 'GB'];
  let i = 0;
  let size = bytes;
  while (size >= 1024 && i < units.length - 1) {
    size /= 1024;
    i++;
  }
  return `${size.toFixed(2)} ${units[i]}`;
};

/**
 * API ņŚÉļ¤¼ ņØæļŗĄņŚÉņä£ ņāüņäĖ ļ®öņŗ£ņ¦Ćļź╝ ņČöņČ£ĒĢ®ļŗłļŗż.
 */
export const extractErrorMessage = (error: unknown): string => {
  // Axios ņŚÉļ¤¼ ņØæļŗĄ ĻĄ¼ņĪ░ ņ▓śļ”¼
  if (error && typeof error === 'object') {
    const axiosError = error as {
      response?: {
        data?: {
          message?: string;
          errors?: Record<string, string[]>;
        };
      };
      message?: string;
    };

    // API ņØæļŗĄņØś message ĒĢäļō£
    if (axiosError.response?.data?.message) {
      return axiosError.response.data.message;
    }

    // Laravel validation ņŚÉļ¤¼ (errors Ļ░Øņ▓┤ņØś ņ▓½ ļ▓łņ¦Ė ļ®öņŗ£ņ¦Ć)
    if (axiosError.response?.data?.errors) {
      const firstError = Object.values(axiosError.response.data.errors)[0];
      if (Array.isArray(firstError) && firstError[0]) {
        return firstError[0];
      }
    }

    // ņØ╝ļ░ś ņŚÉļ¤¼ ļ®öņŗ£ņ¦Ć
    if (axiosError.message) {
      return axiosError.message;
    }
  }

  // Error ņØĖņŖżĒä┤ņŖż
  if (error instanceof Error) {
    return error.message;
  }

  return 'ņŚģļĪ£ļō£ ņŗżĒī©';
};

/**
 * MIME ĒāĆņ×ģņŚÉ ļö░ļźĖ Font Awesome ņĢäņØ┤ņĮś Ēü┤ļ×śņŖżļź╝ ļ░śĒÖśĒĢ®ļŗłļŗż.
 */
export const getFileIcon = (mimeType: string): string => {
  if (!mimeType) return 'fa-file';
  if (mimeType.startsWith('image/')) return 'fa-file-image';
  if (mimeType.startsWith('video/')) return 'fa-file-video';
  if (mimeType.startsWith('audio/')) return 'fa-file-audio';
  if (mimeType === 'application/pdf') return 'fa-file-pdf';
  if (mimeType.includes('word') || mimeType.includes('document')) return 'fa-file-word';
  if (mimeType.includes('excel') || mimeType.includes('spreadsheet')) return 'fa-file-excel';
  if (mimeType.includes('zip') || mimeType.includes('compressed')) return 'fa-file-zipper';
  return 'fa-file';
};

/**
 * G7Core.t() ļ▓łņŚŁ ĒĢ©ņłś ņ░ĖņĪ░
 */
export const t = (key: string, params?: Record<string, string | number>) =>
  G7Core?.t?.(key, params) ?? key;