/**
 * UserInfo ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * Ļ▓īņŗ£ĻĖĆ ņ×æņä▒ņ×É ņĀĢļ│┤ļź╝ Ēæ£ņŗ£ĒĢśĻ│Ā ļō£ļĪŁļŗżņÜ┤ ļ®öļē┤ļź╝ ņĀ£Ļ│ĄĒĢśļŖö ĒåĄĒĢ® ņ╗┤ĒÅ¼ļäīĒŖĖņ×ģļŗłļŗż.
 * - ņ×æņä▒ņ×É ņØ┤ļ”ä, ņä£ļĖīĒģŹņŖżĒŖĖ Ēæ£ņŗ£
 * - Ēü┤ļ”Ł ņŗ£ ļō£ļĪŁļŗżņÜ┤ ļ®öļē┤ (ĒÜīņøÉņØĖ Ļ▓ĮņÜ░)
 * - ļ╣äĒÜīņøÉņØĖ Ļ▓ĮņÜ░ ļ░░ņ¦Ć Ēæ£ņŗ£
 * - ĒāłĒć┤ĒĢ£ ņé¼ņÜ®ņ×ÉņØĖ Ļ▓ĮņÜ░ "ĒāłĒć┤ĒĢ£ ņé¼ņÜ®ņ×É" ĒģŹņŖżĒŖĖ Ēæ£ņŗ£
 *
 * ## Props ņÜ░ņäĀņł£ņ£ä
 * ļ¬ģņŗ£ņĀüņ£╝ļĪ£ ņĀäļŗ¼ĒĢ£ propsĻ░Ć authorņŚÉņä£ ņČöņČ£ĒĢ£ Ļ░Æļ│┤ļŗż ņÜ░ņäĀĒĢ®ļŗłļŗż.
 * - ņØ┤ļ”ä: text > name > author.name
 * - ņé¼ņÜ®ņ×É ID: userId > author.id
 * - ļ╣äĒÜīņøÉ ņŚ¼ļČĆ: isGuest > author.is_guest
 * - ĒāłĒć┤ ņŚ¼ļČĆ: isWithdrawn || author.status === 'withdrawn'
 *
 * @example
 * // ļĀłņØ┤ņĢäņøā JSONņŚÉņä£ ņé¼ņÜ® (author Ļ░Øņ▓┤ ņĀäļŗ¼ - ĻČīņ×ź)
 * {
 *   "type": "composite",
 *   "name": "UserInfo",
 *   "props": {
 *     "author": "{{post.author}}",
 *     "subText": "{{post.created_at | datetime}}"
 *   }
 * }
 *
 * @example
 * // authorņÖĆ Ļ░£ļ│ä props Ēś╝ĒĢ® ņé¼ņÜ® (Ļ░£ļ│ä propsĻ░Ć ņÜ░ņäĀ)
 * {
 *   "type": "composite",
 *   "name": "UserInfo",
 *   "props": {
 *     "author": "{{post.author}}",
 *     "name": "Ļ┤Ćļ”¼ņ×É",
 *     "subText": "{{post.created_at | datetime}}"
 *   }
 * }
 * // author.nameņØ┤ "ĒÖŹĻĖĖļÅÖ"ņØ┤ņ¢┤ļÅä "Ļ┤Ćļ”¼ņ×É"Ļ░Ć Ēæ£ņŗ£ļÉ©
 */

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { createPortal } from 'react-dom';
import { Div } from '../basic/Div';
import { Button } from '../basic/Button';
import { Span } from '../basic/Span';
import { Icon } from '../basic/Icon';

// G7Core ņ░ĖņĪ░
const getG7Core = () => (window as any).G7Core;

// G7Core.t() ļ▓łņŚŁ ĒĢ©ņłś ņ░ĖņĪ░
const t = (key: string, params?: Record<string, string | number>) =>
  (window as any).G7Core?.t?.(key, params) ?? key;

/**
 * ļ®öļē┤ ĒĢŁļ¬® ņäżņĀĢ ņØĖĒä░ĒÄśņØ┤ņŖż
 */
export interface MenuItemConfig {
  /** ļ®öļē┤ ĒĢŁļ¬® ņŗØļ│äņ×É */
  key: string;
  /** Ēæ£ņŗ£ ĒģŹņŖżĒŖĖ */
  label: string;
  /** ņĢäņØ┤ņĮś ņØ┤ļ”ä (ņäĀĒāØ) */
  icon?: string;
  /** ņØ┤ļÅÖ Ļ▓ĮļĪ£ ({{userId}} ņ╣śĒÖś ņ¦ĆņøÉ) */
  path?: string;
  /** ņ╗żņŖżĒģĆ Ēü┤ļ”Ł ĒĢĖļōżļ¤¼ (ņäĀĒāØ) */
  onClick?: () => void;
  /** Ēæ£ņŗ£ ņŚ¼ļČĆ (ĻĖ░ļ│Ė: true) */
  show?: boolean;
}

/**
 * Author Ļ░Øņ▓┤ ņØĖĒä░ĒÄśņØ┤ņŖż
 */
export interface AuthorInfo {
  /** ņé¼ņÜ®ņ×É ID */
  id?: string | number;
  /** ņé¼ņÜ®ņ×É UUID */
  uuid?: string;
  /** ņé¼ņÜ®ņ×É ņØ┤ļ”ä */
  name?: string;
  /** ņĢäļ░öĒāĆ URL */
  avatar?: string;
  /** ņé¼ņÜ®ņ×É ņāüĒā£ */
  status?: 'active' | 'inactive' | 'blocked' | 'withdrawn';
  /** ļ╣äĒÜīņøÉ ņŚ¼ļČĆ */
  is_guest?: boolean;
}

export interface UserInfoProps {
  /**
   * ņ×æņä▒ņ×É Ļ░Øņ▓┤ (ĻČīņ×ź)
   * API ņØæļŗĄņØś author Ļ░Øņ▓┤ļź╝ ĻĘĖļīĆļĪ£ ņĀäļŗ¼ĒĢśļ®┤ ļÉ®ļŗłļŗż.
   * Ļ░£ļ│ä props(name, userId ļō▒)Ļ░Ć ĒĢ©Ļ╗ś ņĀäļŗ¼ļÉśļ®┤ Ļ░£ļ│ä propsĻ░Ć ņÜ░ņäĀĒĢ®ļŗłļŗż.
   */
  author?: AuthorInfo;

  /**
   * ņé¼ņÜ®ņ×É ņØ┤ļ”ä (author.nameļ│┤ļŗż ņÜ░ņäĀ)
   */
  name?: string;

  /**
   * ņé¼ņÜ®ņ×É ID (author.idļ│┤ļŗż ņÜ░ņäĀ)
   */
  userId?: string | number;

  /**
   * Ēæ£ņŗ£ĒĢĀ ņä£ļĖī ĒģŹņŖżĒŖĖ (ļéĀņ¦£, ņŗ£Ļ░ä ļō▒)
   */
  subText?: string;

  /**
   * ņä£ļĖī ĒģŹņŖżĒŖĖņØś title ņåŹņä▒ (tooltipņÜ® ņøÉļ│Ė datetime)
   */
  subTextTitle?: string;

  /**
   * ļ╣äĒÜīņøÉ ņŚ¼ļČĆ (author.is_guestļ│┤ļŗż ņÜ░ņäĀ)
   * @default false
   */
  isGuest?: boolean;

  /**
   * ĒāłĒć┤ĒĢ£ ņé¼ņÜ®ņ×É ņŚ¼ļČĆ (author.status === 'withdrawn'Ļ│╝ OR ņĪ░Ļ▒┤)
   * @default false
   */
  isWithdrawn?: boolean;

  /**
   * ļō£ļĪŁļŗżņÜ┤ Ēæ£ņŗ£ ņŚ¼ļČĆ
   * @default true
   */
  showDropdown?: boolean;

  /**
   * ĒöäļĪ£ĒĢä Ēü┤ļ”Ł Ļ░ĆļŖź ņŚ¼ļČĆ (ļō£ļĪŁļŗżņÜ┤ņØ┤ ņŚåņØä ļĢī)
   * @default true
   */
  clickable?: boolean;

  /**
   * ņé¼ņÜ®ņ×É ĒöäļĪ£ĒĢä Ļ▓ĮļĪ£ Ēī©Ēä┤
   * @default '/users/{userId}'
   */
  profilePath?: string;

  /**
   * ņČöĻ░Ć className
   */
  className?: string;

  /**
   * ļĀłņØ┤ņĢäņøā ļ░®Ē¢ź
   * @default 'vertical'
   */
  layout?: 'vertical' | 'horizontal';

  /**
   * ļĀłņØ┤ņĢäņøā JSONņŚÉņä£ text ņåŹņä▒ņ£╝ļĪ£ ņĀäļŗ¼ļÉśļŖö ņØ┤ļ”ä
   * nameļ│┤ļŗż ņÜ░ņäĀņł£ņ£äĻ░Ć ļåÆņØī
   */
  text?: string;

  /**
   * ņØ┤ļ▓żĒŖĖ ļ▓äļĖöļ¦ü ļ░®ņ¦Ć ņŚ¼ļČĆ
   * @default false
   */
  stopPropagation?: boolean;

  // ļ®öļē┤ ņ╗żņŖżĒä░ļ¦łņØ┤ņ¦Ģ
  /** ņ╗żņŖżĒģĆ ļ®öļē┤ ĒĢŁļ¬® (ņ¦ĆņĀĢ ņŗ£ ĻĖ░ļ│Ė ļ®öļē┤ ļīĆņ▓┤) */
  menuItems?: MenuItemConfig[];
  /** ņł©ĻĖĖ ĻĖ░ļ│Ė ļ®öļē┤ ĒĢŁļ¬® Ēéż ļ░░ņŚ┤ */
  hideMenuItems?: string[];
  /** ĻĖ░ļ│Ė ļ®öļē┤ņŚÉ ņČöĻ░ĆĒĢĀ ĒĢŁļ¬® */
  appendMenuItems?: MenuItemConfig[];
}

// ļĀłņØ┤ņĢäņøāļ│ä ņ╗©ĒģīņØ┤ļäł Ēü┤ļ×śņŖż
const LAYOUT_CLASSES = {
  horizontal: 'flex items-center gap-1.5',
  vertical: 'flex flex-col items-start',
} as const;

// ĻĖ░ļ│Ė ļ®öļē┤ ĒĢŁļ¬® ņāØņä▒
const createDefaultMenuItems = (): MenuItemConfig[] => [
  {
    key: 'view_profile',
    label: t('userinfo.view_profile'),
    icon: 'user',
    path: '/users/{{userId}}',
  },
  {
    key: 'view_posts',
    label: t('userinfo.view_posts'),
    icon: 'file-lines',
    path: '/users/{{userId}}/posts',
  },
];

/**
 * ņä£ļĖīĒģŹņŖżĒŖĖ ļĀīļŹöļ¦ü ņ╗┤ĒÅ¼ļäīĒŖĖ
 */
const SubText: React.FC<{ text?: string; title?: string }> = ({ text, title }) => {
  if (!text) return null;
  return (
    <Span className="text-sm text-gray-500 dark:text-gray-400" title={title}>
      {text}
    </Span>
  );
};

/**
 * UserInfo ņ╗┤ĒÅ¼ļäīĒŖĖ
 */
export const UserInfo: React.FC<UserInfoProps> = ({
  author,
  name,
  userId,
  subText,
  subTextTitle,
  isGuest = false,
  isWithdrawn = false,
  showDropdown = true,
  clickable = true,
  profilePath = '/users/{userId}',
  className = '',
  layout = 'vertical',
  text,
  stopPropagation = false,
  menuItems,
  hideMenuItems = [],
  appendMenuItems = [],
}) => {
  // ļ¬ģņŗ£ņĀü props > author ņČöņČ£Ļ░Æ ņł£ņä£ļĪ£ Ļ▓░ņĀĢ
  const actualUserId = userId ?? author?.uuid;
  const actualIsGuest = isGuest || author?.is_guest || false;
  const actualIsWithdrawn = isWithdrawn || author?.status === 'withdrawn';

  // ņØ┤ļ”ä ņÜ░ņäĀņł£ņ£ä: text > name > author.name
  // ĒāłĒć┤ĒĢ£ ņé¼ņÜ®ņ×ÉļŖö "ĒāłĒć┤ĒĢ£ ņé¼ņÜ®ņ×É" ĒģŹņŖżĒŖĖ Ēæ£ņŗ£
  const actualName = actualIsWithdrawn
    ? t('userinfo.withdrawn_user')
    : (text ?? name ?? author?.name ?? '');

  // ļō£ļĪŁļŗżņÜ┤ ņāüĒā£
  const [showMenu, setShowMenu] = useState(false);
  const [menuPosition, setMenuPosition] = useState({ top: 0, left: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const buttonRef = useRef<HTMLButtonElement>(null);

  // ĒöäļĪ£ĒĢä Ļ▓ĮļĪ£ ņāØņä▒
  const actualProfilePath = profilePath.replace('{userId}', String(actualUserId ?? ''));

  // ņ╗©ĒģīņØ┤ļäł Ēü┤ļ×śņŖż
  const containerClass = `${LAYOUT_CLASSES[layout]} ${className}`;

  // ļ®öļē┤ ņÖĖļČĆ Ēü┤ļ”Ł ņŗ£ ļŗ½ĻĖ░ + ņŖżĒü¼ļĪż/ļ”¼ņé¼ņØ┤ņ”ł ņŗ£ ļŗ½ĻĖ░
  useEffect(() => {
    if (!showMenu) return;

    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as Node;
      const isInsideContainer = containerRef.current?.contains(target);
      const isInsideDropdown = dropdownRef.current?.contains(target);

      if (!isInsideContainer && !isInsideDropdown) {
        setShowMenu(false);
      }
    };

    const handleScrollOrResize = () => setShowMenu(false);

    document.addEventListener('mousedown', handleClickOutside);
    window.addEventListener('scroll', handleScrollOrResize, true);
    window.addEventListener('resize', handleScrollOrResize);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      window.removeEventListener('scroll', handleScrollOrResize, true);
      window.removeEventListener('resize', handleScrollOrResize);
    };
  }, [showMenu]);

  // ņĄ£ņóģ ļ®öļē┤ ĒĢŁļ¬® Ļ│äņé░
  const getMenuItems = useCallback((): MenuItemConfig[] => {
    // ņ╗żņŖżĒģĆ ļ®öļē┤Ļ░Ć ņ¦ĆņĀĢļÉ£ Ļ▓ĮņÜ░ ĻĘĖļīĆļĪ£ ņé¼ņÜ®
    if (menuItems && menuItems.length > 0) {
      return menuItems.filter((item) => item.show !== false);
    }

    // ĻĖ░ļ│Ė ļ®öļē┤ņŚÉņä£ ņł©ĻĖĖ ĒĢŁļ¬® ņĀ£Ļ▒░
    const defaultItems = createDefaultMenuItems();
    let items = defaultItems.filter(
      (item) => !hideMenuItems.includes(item.key) && item.show !== false
    );

    // ņČöĻ░Ć ĒĢŁļ¬® ļ│æĒĢ®
    if (appendMenuItems && appendMenuItems.length > 0) {
      items = [...items, ...appendMenuItems.filter((item) => item.show !== false)];
    }

    return items;
  }, [menuItems, hideMenuItems, appendMenuItems]);

  // ļō£ļĪŁļŗżņÜ┤ ņ£äņ╣ś Ļ│äņé░ (ļĘ░ĒÅ¼ĒŖĖ ĻĖ░ņżĆ fixed ņ£äņ╣ś ŌĆö Portal ņé¼ņÜ®)
  const updateMenuPosition = useCallback(() => {
    if (buttonRef.current) {
      const buttonRect = buttonRef.current.getBoundingClientRect();
      setMenuPosition({
        top: buttonRect.bottom + 4,
        left: buttonRect.left,
      });
    }
  }, []);

  // ļ®öļē┤ ĒĢŁļ¬® Ēü┤ļ”Ł ĒĢĖļōżļ¤¼
  const handleMenuItemClick = useCallback((item: MenuItemConfig, e: React.MouseEvent) => {
    e.stopPropagation();
    e.preventDefault();
    setShowMenu(false);

    if (item.onClick) {
      item.onClick();
    } else if (item.path) {
      const path = item.path.replace(/\{\{userId\}\}/g, String(actualUserId ?? ''));
      const g7Core = getG7Core();
      if (g7Core?.navigate) {
        g7Core.navigate(path);
      } else {
        window.location.href = path;
      }
    }
  }, [actualUserId]);

  // Ēü┤ļ”Ł ĒĢĖļōżļ¤¼ (ļō£ļĪŁļŗżņÜ┤ ļśÉļŖö ĒöäļĪ£ĒĢä ņØ┤ļÅÖ)
  const handleClick = useCallback((e: React.MouseEvent) => {
    e.preventDefault();

    if (stopPropagation) {
      e.stopPropagation();
    }

    // ļ╣äĒÜīņøÉņØ┤Ļ▒░ļéś userIdĻ░Ć ņŚåņ£╝ļ®┤ ņĢäļ¼┤ ļÅÖņ×æ ņĢł ĒĢ©
    if (actualIsGuest || !actualUserId) {
      return;
    }

    // ļō£ļĪŁļŗżņÜ┤ņØ┤ ĒÖ£ņä▒ĒÖöļÉ£ Ļ▓ĮņÜ░
    if (showDropdown) {
      if (!showMenu) {
        updateMenuPosition();
      }
      setShowMenu((prev) => !prev);
    }
    // ļō£ļĪŁļŗżņÜ┤ņØ┤ ļ╣äĒÖ£ņä▒ĒÖöļÉśĻ│Ā Ēü┤ļ”Ł Ļ░ĆļŖźĒĢ£ Ļ▓ĮņÜ░
    else if (clickable) {
      getG7Core()?.navigate?.(actualProfilePath);
    }
  }, [stopPropagation, actualIsGuest, actualUserId, showDropdown, showMenu, updateMenuPosition, clickable, actualProfilePath]);

  // ļ╣äĒÜīņøÉņØĖ Ļ▓ĮņÜ░
  if (actualIsGuest || !actualUserId) {
    return (
      <Div className={containerClass}>
        <Div className="flex items-center gap-1.5 text-gray-400 dark:text-gray-500">
          <Span>{actualName}</Span>
          <Span className="text-xs px-1.5 py-0.5 bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 rounded">
            {t('userinfo.guest_badge')}
          </Span>
        </Div>
        <SubText text={subText} title={subTextTitle} />
      </Div>
    );
  }

  // ĒāłĒć┤ĒĢ£ ņé¼ņÜ®ņ×ÉņØĖ Ļ▓ĮņÜ░
  if (actualIsWithdrawn) {
    return (
      <Div className={containerClass}>
        <Span className="text-gray-400 dark:text-gray-500 line-through">
          {actualName}
        </Span>
        <SubText text={subText} title={subTextTitle} />
      </Div>
    );
  }

  // ĒÜīņøÉņØĖ Ļ▓ĮņÜ░
  const finalMenuItems = getMenuItems();
  // classNameņŚÉ text- ņāēņāü Ēü┤ļ×śņŖżĻ░Ć ņ×łņ£╝ļ®┤ nameButtonClassņØś ĻĖ░ļ│Ė ņāēņāüņØä ļīĆņ▓┤
  const hasCustomColor = /\btext-\S+/.test(className);
  const defaultColorClass = hasCustomColor ? '' : 'text-gray-900 dark:text-white';
  const nameButtonClass = (showDropdown || clickable)
    ? `${defaultColorClass} hover:text-blue-600 dark:hover:text-blue-400 cursor-pointer font-medium`.trim()
    : `${defaultColorClass} font-medium`.trim();

  return (
    <Div ref={containerRef} className={`relative inline-block ${className}`}>
      <Div className={LAYOUT_CLASSES[layout]}>
        <Button
          ref={buttonRef}
          onClick={handleClick}
          className={nameButtonClass}
        >
          {actualName}
        </Button>
        <SubText text={subText} title={subTextTitle} />
      </Div>

      {/* ļō£ļĪŁļŗżņÜ┤ ļ®öļē┤ - PortalļĪ£ document.bodyņŚÉ fixed ļ░░ņ╣ś (overflow-hidden ļČĆļ¬© ĒÜīĒö╝) */}
      {showDropdown && showMenu && finalMenuItems.length > 0 && createPortal(
        <Div
          ref={dropdownRef}
          className="fixed w-40 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg shadow-lg py-1 z-[9999]"
          style={{ top: menuPosition.top, left: menuPosition.left }}
          data-testid="author-dropdown-menu"
        >
          {finalMenuItems.map((item) => (
            <Button
              key={item.key}
              onClick={(e) => handleMenuItemClick(item, e)}
              className="flex items-center justify-start gap-2 w-full text-left px-3 py-2 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 cursor-pointer"
              data-testid={`menu-item-${item.key}`}
            >
              {item.icon && <Icon name={item.icon} className="w-4 h-4" />}
              <Span>{item.label}</Span>
            </Button>
          ))}
        </Div>,
        document.body
      )}
    </Div>
  );
};
