import React, { useMemo } from 'react';

export interface SelectOption {
  value: string | number;
  label: string;
  disabled?: boolean;
}

export interface SelectProps extends Omit<React.SelectHTMLAttributes<HTMLSelectElement>, 'onChange'> {
  label?: string;
  error?: string;
  options?: SelectOption[] | string[];
  onChange?: (e: React.ChangeEvent<HTMLSelectElement> | { target: { value: string | number } }) => void;
}

function getLocaleName(locale: string): string {
  const localeNames: Record<string, string> = {
    ko: 'ĒĢ£ĻĄŁņ¢┤',
    en: 'English',
    ja: 'µŚźµ£¼Ķ¬×',
    zh: 'õĖŁµ¢ć',
    es: 'Espa├▒ol',
    fr: 'Fran├¦ais',
    de: 'Deutsch',
  };
  return localeNames[locale] || locale;
}

/**
 * daisyUI Select ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * ļäżņØ┤Ēŗ░ļĖī <select>ņŚÉ daisyUI `select` Ēü┤ļ×śņŖżļź╝ ņĀüņÜ®ĒĢ®ļŗłļŗż.
 */
export const Select: React.FC<SelectProps> = ({
  children,
  label,
  error,
  options,
  className = '',
  value,
  onChange,
  disabled,
  ...props
}) => {
  const normalizedOptions = useMemo((): SelectOption[] | null => {
    if (!options) return null;
    if (!Array.isArray(options)) return null;
    if (options.length === 0) return [];

    if (typeof options[0] === 'string') {
      return (options as string[]).map((locale): SelectOption => ({
        value: locale,
        label: getLocaleName(locale),
      }));
    }

    return options as SelectOption[];
  }, [options]);

  // daisyUI select ĻĖ░ļ│Ė Ēü┤ļ×śņŖż Ļ▓░ņĀĢ
  const hasDaisyClass = className.includes('select');
  const selectClass = hasDaisyClass
    ? className
    : `select ${className}`.trim();

  if (!normalizedOptions) {
    return (
      <select
        className={selectClass}
        value={value}
        onChange={onChange as React.ChangeEventHandler<HTMLSelectElement>}
        disabled={disabled}
        {...props}
      >
        {children}
      </select>
    );
  }

  const handleChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    if (onChange) {
      onChange(e);
    }
  };

  return (
    <select
      className={selectClass}
      value={value}
      onChange={handleChange}
      disabled={disabled}
      {...props}
    >
      {normalizedOptions.map((option) => (
        <option
          key={option.value}
          value={option.value}
          disabled={option.disabled}
        >
          {option.label}
        </option>
      ))}
    </select>
  );
};
