  showDownload?: boolean;
  /** ņŹĖļäżņØ╝ ļäżļ╣äĻ▓īņØ┤ņģś Ēæ£ņŗ£ (ĻĖ░ļ│ĖĻ░Æ: true) */
  showThumbnails?: boolean;
  /** ņ╗żņŖżĒģĆ ļŗżņÜ┤ļĪ£ļō£ ĒĢĖļōżļ¤¼ (ņĀ£Ļ│Ą ņŗ£ ĻĖ░ļ│Ė ļŗżņÜ┤ļĪ£ļō£ ļĪ£ņ¦ü ļīĆņŗĀ ņŗżĒ¢ē) */
  onDownload?: (image: GalleryImage, index: number) => void;
