// ========== Helper Functions ==========

/**
 * ņØĖņ”ØļÉ£ ņØ┤ļ»Ėņ¦Ć ļŗżņÜ┤ļĪ£ļō£ (Blobņ£╝ļĪ£ ļ│ĆĒÖś Ēøä ļŗżņÜ┤ļĪ£ļō£)
 */
const downloadAuthenticatedFile = async (url: string, filename: string): Promise<void> => {
  try {
    const blob = await G7Core.api.get(url, {
      responseType: 'blob',
    });

    if (blob) {
      const objectUrl = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = objectUrl;
      link.download = filename;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(objectUrl);
    }
  } catch (error) {
    console.error('Failed to download file:', error);
    G7Core?.toast?.error?.(t('common.download_failed'));
  }
};

/**
 * ņØ╝ļ░ś ĒīīņØ╝ ļŗżņÜ┤ļĪ£ļō£
 */
const downloadFile = (url: string, filename: string): void => {
  const link = document.createElement('a');
  link.href = url;
  link.download = filename;
  link.target = '_blank';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

/**
 * ņØ┤ļ»Ėņ¦Ć ļŗżņÜ┤ļĪ£ļō£ ņŗżĒ¢ē
 */
export const executeImageDownload = async (image: GalleryImage): Promise<void> => {
  const downloadUrl = image.downloadUrl || image.src;
  const filename = image.filename || image.title || 'image';

  if (image.downloadRequiresAuth) {
    await downloadAuthenticatedFile(downloadUrl, filename);
  } else {
    downloadFile(downloadUrl, filename);
  }
};

// ========== Custom Download Button Component ==========

interface DownloadButtonProps {
  image: GalleryImage;
  index: number;
  onDownload?: (image: GalleryImage, index: number) => void;
}

const DownloadButton: React.FC<DownloadButtonProps> = ({ image, index, onDownload }) => {
  const [isDownloading, setIsDownloading] = useState(false);

  const handleDownload = async (e: React.MouseEvent) => {
    e.stopPropagation();

    if (onDownload) {
      onDownload(image, index);
      return;
    }

    setIsDownloading(true);
    try {
      await executeImageDownload(image);
    } finally {
      setIsDownloading(false);
    }
  };

  return (
    <Button
      type="button"
      onClick={handleDownload}
      disabled={isDownloading}
      className="yarl__button flex items-center justify-center"
      aria-label={t('common.download')}
      title={t('common.download')}
    >
      {isDownloading ? (
        <I className="fa-solid fa-spinner fa-spin text-white" />
      ) : (
        <I className="fa-solid fa-download text-white" />
      )}
    </Button>
  );
};

// ========== Main Component ==========

export const ImageGallery: React.FC<ImageGalleryProps> = ({
  images,
  isOpen,
  onClose,
  startIndex = 0,
  enableZoom = true,
  enableSlideshow = false,
  enableFullscreen = true,
  showCounter = true,
  showDownload = true,
  showThumbnails = true,
  onDownload,
}) => {
  // Ēśäņ×¼ ņŖ¼ļØ╝ņØ┤ļō£ ņØĖļŹ▒ņŖż (ļŗżņÜ┤ļĪ£ļō£ ļ▓äĒŖ╝ņÜ®)
  const [currentIndex, setCurrentIndex] = useState(startIndex);
  // ņĄ£ņŗĀ ņØĖļŹ▒ņŖżļź╝ refļĪ£ ņČöņĀü (Ēü┤ļĪ£ņĀĆ ļ¼ĖņĀ£ ļ░®ņ¦Ć)
  const currentIndexRef = useRef(startIndex);

  // ņØ┤ļ»Ėņ¦Ćļź╝ ļØ╝ņØ┤ĒŖĖļ░ĢņŖż ņŖ¼ļØ╝ņØ┤ļō£ ĒśĢņŗØņ£╝ļĪ£ ļ│ĆĒÖś (ņŹĖļäżņØ╝ ĒÅ¼ĒĢ©)
  const slides: Slide[] = images.map((image) => ({
    src: image.src,
    title: image.title,
    description: image.description,
  }));

  // ĒÖ£ņä▒ĒÖöĒĢĀ Ēöīļ¤¼ĻĘĖņØĖ ļ¬®ļĪØ
  const plugins = [];
  if (enableZoom) plugins.push(Zoom);
  if (enableSlideshow) plugins.push(Slideshow);
  if (enableFullscreen) plugins.push(Fullscreen);
  if (showCounter) plugins.push(Counter);
  if (showThumbnails) plugins.push(Thumbnails);

  // Ēśäņ×¼ ņØ┤ļ»Ėņ¦Ć
  const currentImage = images[currentIndex];

  // startIndex propņØ┤ ļ│ĆĻ▓ĮļÉśļ®┤ currentIndex ļÅÖĻĖ░ĒÖö
  useEffect(() => {
    setCurrentIndex(startIndex);
    currentIndexRef.current = startIndex;
  }, [startIndex]);

  // currentIndexĻ░Ć ļ│ĆĻ▓ĮļÉśļ®┤ refļÅä ņŚģļŹ░ņØ┤ĒŖĖ
  useEffect(() => {
    currentIndexRef.current = currentIndex;
  }, [currentIndex]);

  return (
    <Lightbox
      open={isOpen}
      close={onClose}
      slides={slides}
      index={currentIndex}
      plugins={plugins}
      on={{
        view: ({ index }) => {
          if (index !== currentIndexRef.current) {
            setCurrentIndex(index);
          }
        },
      }}
      zoom={{
        maxZoomPixelRatio: 3,
        zoomInMultiplier: 2,
        doubleTapDelay: 300,
        doubleClickDelay: 300,
        doubleClickMaxStops: 2,
        keyboardMoveDistance: 50,
        wheelZoomDistanceFactor: 100,
        pinchZoomDistanceFactor: 100,
        scrollToZoom: true,
      }}
      carousel={{
        finite: true,
        preload: 2,
        padding: '16px',
        spacing: '30%',
      }}
      animation={{
        fade: 250,
        swipe: 500,
        easing: {
          fade: 'ease',
          swipe: 'ease-out',
          navigation: 'ease-in-out',
        },
      }}
      controller={{
        closeOnBackdropClick: true,
        closeOnPullDown: true,
        closeOnPullUp: true,
      }}
      thumbnails={{
        position: 'bottom',
        width: 120,
        height: 80,
        border: 2,
        borderRadius: 4,
        padding: 4,
        gap: 16,
        showToggle: false,
        vignette: true,
      }}
      toolbar={{
        buttons: [
          showDownload && currentImage && (
            <DownloadButton
              key="download"
              image={currentImage}
              index={currentIndex}
              onDownload={onDownload}
            />
          ),
          'close',
        ].filter(Boolean),
      }}
      styles={{
        container: {
          backgroundColor: 'rgba(0, 0, 0, 0.9)',
        },
      }}
    />
  );
};

// ========== Utility Hook ==========

/**
 * ImageGalleryļź╝ ņēĮĻ▓ī ņé¼ņÜ®ĒĢśĻĖ░ ņ£äĒĢ£ ņ╗żņŖżĒģĆ Ēøģ
 *
 * @example
 * const { openGallery, galleryProps } = useImageGallery();
 *
 * // ņØ┤ļ»Ėņ¦Ć Ēü┤ļ”Ł ņŗ£
 * <img onClick={() => openGallery(images, 0)} />
 *
 * // ņ╗┤ĒÅ¼ļäīĒŖĖ ļĀīļŹöļ¦ü
 * <ImageGallery {...galleryProps} />
 */
export const useImageGallery = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [images, setImages] = useState<GalleryImage[]>([]);
  const [startIndex, setStartIndex] = useState(0);

  const openGallery = useCallback((galleryImages: GalleryImage[], index = 0) => {
    setImages(galleryImages);
    setStartIndex(index);
    setIsOpen(true);
  }, []);

  const closeGallery = useCallback(() => {
    setIsOpen(false);
  }, []);

  return {
    isOpen,
    openGallery,
    closeGallery,
    galleryProps: {
      images,
      isOpen,
      onClose: closeGallery,
      startIndex,
    },
  };
};

ImageGallery.displayName = 'ImageGallery';

export default ImageGallery;
