import React, { useMemo } from 'react';
import { Div } from '../basic/Div';
import { Button } from '../basic/Button';

// G7Core.t() ļ▓łņŚŁ ĒĢ©ņłś ņ░ĖņĪ░
const t = (key: string, params?: Record<string, string | number>) =>
  (window as any).G7Core?.t?.(key, params) ?? key;

export interface PaginationProps {
  currentPage: number;
  totalPages: number;
  onPageChange: (page: number) => void;
  maxVisiblePages?: number;
  showFirstLast?: boolean;
  className?: string;
  style?: React.CSSProperties;
  prevText?: string;
  nextText?: string;
}

/**
 * Pagination ņ¦æĒĢ® ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * Button + Span ĻĖ░ļ│Ė ņ╗┤ĒÅ¼ļäīĒŖĖļź╝ ņĪ░ĒĢ®ĒĢśņŚ¼ ĒÄśņØ┤ņ¦ĆļäżņØ┤ņģś UIļź╝ ĻĄ¼ņä▒ĒĢ®ļŗłļŗż.
 * ĒÄśņØ┤ņ¦Ć ļ▓łĒśĖ ņāØņä▒ ņĢīĻ│Āļ”¼ņ”śņØä ĒÅ¼ĒĢ©ĒĢśļ®░, ļ¦ÄņØĆ ĒÄśņØ┤ņ¦Ć ņłśņŚÉ ļīĆĒĢ┤ ĒÜ©ņ£©ņĀüņ£╝ļĪ£ ļĀīļŹöļ¦üĒĢ®ļŗłļŗż.
 *
 * @example
 * // ļĀłņØ┤ņĢäņøā JSON ņé¼ņÜ® ņśłņŗ£
 * {
 *   "name": "Pagination",
 *   "props": {
 *     "currentPage": "{{pagination.current}}",
 *     "totalPages": "{{pagination.total}}",
 *     "maxVisiblePages": 5,
 *     "showFirstLast": true
 *   }
 * }
 */
export const Pagination: React.FC<PaginationProps> = ({
  currentPage,
  totalPages,
  onPageChange,
  maxVisiblePages = 5,
  showFirstLast = true,
  className = '',
  style,
  prevText,
  nextText,
}) => {

  // ĒÄśņØ┤ņ¦Ć ļ▓łĒśĖ ņāØņä▒ ņĢīĻ│Āļ”¼ņ”ś
  const pageNumbers = useMemo(() => {
    const pages: (number | string)[] = [];

    if (totalPages <= maxVisiblePages + 2) {
      // ĒÄśņØ┤ņ¦ĆĻ░Ć ņĀüņ£╝ļ®┤ ļ¬©ļæÉ Ēæ£ņŗ£
      for (let i = 1; i <= totalPages; i++) {
        pages.push(i);
      }
    } else {
      // ĒÄśņØ┤ņ¦ĆĻ░Ć ļ¦Äņ£╝ļ®┤ ņČĢņĢĮ Ēæ£ņŗ£
      const halfVisible = Math.floor(maxVisiblePages / 2);

      let startPage = Math.max(2, currentPage - halfVisible);
      let endPage = Math.min(totalPages - 1, currentPage + halfVisible);

      // ņŗ£ņ×æ ļśÉļŖö ļüØ ĻĘ╝ņ▓śņØ╝ ļĢī ņĪ░ņĀĢ
      if (currentPage <= halfVisible + 1) {
        endPage = maxVisiblePages;
      } else if (currentPage >= totalPages - halfVisible) {
        startPage = totalPages - maxVisiblePages + 1;
      }

      // ņ▓½ ĒÄśņØ┤ņ¦Ć
      pages.push(1);

      // ņŗ£ņ×æ ņāØļ×Ą ļČĆĒśĖ
      if (startPage > 2) {
        pages.push('...');
      }

      // ņżæĻ░ä ĒÄśņØ┤ņ¦Ćļōż
      for (let i = startPage; i <= endPage; i++) {
        pages.push(i);
      }

      // ļüØ ņāØļ×Ą ļČĆĒśĖ
      if (endPage < totalPages - 1) {
        pages.push('...');
      }

      // ļ¦łņ¦Ćļ¦ē ĒÄśņØ┤ņ¦Ć
      if (totalPages > 1) {
        pages.push(totalPages);
      }
    }

    return pages;
  }, [currentPage, totalPages, maxVisiblePages]);

  const handlePageClick = (page: number) => {
    if (page < 1 || page > totalPages || page === currentPage) return;
    onPageChange(page);
  };

  const handlePrevious = () => {
    if (currentPage > 1) {
      onPageChange(currentPage - 1);
    }
  };

  const handleNext = () => {
    if (currentPage < totalPages) {
      onPageChange(currentPage + 1);
    }
  };

  return (
    <Div
      className={`join ${className}`}
      style={style}
      role="navigation"
      aria-label={t('common.pagination')}
    >
      {/* First Button */}
      {showFirstLast && (
        <Button
          onClick={() => handlePageClick(1)}
          disabled={currentPage === 1}
          className="join-item btn btn-md"
          aria-label={t('common.first_page')}
        >
          &#171;
        </Button>
      )}

      {/* Previous Button */}
      <Button
        onClick={handlePrevious}
        disabled={currentPage === 1}
        className="join-item btn btn-md"
        aria-label={t('common.prev_page')}
      >
        {prevText || <>&#8249;</>}
      </Button>

      {/* Page Numbers */}
      {pageNumbers.map((page, index) => {
        if (page === '...') {
          return (
            <Button
              key={`ellipsis-${index}`}
              className="join-item btn btn-md btn-disabled"
            >
              ...
            </Button>
          );
        }

        const pageNum = page as number;
        const isActive = pageNum === currentPage;

        return (
          <Button
            key={pageNum}
            onClick={() => handlePageClick(pageNum)}
            className={`join-item btn btn-md ${isActive ? 'btn-active btn-primary' : ''}`}
            aria-label={t('common.page_n', { n: pageNum })}
            aria-current={isActive ? 'page' : undefined}
          >
            {pageNum}
          </Button>
        );
      })}

      {/* Next Button */}
      <Button
        onClick={handleNext}
        disabled={currentPage === totalPages}
        className="join-item btn btn-md"
        aria-label={t('common.next_page')}
      >
        {nextText || <>&#8250;</>}
      </Button>

      {/* Last Button */}
      {showFirstLast && (
        <Button
          onClick={() => handlePageClick(totalPages)}
          disabled={currentPage === totalPages}
          className="join-item btn btn-md"
          aria-label={t('common.last_page')}
        >
          &#187;
        </Button>
      )}
    </Div>
  );
};
