/**
 * RichTextEditor ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * Ļ▓īņŗ£ĻĖĆ ņ×æņä▒ņØä ņ£äĒĢ£ ļ”¼ņ╣ś ĒģŹņŖżĒŖĖ ņŚÉļööĒä░ņ×ģļŗłļŗż.
 * TipTap ļśÉļŖö Quill ļō▒ņØś ņÖĖļČĆ ļØ╝ņØ┤ļĖīļ¤¼ļ”¼ļź╝ ļ×śĒĢæĒĢ®ļŗłļŗż.
 *
 * @note ņŗżņĀ£ ĻĄ¼Ēśä ņŗ£ TipTap, Quill, CKEditor ļō▒ ņäĀĒāØĒĢśņŚ¼ ļ×śĒĢæ
 */

import React, { useEffect, useRef, useState } from 'react';
import { Div } from '../basic/Div';

// Logger ņäżņĀĢ (G7Core ņ┤łĻĖ░ĒÖö ņĀäņŚÉļÅä ļÅÖņ×æĒĢśļÅäļĪØ ĒÅ┤ļ░▒ ĒÅ¼ĒĢ©)
const logger = ((window as any).G7Core?.createLogger?.('Comp:RichTextEditor')) ?? {
    log: (...args: unknown[]) => console.log('[Comp:RichTextEditor]', ...args),
    warn: (...args: unknown[]) => console.warn('[Comp:RichTextEditor]', ...args),
    error: (...args: unknown[]) => console.error('[Comp:RichTextEditor]', ...args),
};
import { Button } from '../basic/Button';
import { Input } from '../basic/Input';
import { Textarea } from '../basic/Textarea';
import { H3 } from '../basic/H3';
import { Label } from '../basic/Label';

// G7Core.t() ļ▓łņŚŁ ĒĢ©ņłś ņ░ĖņĪ░
const t = (key: string, params?: Record<string, string | number>) =>
  (window as any).G7Core?.t?.(key, params) ?? key;

interface RichTextEditorProps {
  /** ĒĢäļō£ ņØ┤ļ”ä */
  name: string;
  /** ņ┤łĻĖ░ HTML Ļ░Æ */
  initialValue?: string;
  /** ĒöīļĀłņØ┤ņŖżĒÖĆļŹö */
  placeholder?: string;
  /** Ļ░Æ ļ│ĆĻ▓Į ņĮ£ļ░▒ */
  onChange?: (html: string) => void;
  /** ņØ┤ļ»Ėņ¦Ć ņŚģļĪ£ļō£ URL */
  imageUploadUrl?: string;
  /** ņĄ£ņåī ļåÆņØ┤ */
  minHeight?: string;
  /** ļ╣äĒÖ£ņä▒ĒÖö ņŚ¼ļČĆ */
  disabled?: boolean;
  /** ņČöĻ░Ć CSS Ēü┤ļ×śņŖż */
  className?: string;
}

type FormatType =
  | 'bold'
  | 'italic'
  | 'underline'
  | 'strike'
  | 'code'
  | 'h1'
  | 'h2'
  | 'h3'
  | 'bulletList'
  | 'orderedList'
  | 'blockquote'
  | 'link'
  | 'image';

/**
 * ļ”¼ņ╣ś ĒģŹņŖżĒŖĖ ņŚÉļööĒä░ ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * @example
 * ```tsx
 * <RichTextEditor
 *   name="content"
 *   initialValue={post?.content}
 *   placeholder="ļé┤ņÜ®ņØä ņ×ģļĀźĒĢśņäĖņÜö..."
 *   onChange={(html) => setContent(html)}
 * />
 * ```
 *
 * @example
 * ```json
 * // ļĀłņØ┤ņĢäņøā JSONņŚÉņä£ ņé¼ņÜ®
 * {
 *   "type": "composite",
 *   "name": "RichTextEditor",
 *   "props": {
 *     "name": "content",
 *     "placeholder": "$t:board.form.content_placeholder",
 *     "initialValue": "{{post.data?.content ?? ''}}"
 *   }
 * }
 * ```
 */
const RichTextEditor: React.FC<RichTextEditorProps> = ({
  name,
  initialValue = '',
  placeholder,
  onChange,
  imageUploadUrl = '/api/upload/image',
  minHeight = '300px',
  disabled = false,
  className = '',
}) => {
  const editorRef = useRef<HTMLDivElement>(null);
  const [content, setContent] = useState(initialValue);
  const [showCodeView, setShowCodeView] = useState(false);
  const [showLinkModal, setShowLinkModal] = useState(false);
  const [linkUrl, setLinkUrl] = useState('');

  // ņŚÉļööĒä░ ņ┤łĻĖ░ĒÖö (ņŗżņĀ£ ĻĄ¼Ēśä ņŗ£ TipTap/Quill ņ┤łĻĖ░ĒÖö)
  useEffect(() => {
    // ņ┤łĻĖ░Ļ░Æ ņäżņĀĢ (dangerouslySetInnerHTML ļīĆņŗĀ ņ¦üņĀæ ņäżņĀĢ)
    if (editorRef.current && !editorRef.current.innerHTML) {
      editorRef.current.innerHTML = initialValue;
    }
  }, [initialValue]);

  // Ļ░Æ ļ│ĆĻ▓Į ņŗ£ ņĮ£ļ░▒ ĒśĖņČ£
  useEffect(() => {
    if (onChange) {
      onChange(content);
    }
  }, [content, onChange]);

  // ĒÅ¼ļ¦Ę ņĀüņÜ® (ņŗżņĀ£ ĻĄ¼Ēśä ņŗ£ ņŚÉļööĒä░ API ņé¼ņÜ®)
  const applyFormat = (format: FormatType) => {
    // TODO: ņŚÉļööĒä░ ļØ╝ņØ┤ļĖīļ¤¼ļ”¼ņØś ĒÅ¼ļ¦Ę API ĒśĖņČ£
    logger.log('Apply format:', format);
  };

  // ņØ┤ļ»Ėņ¦Ć ņŚģļĪ£ļō£
  const handleImageUpload = async (file: File) => {
    const formData = new FormData();
    formData.append('file', file);

    try {
      const response = await fetch(imageUploadUrl, {
        method: 'POST',
        body: formData,
        credentials: 'include',
      });

      if (!response.ok) throw new Error('ņŚģļĪ£ļō£ ņŗżĒī©');

      const data = await response.json();
      // TODO: ņŚÉļööĒä░ņŚÉ ņØ┤ļ»Ėņ¦Ć ņéĮņ×ģ
      logger.log('Image uploaded:', data.url);
    } catch (error) {
      logger.error('ņØ┤ļ»Ėņ¦Ć ņŚģļĪ£ļō£ ņśżļźś:', error);
    }
  };

  // ĒīīņØ╝ ņäĀĒāØ ĒĢĖļōżļ¤¼
  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      handleImageUpload(file);
    }
  };

  // ļ¦üĒü¼ ņéĮņ×ģ
  const insertLink = () => {
    if (linkUrl) {
      // TODO: ņŚÉļööĒä░ņŚÉ ļ¦üĒü¼ ņéĮņ×ģ
      logger.log('Insert link:', linkUrl);
      setShowLinkModal(false);
      setLinkUrl('');
    }
  };

  const toolbarButtons: { format: FormatType; icon: React.ReactNode; title: string }[] = [
    { format: 'bold', icon: 'B', title: t('editor.toolbar.bold') },
    { format: 'italic', icon: 'I', title: t('editor.toolbar.italic') },
    { format: 'underline', icon: 'U', title: t('editor.toolbar.underline') },
    { format: 'strike', icon: 'S', title: t('editor.toolbar.strike') },
    { format: 'code', icon: '</>', title: t('editor.toolbar.code') },
  ];

  const headingButtons: { format: FormatType; label: string }[] = [
    { format: 'h1', label: 'H1' },
    { format: 'h2', label: 'H2' },
    { format: 'h3', label: 'H3' },
  ];

  const listButtons: { format: FormatType; icon: string; title: string }[] = [
    { format: 'bulletList', icon: 'ŌĆó', title: t('editor.toolbar.bullet_list') },
    { format: 'orderedList', icon: '1.', title: t('editor.toolbar.ordered_list') },
    { format: 'blockquote', icon: 'ŌØØ', title: t('editor.toolbar.blockquote') },
  ];

  return (
    <Div className={`border border-gray-300 dark:border-gray-600 rounded-lg overflow-hidden ${className}`}>
      {/* Ēł┤ļ░ö */}
      <Div className="flex flex-wrap items-center gap-1 p-2 bg-gray-50 dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700">
        {/* ĒģŹņŖżĒŖĖ ĒÅ¼ļ¦Ę */}
        <Div className="flex items-center gap-1 pr-2 border-r border-gray-200 dark:border-gray-700">
          {toolbarButtons.map((btn) => (
            <Button
              key={btn.format}
              type="button"
              onClick={() => applyFormat(btn.format)}
              disabled={disabled}
              className="w-8 h-8 flex items-center justify-center text-sm font-medium text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700 rounded disabled:opacity-50"
              title={btn.title}
            >
              {btn.icon}
            </Button>
          ))}
        </Div>

        {/* ņĀ£ļ¬® */}
        <Div className="flex items-center gap-1 pr-2 border-r border-gray-200 dark:border-gray-700">
          {headingButtons.map((btn) => (
            <Button
              key={btn.format}
              type="button"
              onClick={() => applyFormat(btn.format)}
              disabled={disabled}
              className="px-2 h-8 text-sm font-medium text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700 rounded disabled:opacity-50"
            >
              {btn.label}
            </Button>
          ))}
        </Div>

        {/* ļ”¼ņŖżĒŖĖ */}
        <Div className="flex items-center gap-1 pr-2 border-r border-gray-200 dark:border-gray-700">
          {listButtons.map((btn) => (
            <Button
              key={btn.format}
              type="button"
              onClick={() => applyFormat(btn.format)}
              disabled={disabled}
              className="w-8 h-8 flex items-center justify-center text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700 rounded disabled:opacity-50"
              title={btn.title}
            >
              {btn.icon}
            </Button>
          ))}
        </Div>

        {/* ļ»Ėļööņ¢┤ */}
        <Div className="flex items-center gap-1 pr-2 border-r border-gray-200 dark:border-gray-700">
          <Button
            type="button"
            onClick={() => setShowLinkModal(true)}
            disabled={disabled}
            className="w-8 h-8 flex items-center justify-center text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700 rounded disabled:opacity-50"
            title={t('editor.toolbar.link')}
          >
            ­¤öŚ
          </Button>
          <Label className="w-8 h-8 flex items-center justify-center text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700 rounded cursor-pointer">
            ­¤¢╝
            <Input
              type="file"
              accept="image/*"
              onChange={handleFileSelect}
              disabled={disabled}
              className="hidden"
            />
          </Label>
        </Div>

        {/* ņĮöļō£ ļ│┤ĻĖ░ ĒåĀĻĖĆ */}
        <Button
          type="button"
          onClick={() => setShowCodeView(!showCodeView)}
          disabled={disabled}
          className={`px-2 h-8 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700 rounded disabled:opacity-50 ${
            showCodeView ? 'bg-gray-200 dark:bg-gray-700' : ''
          }`}
        >
          {'</>'}
          {t('editor.toolbar.code_view')}
        </Button>
      </Div>

      {/* ņŚÉļööĒä░ ņśüņŚŁ */}
      {showCodeView ? (
        <Textarea
          value={content}
          onChange={(e) => setContent(e.target.value)}
          placeholder={placeholder}
          disabled={disabled}
          className="w-full p-4 bg-gray-900 text-gray-100 font-mono text-sm focus:outline-none resize-none"
          style={{ minHeight }}
        />
      ) : (
        <Div
          ref={editorRef}
          contentEditable={!disabled}
          onInput={(e) => setContent(e.currentTarget.innerHTML)}
          className="p-4 bg-white dark:bg-gray-900 text-gray-900 dark:text-white focus:outline-none prose dark:prose-invert max-w-none"
          style={{ minHeight }}
          data-placeholder={placeholder}
        />
      )}

      {/* ņł©Ļ▓©ņ¦ä input (ĒÅ╝ ņĀäņåĪņÜ®) */}
      <Input type="hidden" name={name} value={content} />

      {/* ļ¦üĒü¼ ļ¬©ļŗ¼ */}
      {showLinkModal && (
        <Div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
          <Div className="bg-white dark:bg-gray-800 rounded-lg p-6 w-96">
            <H3 className="text-lg font-medium text-gray-900 dark:text-white mb-4">
              {t('editor.link_modal.title')}
            </H3>
            <Input
              type="url"
              value={linkUrl}
              onChange={(e) => setLinkUrl(e.target.value)}
              placeholder="https://example.com"
              className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white mb-4"
            />
            <Div className="flex justify-end gap-2">
              <Button
                type="button"
                onClick={() => {
                  setShowLinkModal(false);
                  setLinkUrl('');
                }}
                className="px-4 py-2 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg"
              >
                {t('common.cancel')}
              </Button>
              <Button
                type="button"
                onClick={insertLink}
                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
              >
                {t('editor.link_modal.insert')}
              </Button>
            </Div>
          </Div>
        </Div>
      )}
    </Div>
  );
};

export default RichTextEditor;
