import React, { useState, useCallback, forwardRef, useImperativeHandle, useRef, useEffect, useMemo } from 'react';
import { Icon } from './Icon';

// G7Core.t() ļ▓łņŚŁ ĒĢ©ņłś ņ░ĖņĪ░
const t = (key: string, params?: Record<string, string | number>) =>
  (window as unknown as { G7Core?: { t?: (key: string, params?: Record<string, string | number>) => string } })
    .G7Core?.t?.(key, params) ?? key;

/**
 * ļ╣äļ░Ćļ▓łĒśĖ Ļ▓Ćņ”Ø ĻĘ£ņ╣Ö ņĀĢņØś
 */
export interface PasswordRule {
  /** ĻĘ£ņ╣Ö ņŗØļ│äņ×É */
  key: string;
  /** ĻĘ£ņ╣Ö ņäżļ¬ģ (ļŗżĻĄŁņ¢┤ Ēéż) */
  labelKey: string;
  /** Ļ▓Ćņ”Ø ĒĢ©ņłś (paramņØĆ ĻĘ£ņ╣Öļ│ä ņäżņĀĢĻ░Æ) */
  validate: (value: string, param?: number) => boolean;
  /** ĻĖ░ļ│Ė ĒīīļØ╝ļ»ĖĒä░ Ļ░Æ */
  defaultParam?: number;
}

/**
 * ņé¼ņÜ® Ļ░ĆļŖźĒĢ£ ļ¬©ļōĀ ļ╣äļ░Ćļ▓łĒśĖ Ļ▓Ćņ”Ø ĻĘ£ņ╣Ö
 *
 * JSON ļĀłņØ┤ņĢäņøāņŚÉņä£ enableRules propņ£╝ļĪ£ Ēéżļź╝ ņ¦ĆņĀĢĒĢśņŚ¼ ņäĀĒāØņĀüņ£╝ļĪ£ ĒÖ£ņä▒ĒÖö
 * ĒīīļØ╝ļ»ĖĒä░Ļ░Ć ņ×łļŖö ĻĘ£ņ╣ÖņØĆ "ĻĘ£ņ╣Öļ¬ģ:Ļ░Æ" ĒśĢņŗØņ£╝ļĪ£ ņ¦ĆņĀĢ (ņśł: "minLength:12")
 */
export const availablePasswordRules: Record<string, PasswordRule> = {
  minLength: {
    key: 'minLength',
    labelKey: 'auth.password_input.rules.minLength',
    defaultParam: 6,
    validate: (value: string, param = 6) => value.length >= param,
  },
  maxLength: {
    key: 'maxLength',
    labelKey: 'auth.password_input.rules.maxLength',
    defaultParam: 20,
    validate: (value: string, param = 20) => value.length <= param,
  },
  hasUppercase: {
    key: 'hasUppercase',
    labelKey: 'auth.password_input.rules.hasUppercase',
    validate: (value: string) => /[A-Z]/.test(value),
  },
  hasLowercase: {
    key: 'hasLowercase',
    labelKey: 'auth.password_input.rules.hasLowercase',
    validate: (value: string) => /[a-z]/.test(value),
  },
  hasNumber: {
    key: 'hasNumber',
    labelKey: 'auth.password_input.rules.hasNumber',
    validate: (value: string) => /[0-9]/.test(value),
  },
  hasSpecial: {
    key: 'hasSpecial',
    labelKey: 'auth.password_input.rules.hasSpecial',
    validate: (value: string) => /[!@#$%^&*(),.?":{}|<>]/.test(value),
  },
  noSpaces: {
    key: 'noSpaces',
    labelKey: 'auth.password_input.rules.noSpaces',
    validate: (value: string) => !/\s/.test(value),
  },
  minTypes: {
    key: 'minTypes',
    labelKey: 'auth.password_input.rules.minTypes',
    defaultParam: 3,
    validate: (value: string, param = 3) => {
      let types = 0;
      if (/[A-Z]/.test(value)) types++;
      if (/[a-z]/.test(value)) types++;
      if (/[0-9]/.test(value)) types++;
      if (/[!@#$%^&*(),.?":{}|<>]/.test(value)) types++;
      return types >= param;
    },
  },
};

/**
 * ĻĖ░ļ│Ė ļ╣äļ░Ćļ▓łĒśĖ Ļ▓Ćņ”Ø ĻĘ£ņ╣Ö
 *
 * ļ░▒ņŚöļō£ Ļ▓Ćņ”Ø ĻĘ£ņ╣Ö(RegisterRequest.php)Ļ│╝ ļÅÖņØ╝:
 * - password: required|string|min:6|confirmed
 */
export const defaultPasswordRules: PasswordRule[] = [
  availablePasswordRules.minLength,
];

/**
 * Ēīīņŗ▒ļÉ£ ĻĘ£ņ╣Ö (ĻĘ£ņ╣Ö + ĒīīļØ╝ļ»ĖĒä░)
 */
interface ParsedRule {
  rule: PasswordRule;
  param?: number;
}

/**
 * enableRules ļ¼Ėņ×ÉņŚ┤ņØä Ēīīņŗ▒ĒĢśņŚ¼ ĻĘ£ņ╣ÖĻ│╝ ĒīīļØ╝ļ»ĖĒä░ļź╝ ņČöņČ£
 * ņśł: "minLength:12" ŌåÆ { rule: minLengthRule, param: 12 }
 * ņśł: "hasUppercase" ŌåÆ { rule: hasUppercaseRule, param: undefined }
 *
 * @param ruleString ĻĘ£ņ╣Ö ļ¼Ėņ×ÉņŚ┤ (ņśł: "minLength:12" ļśÉļŖö "hasUppercase")
 * @returns Ēīīņŗ▒ļÉ£ ĻĘ£ņ╣Ö ļśÉļŖö null (ĻĘ£ņ╣ÖņØ┤ ņĪ┤ņ×¼ĒĢśņ¦Ć ņĢŖļŖö Ļ▓ĮņÜ░)
 */
function parseRuleString(ruleString: string): ParsedRule | null {
  const [key, paramStr] = ruleString.split(':');
  const rule = availablePasswordRules[key];
  if (!rule) return null;

  const param = paramStr ? parseInt(paramStr, 10) : rule.defaultParam;
  return { rule, param: isNaN(param as number) ? rule.defaultParam : param };
}

/**
 * PasswordInputņŚÉņä£ ņé¼ņÜ®ĒĢśņ¦Ć ņĢŖļŖö HTML ņåŹņä▒ ļ¬®ļĪØ
 * (ĻĘĖļłäļ│┤ļō£7 Ēģ£Ēöīļ”┐ ņŚöņ¦äņŚÉņä£ ņĀäļŗ¼ļÉśļŖö ņ╗żņŖżĒģĆ ņåŹņä▒)
 */
interface NonStandardProps {
  loadingactions?: unknown;
  formdata?: unknown;
}

export interface PasswordInputProps extends Omit<React.InputHTMLAttributes<HTMLInputElement>, 'type'> {
  /** ļĀłņØ┤ļĖö ĒģŹņŖżĒŖĖ */
  label?: string;
  /** ņŚÉļ¤¼ ļ®öņŗ£ņ¦Ć */
  error?: string;
  /** ļ╣äļ░Ćļ▓łĒśĖ ļ│┤ĻĖ░/ņł©ĻĖ░ĻĖ░ ļ▓äĒŖ╝ Ēæ£ņŗ£ */
  showToggle?: boolean;
  /** ļ╣äļ░Ćļ▓łĒśĖ ņĪ░Ļ▒┤ Ļ▓Ćņ”Ø Ēæ£ņŗ£ */
  showValidation?: boolean;
  /** ļ╣äļ░Ćļ▓łĒśĖ ĒÖĢņØĖ ļ¬©ļō£ (ĒÖĢņØĖ ĒĢäļō£ļĪ£ ņé¼ņÜ®) */
  isConfirmField?: boolean;
  /** ļ╣äļ░Ćļ▓łĒśĖ ĒÖĢņØĖ ļīĆņāü Ļ░Æ (isConfirmFieldĻ░Ć trueņØ╝ ļĢī ĒĢäņÜö) */
  confirmTarget?: string;
  /** ļ╣äļ░Ćļ▓łĒśĖ ĒÖĢņØĖ ņØ╝ņ╣ś ņŚ¼ļČĆ ņĮ£ļ░▒ */
  onMatchChange?: (isMatch: boolean) => void;
  /** ļ╣äļ░Ćļ▓łĒśĖ ņ£ĀĒÜ©ņä▒ ļ│ĆĻ▓Į ņĮ£ļ░▒ */
  onValidityChange?: (isValid: boolean, failedRules: string[]) => void;
  /** ņ╗żņŖżĒģĆ ļ╣äļ░Ćļ▓łĒśĖ ĻĘ£ņ╣Ö (ĻĖ░ļ│Ė ĻĘ£ņ╣Ö ļīĆņ▓┤, ņĮöļō£ņŚÉņä£ļ¦ī ņé¼ņÜ®) */
  rules?: PasswordRule[];
  /**
   * ĒÖ£ņä▒ĒÖöĒĢĀ ĻĘ£ņ╣Ö Ēéż ļ¬®ļĪØ (JSON ļĀłņØ┤ņĢäņøāņŚÉņä£ ņé¼ņÜ®)
   * ņé¼ņÜ® Ļ░ĆļŖź: minLength, maxLength, hasUppercase, hasLowercase, hasNumber, hasSpecial, noSpaces, minTypes
   * ĒīīļØ╝ļ»ĖĒä░ ņ¦ĆņĀĢ: "ĻĘ£ņ╣Öļ¬ģ:Ļ░Æ" ĒśĢņŗØ (ņśł: "minLength:12", "minTypes:3")
   * ņśł: ["minLength:12", "hasUppercase", "hasSpecial"]
   */
  enableRules?: string[];
  /** Ēæ£ņŗ£ĒĢĀ ĻĘ£ņ╣Ö Ēéż ļ¬®ļĪØ (ņ¦ĆņĀĢĒĢśņ¦Ć ņĢŖņ£╝ļ®┤ ņĀäņ▓┤ Ēæ£ņŗ£) */
  showRules?: string[];
  /** ņ×ģļĀź ĒĢäļō£ wrapper Ēü┤ļ×śņŖż */
  wrapperClassName?: string;
  /** Ļ▓Ćņ”Ø Ļ▓░Ļ│╝ Ēæ£ņŗ£ ņśüņŚŁ Ēü┤ļ×śņŖż */
  validationClassName?: string;
}

/**
 * ļ╣äļ░Ćļ▓łĒśĖ ņ×ģļĀź ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * ļ╣äļ░Ćļ▓łĒśĖ ļ│┤ĻĖ░/ņł©ĻĖ░ĻĖ░ ĒåĀĻĖĆ, ņŗżņŗ£Ļ░ä ņĪ░Ļ▒┤ Ļ▓Ćņ”Ø, ļ╣äļ░Ćļ▓łĒśĖ ĒÖĢņØĖ ĻĖ░ļŖźņØä ņĀ£Ļ│ĄĒĢ®ļŗłļŗż.
 *
 * @example
 * // ĻĖ░ļ│Ė ņé¼ņÜ® (ļ│┤ĻĖ░/ņł©ĻĖ░ĻĖ░ļ¦ī)
 * <PasswordInput name="password" showToggle />
 *
 * @example
 * // ņĪ░Ļ▒┤ Ļ▓Ćņ”Ø Ēæ£ņŗ£
 * <PasswordInput
 *   name="password"
 *   showToggle
 *   showValidation
 *   onValidityChange={(isValid, failed) => console.log(isValid, failed)}
 * />
 *
 * @example
 * // ļ╣äļ░Ćļ▓łĒśĖ ĒÖĢņØĖ ĒĢäļō£
 * <PasswordInput
 *   name="password_confirmation"
 *   isConfirmField
 *   confirmTarget={password}
 *   onMatchChange={(isMatch) => console.log(isMatch)}
 * />
 */
export const PasswordInput = forwardRef<HTMLInputElement, PasswordInputProps>(
  (
    {
      label,
      error,
      showToggle = true,
      showValidation = false,
      isConfirmField = false,
      confirmTarget,
      onMatchChange,
      onValidityChange,
      rules,
      enableRules,
      showRules,
      wrapperClassName = '',
      validationClassName = '',
      className = '',
      onChange,
      value,
      defaultValue,
      disabled,
      ...props
    },
    ref
  ) => {
    const internalRef = useRef<HTMLInputElement>(null);
    useImperativeHandle(ref, () => internalRef.current as HTMLInputElement);

    // ļ╣äļ░Ćļ▓łĒśĖ ļ│┤ĻĖ░/ņł©ĻĖ░ĻĖ░ ņāüĒā£
    const [showPassword, setShowPassword] = useState(false);

    // CapsLock ĒÖ£ņä▒ĒÖö ņāüĒā£
    const [capsLockOn, setCapsLockOn] = useState(false);

    // ļé┤ļČĆ Ļ░Æ ņāüĒā£ (controlled/uncontrolled ņ¦ĆņøÉ)
    const [internalValue, setInternalValue] = useState<string>(
      (value as string) ?? (defaultValue as string) ?? ''
    );

    // ņÖĖļČĆ valueĻ░Ć ļ│ĆĻ▓ĮļÉśļ®┤ ļÅÖĻĖ░ĒÖö
    useEffect(() => {
      if (value !== undefined) {
        setInternalValue(value as string);
      }
    }, [value]);

    // ņé¼ņÜ®ĒĢĀ ĻĘ£ņ╣Ö Ļ▓░ņĀĢ: rules > enableRules > defaultPasswordRules
    const parsedRules = useMemo((): ParsedRule[] => {
      // 1. rules propņØ┤ ņ×łņ£╝ļ®┤ ĻĘĖļīĆļĪ£ ņé¼ņÜ® (ņĮöļō£ņŚÉņä£ ņ¦üņĀæ ņĀäļŗ¼, ĻĖ░ļ│Ė ĒīīļØ╝ļ»ĖĒä░ ņĀüņÜ®)
      if (rules && rules.length > 0) {
        return rules.map((rule) => ({ rule, param: rule.defaultParam }));
      }

      // 2. enableRulesĻ░Ć ņ×łņ£╝ļ®┤ Ēīīņŗ▒ĒĢśņŚ¼ ĻĘ£ņ╣ÖĻ│╝ ĒīīļØ╝ļ»ĖĒä░ ņČöņČ£
      if (enableRules && enableRules.length > 0) {
        return enableRules
          .map((ruleStr) => parseRuleString(ruleStr))
          .filter((parsed): parsed is ParsedRule => parsed !== null);
      }

      // 3. ĻĖ░ļ│Ė ĻĘ£ņ╣Ö ņé¼ņÜ®
      return defaultPasswordRules.map((rule) => ({ rule, param: rule.defaultParam }));
    }, [rules, enableRules]);

    // Ēæ£ņŗ£ĒĢĀ ĻĘ£ņ╣Ö ĒĢäĒä░ļ¦ü
    const displayRules = useMemo(() => {
      if (!showRules || showRules.length === 0) return parsedRules;
      return parsedRules.filter((parsed) => showRules.includes(parsed.rule.key));
    }, [parsedRules, showRules]);

    // ļ╣äļ░Ćļ▓łĒśĖ ĻĘ£ņ╣Ö Ļ▓Ćņ”Ø Ļ▓░Ļ│╝
    const validationResults = useMemo(() => {
      if (!showValidation || isConfirmField) return {};
      return displayRules.reduce((acc, { rule, param }) => {
        acc[rule.key] = rule.validate(internalValue, param);
        return acc;
      }, {} as Record<string, boolean>);
    }, [internalValue, displayRules, showValidation, isConfirmField]);

    // ļ╣äļ░Ćļ▓łĒśĖ ĒÖĢņØĖ ņØ╝ņ╣ś ņŚ¼ļČĆ
    const isMatch = useMemo(() => {
      if (!isConfirmField || confirmTarget === undefined) return true;
      return internalValue === confirmTarget && internalValue.length > 0;
    }, [isConfirmField, internalValue, confirmTarget]);

    // ņĀäņ▓┤ ņ£ĀĒÜ©ņä▒ (ļ¬©ļōĀ ĻĘ£ņ╣Ö ĒåĄĻ│╝)
    const isAllValid = useMemo(() => {
      if (!showValidation) return true;
      return Object.values(validationResults).every((v) => v);
    }, [validationResults, showValidation]);

    // ņ£ĀĒÜ©ņä▒ ļ│ĆĻ▓Į ņĮ£ļ░▒
    useEffect(() => {
      if (onValidityChange && showValidation && !isConfirmField) {
        const failedRules = Object.entries(validationResults)
          .filter(([, passed]) => !passed)
          .map(([key]) => key);
        onValidityChange(isAllValid, failedRules);
      }
    }, [isAllValid, validationResults, onValidityChange, showValidation, isConfirmField]);

    // ļ╣äļ░Ćļ▓łĒśĖ ĒÖĢņØĖ ņØ╝ņ╣ś ņĮ£ļ░▒
    useEffect(() => {
      if (onMatchChange && isConfirmField) {
        onMatchChange(isMatch);
      }
    }, [isMatch, onMatchChange, isConfirmField]);

    // ļ╣äļ░Ćļ▓łĒśĖ ļ│┤ĻĖ░/ņł©ĻĖ░ĻĖ░ ĒåĀĻĖĆ
    const handleToggle = useCallback(() => {
      setShowPassword((prev) => !prev);
    }, []);

    // ņ×ģļĀźĻ░Æ ļ│ĆĻ▓Į ņ▓śļ”¼
    const handleChange = useCallback(
      (e: React.ChangeEvent<HTMLInputElement>) => {
        const newValue = e.target.value;
        setInternalValue(newValue);
        if (onChange) {
          onChange(e);
        }
      },
      [onChange]
    );

    // CapsLock ņāüĒā£ Ļ░Éņ¦Ć
    const handleKeyEvent = useCallback(
      (e: React.KeyboardEvent<HTMLInputElement>) => {
        setCapsLockOn(e.getModifierState('CapsLock'));
      },
      []
    );

    // HTML Ēæ£ņżĆ ņåŹņä▒ņØ┤ ņĢäļŗī Ļ▓āļōżņØä ĒĢäĒä░ļ¦ü (ĒāĆņ×ģ ņĢłņĀäņä▒ Ļ░£ņäĀ)
    const { loadingactions, formdata, ...validProps } = props as typeof props & NonStandardProps;

    return (
      <div className={`relative ${wrapperClassName}`}>
        {/* ņ×ģļĀź ĒĢäļō£ wrapper */}
        <div className="relative">
          <input
            ref={internalRef}
            type={showPassword ? 'text' : 'password'}
            className={`${className} ${showToggle ? 'pr-10' : ''}`}
            value={value !== undefined ? (value as string) : undefined}
            defaultValue={value === undefined ? defaultValue : undefined}
            onChange={handleChange}
            onKeyDown={handleKeyEvent}
            onKeyUp={handleKeyEvent}
            disabled={disabled}
            {...validProps}
          />

          {/* ļ╣äļ░Ćļ▓łĒśĖ ļ│┤ĻĖ░/ņł©ĻĖ░ĻĖ░ ļ▓äĒŖ╝ */}
          {showToggle && (
            <button
              type="button"
              onClick={handleToggle}
              disabled={disabled}
              className="absolute right-2 top-1/2 -translate-y-1/2 p-1 text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200 disabled:opacity-50 disabled:cursor-not-allowed dark:disabled:opacity-50"
              aria-label={showPassword ? t('auth.password_input.hide') : t('auth.password_input.show')}
            >
              <Icon
                name={showPassword ? 'eye-slash' : 'eye'}
                className="w-5 h-5"
              />
            </button>
          )}
        </div>

        {/* CapsLock Ļ▓ĮĻ│Ā */}
        {capsLockOn && !showPassword && (
          <div className="mt-2 flex items-center gap-1.5 text-sm text-yellow-600 dark:text-yellow-400">
            <Icon name="triangle-exclamation" className="w-4 h-4" />
            <span>{t('auth.password_input.caps_lock_on')}</span>
          </div>
        )}

        {/* ļ╣äļ░Ćļ▓łĒśĖ ĒÖĢņØĖ ņØ╝ņ╣ś/ļČłņØ╝ņ╣ś Ēæ£ņŗ£ */}
        {isConfirmField && confirmTarget !== undefined && internalValue.length > 0 && (
          <div
            className={`mt-2 flex items-center gap-1.5 text-sm ${
              isMatch
                ? 'text-green-600 dark:text-green-400'
                : 'text-red-600 dark:text-red-400'
            }`}
          >
            <Icon
              name={isMatch ? 'check-circle' : 'xmark-circle'}
              className="w-4 h-4"
            />
            <span>{isMatch ? t('auth.password_input.match') : t('auth.password_input.mismatch')}</span>
          </div>
        )}

        {/* ļ╣äļ░Ćļ▓łĒśĖ ņĪ░Ļ▒┤ Ļ▓Ćņ”Ø Ēæ£ņŗ£ */}
        {showValidation && !isConfirmField && internalValue.length > 0 && (
          <div className={`mt-2 space-y-1 ${validationClassName}`}>
            {displayRules.map(({ rule, param }) => {
              const passed = validationResults[rule.key];
              // ĒīīļØ╝ļ»ĖĒä░Ļ░Ć ņ×łļŖö ĻĘ£ņ╣ÖņØĆ ļØ╝ļ▓©ņŚÉ ĒīīļØ╝ļ»ĖĒä░ Ļ░Æ ņĀäļŗ¼
              const labelParams = param !== undefined ? { count: param } : undefined;
              return (
                <div
                  key={rule.key}
                  className={`flex items-center gap-1.5 text-sm ${
                    passed
                      ? 'text-green-600 dark:text-green-400'
                      : 'text-gray-500 dark:text-gray-400'
                  }`}
                >
                  <Icon
                    name={passed ? 'check-circle' : 'circle'}
                    className="w-4 h-4"
                  />
                  <span>{t(rule.labelKey, labelParams)}</span>
                </div>
              );
            })}
          </div>
        )}

        {/* ņŚÉļ¤¼ ļ®öņŗ£ņ¦Ć */}
        {error && (
          <p className="mt-1 text-sm text-red-600 dark:text-red-400">{error}</p>
        )}
      </div>
    );
  }
);

PasswordInput.displayName = 'PasswordInput';
