/**
 * PostReactions ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * Ļ▓īņŗ£ĻĖĆņŚÉ ļīĆĒĢ£ ļ”¼ņĢĪņģś(ņØ┤ļ¬©ņ¦Ć) ļ▓äĒŖ╝ ĻĘĖļŻ╣ņ×ģļŗłļŗż.
 * ņóŗņĢäņÜö, ņøāĻ▓©ņÜö, ļÅÖņØśĒĢ┤ņÜö, Ļ░Éņé¼ĒĢ┤ņÜö, ļåĆļØ╝ņøīņÜö 5ņóģ ļ”¼ņĢĪņģśņØä ņ¦ĆņøÉĒĢ®ļŗłļŗż.
 */

import React from 'react';
import { Div } from '../basic/Div';
import { Button } from '../basic/Button';
import { Span } from '../basic/Span';

// Logger ņäżņĀĢ (G7Core ņ┤łĻĖ░ĒÖö ņĀäņŚÉļÅä ļÅÖņ×æĒĢśļÅäļĪØ ĒÅ┤ļ░▒ ĒÅ¼ĒĢ©)
const logger = ((window as any).G7Core?.createLogger?.('Comp:PostReactions')) ?? {
    log: (...args: unknown[]) => console.log('[Comp:PostReactions]', ...args),
    warn: (...args: unknown[]) => console.warn('[Comp:PostReactions]', ...args),
    error: (...args: unknown[]) => console.error('[Comp:PostReactions]', ...args),
};

/**
 * G7Core ļ▓łņŚŁ ĒĢ©ņłś
 */
const t = (key: string, params?: Record<string, string | number>) =>
  (window as any).G7Core?.t?.(key, params) ?? key;

type ReactionType = 'like' | 'funny' | 'agree' | 'thanks' | 'wow';

interface ReactionCount {
  type: ReactionType;
  count: number;
}

interface PostReactionsProps {
  /** Ļ░ü ļ”¼ņĢĪņģśļ│ä ņ╣┤ņÜ┤ĒŖĖ */
  reactions: ReactionCount[];
  /** Ēśäņ×¼ ņé¼ņÜ®ņ×ÉņØś ļ”¼ņĢĪņģś (ņŚåņ£╝ļ®┤ null) */
  userReaction?: ReactionType | null;
  /** Ļ▓īņŗ£ĻĖĆ ID */
  postId: number;
  /** ļ”¼ņĢĪņģś Ēü┤ļ”Ł ņĮ£ļ░▒ */
  onReact?: (type: ReactionType) => void;
  /** ņ╗┤ĒÅ¼ļäīĒŖĖ Ēü¼ĻĖ░ */
  size?: 'sm' | 'md' | 'lg';
  /** ņČöĻ░Ć CSS Ēü┤ļ×śņŖż */
  className?: string;
}

interface ReactionConfig {
  type: ReactionType;
  emoji: string;
  labelKey: string;
  activeColor: string;
}

/**
 * ļ”¼ņĢĪņģś ņäżņĀĢ
 */
const REACTION_CONFIGS: ReactionConfig[] = [
  { type: 'like', emoji: '­¤æŹ', labelKey: 'board.reactions.like', activeColor: 'bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400' },
  { type: 'funny', emoji: '­¤śé', labelKey: 'board.reactions.funny', activeColor: 'bg-yellow-100 dark:bg-yellow-900/30 text-yellow-600 dark:text-yellow-400' },
  { type: 'agree', emoji: '­¤æī', labelKey: 'board.reactions.agree', activeColor: 'bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400' },
  { type: 'thanks', emoji: '­¤ÖÅ', labelKey: 'board.reactions.thanks', activeColor: 'bg-purple-100 dark:bg-purple-900/30 text-purple-600 dark:text-purple-400' },
  { type: 'wow', emoji: '­¤ś«', labelKey: 'board.reactions.wow', activeColor: 'bg-orange-100 dark:bg-orange-900/30 text-orange-600 dark:text-orange-400' },
];

/**
 * Ļ▓īņŗ£ĻĖĆ ļ”¼ņĢĪņģś ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * @example
 * ```tsx
 * <PostReactions
 *   reactions={[
 *     { type: 'like', count: 5 },
 *     { type: 'funny', count: 2 },
 *   ]}
 *   userReaction="like"
 *   postId={123}
 *   onReact={(type) => handleReact(type)}
 * />
 * ```
 *
 * @example
 * ```json
 * // ļĀłņØ┤ņĢäņøā JSONņŚÉņä£ ņé¼ņÜ®
 * {
 *   "type": "composite",
 *   "name": "PostReactions",
 *   "props": {
 *     "reactions": "{{post.data.reactions}}",
 *     "userReaction": "{{post.data.user_reaction}}",
 *     "postId": "{{post.data.id}}"
 *   }
 * }
 * ```
 */
const PostReactions: React.FC<PostReactionsProps> = ({
  reactions,
  userReaction,
  postId,
  onReact,
  size = 'md',
  className = '',
}) => {
  const sizeClasses = {
    sm: 'px-2 py-1 text-xs gap-1',
    md: 'px-3 py-1.5 text-sm gap-1.5',
    lg: 'px-4 py-2 text-base gap-2',
  };

  const emojiSizes = {
    sm: 'text-sm',
    md: 'text-base',
    lg: 'text-lg',
  };

  const getReactionCount = (type: ReactionType): number => {
    const reaction = reactions.find((r) => r.type === type);
    return reaction?.count ?? 0;
  };

  const handleClick = async (type: ReactionType) => {
    if (onReact) {
      onReact(type);
      return;
    }

    // ĻĖ░ļ│Ė API ĒśĖņČ£
    try {
      const response = await fetch(`/api/posts/${postId}/reactions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ type }),
        credentials: 'include',
      });

      if (!response.ok) {
        throw new Error('ļ”¼ņĢĪņģś ņ▓śļ”¼ ņŗżĒī©');
      }

      // ņä▒Ļ│Ą ņŗ£ ĒÄśņØ┤ņ¦Ć ņāłļĪ£Ļ│Āņ╣© ļśÉļŖö ņāüĒā£ ņŚģļŹ░ņØ┤ĒŖĖ
      window.location.reload();
    } catch (error) {
      logger.error('ļ”¼ņĢĪņģś ņśżļźś:', error);
    }
  };

  return (
    <Div className={`flex flex-wrap gap-2 ${className}`}>
      {REACTION_CONFIGS.map((config) => {
        const count = getReactionCount(config.type);
        const isActive = userReaction === config.type;

        return (
          <Button
            key={config.type}
            onClick={() => handleClick(config.type)}
            className={`
              inline-flex items-center rounded-full border transition-colors
              ${sizeClasses[size]}
              ${isActive
                ? `${config.activeColor} border-transparent`
                : 'border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700'
              }
            `}
            title={t(config.labelKey)}
          >
            <Span className={emojiSizes[size]}>{config.emoji}</Span>
            <Span>{t(config.labelKey)}</Span>
            {count > 0 && (
              <Span className="font-medium">{count}</Span>
            )}
          </Button>
        );
      })}
    </Div>
  );
};

export default PostReactions;
