import React, { useMemo } from 'react';
import { Div } from '../basic/Div';
import { Img } from '../basic/Img';
import { Icon } from '../basic/Icon';

/**
 * ņĢäļ░öĒāĆ Ēü¼ĻĖ░ ĒāĆņ×ģ
 */
export type AvatarSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl' | '2xl' | '3xl' | '4xl' | '5xl';

/**
 * ņé¼ņØ┤ņ”łļ│ä Tailwind Ēü┤ļ×śņŖż ļ¦żĒĢæ
 * - Ēü¼ĻĖ░ (w/h) + ĒģŹņŖżĒŖĖ Ēü¼ĻĖ░ (ņØ┤ļŗłņģ£ņÜ®)
 */
const SIZE_CLASSES: Record<AvatarSize, string> = {
  xs: 'w-6 h-6 text-xs',         // 24px
  sm: 'w-8 h-8 text-sm',         // 32px
  md: 'w-10 h-10 text-base',     // 40px
  lg: 'w-12 h-12 text-lg',       // 48px
  xl: 'w-16 h-16 text-xl',       // 64px
  '2xl': 'w-24 h-24 text-2xl',   // 96px
  '3xl': 'w-32 h-32 text-3xl',   // 128px
  '4xl': 'w-40 h-40 text-4xl',   // 160px
  '5xl': 'w-48 h-48 text-5xl',   // 192px
} as const;

/**
 * ĻĖ░ļ│Ė ņ╗©ĒģīņØ┤ļäł ņŖżĒāĆņØ╝ (Ļ│ĄĒåĄ)
 */
const BASE_CONTAINER_CLASSES = 'rounded-full overflow-hidden flex-shrink-0 border border-gray-200 dark:border-gray-700';

/**
 * ĒāłĒć┤ ņé¼ņÜ®ņ×É ņŖżĒāĆņØ╝
 */
const WITHDRAWN_CLASSES = 'grayscale opacity-50';

/**
 * ņØ┤ļŗłņģ£ ļ░░Ļ▓Į ņŖżĒāĆņØ╝
 */
const INITIAL_BG_CLASSES = {
  normal: 'bg-gradient-to-br from-blue-500 to-purple-600',
  withdrawn: 'bg-gray-300 dark:bg-gray-600',
  guest: 'bg-gray-200 dark:bg-gray-700',
} as const;

/**
 * Author Ļ░Øņ▓┤ ņØĖĒä░ĒÄśņØ┤ņŖż
 */
export interface AuthorInfo {
  /** ņé¼ņÜ®ņ×É ID */
  id?: string | number;
  /** ņé¼ņÜ®ņ×É ņØ┤ļ”ä */
  name?: string;
  /** ņĢäļ░öĒāĆ URL */
  avatar?: string;
  /** ņé¼ņÜ®ņ×É ņāüĒā£ */
  status?: 'active' | 'inactive' | 'blocked' | 'withdrawn';
  /** ļ╣äĒÜīņøÉ ņŚ¼ļČĆ */
  is_guest?: boolean;
}

export interface AvatarProps {
  /**
   * ņ×æņä▒ņ×É Ļ░Øņ▓┤ (ĻČīņ×ź)
   * API ņØæļŗĄņØś author Ļ░Øņ▓┤ļź╝ ĻĘĖļīĆļĪ£ ņĀäļŗ¼ĒĢśļ®┤ ļÉ®ļŗłļŗż.
   * Ļ░£ļ│ä props(name, avatar ļō▒)Ļ░Ć ĒĢ©Ļ╗ś ņĀäļŗ¼ļÉśļ®┤ Ļ░£ļ│ä propsĻ░Ć ņÜ░ņäĀĒĢ®ļŗłļŗż.
   */
  author?: AuthorInfo;
  /** ņé¼ņÜ®ņ×É ņØ┤ļ”ä (author.nameļ│┤ļŗż ņÜ░ņäĀ) */
  name?: string;
  /** ņĢäļ░öĒāĆ ņØ┤ļ»Ėņ¦Ć URL (author.avatarļ│┤ļŗż ņÜ░ņäĀ) */
  avatar?: string;
  /** ņé¼ņØ┤ņ”ł @default 'md' */
  size?: AvatarSize;
  /** ņČöĻ░Ć className */
  className?: string;
  /** ļĀłņØ┤ņĢäņøā JSON text ņåŹņä▒ (nameļ│┤ļŗż ņÜ░ņäĀ) */
  text?: string;
  /** ĒāłĒć┤ĒĢ£ ņé¼ņÜ®ņ×É ņŚ¼ļČĆ (author.status === 'withdrawn'Ļ│╝ OR ņĪ░Ļ▒┤) @default false */
  isWithdrawn?: boolean;
  /** ļ╣äĒÜīņøÉ ņŚ¼ļČĆ (author.is_guestļ│┤ļŗż ņÜ░ņäĀ) @default false */
  isGuest?: boolean;
}

/**
 * Avatar ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * ņé¼ņÜ®ņ×É ņĢäļ░öĒāĆļź╝ Ēæ£ņŗ£ĒĢśļŖö ņ×¼ņé¼ņÜ® Ļ░ĆļŖźĒĢ£ composite ņ╗┤ĒÅ¼ļäīĒŖĖņ×ģļŗłļŗż.
 * - ņĢäļ░öĒāĆ ņØ┤ļ»Ėņ¦ĆĻ░Ć ņ×łņ£╝ļ®┤ ņØ┤ļ»Ėņ¦Ć Ēæ£ņŗ£
 * - ņØ┤ļ»Ėņ¦ĆĻ░Ć ņŚåņ£╝ļ®┤ ņØ┤ļ”äņØś ņ▓½ ĻĖĆņ×É(ņØ┤ļŗłņģ£) Ēæ£ņŗ£
 * - ļ╣äĒÜīņøÉ: ņŚ░ĒĢ£ ĒÜīņāē ļ░░Ļ▓Į + ņé¼ļ×ī ņŗżļŻ©ņŚŻ ņĢäņØ┤ņĮś
 * - ĒāłĒć┤ĒĢ£ ņé¼ņÜ®ņ×É: ĒÜīņāē ļ╣ł ņøÉ (ĻĘĖļĀłņØ┤ņŖżņ╝ĆņØ╝ + Ēł¼ļ¬ģļÅä)
 *
 * ## Props ņÜ░ņäĀņł£ņ£ä
 * ļ¬ģņŗ£ņĀüņ£╝ļĪ£ ņĀäļŗ¼ĒĢ£ propsĻ░Ć authorņŚÉņä£ ņČöņČ£ĒĢ£ Ļ░Æļ│┤ļŗż ņÜ░ņäĀĒĢ®ļŗłļŗż.
 * - ņØ┤ļ”ä: text > name > author.name
 * - ņĢäļ░öĒāĆ: avatar > author.avatar
 * - ļ╣äĒÜīņøÉ ņŚ¼ļČĆ: isGuest > author.is_guest
 * - ĒāłĒć┤ ņŚ¼ļČĆ: isWithdrawn || author.status === 'withdrawn'
 *
 * @example
 * // ļĀłņØ┤ņĢäņøā JSONņŚÉņä£ ņé¼ņÜ® (author Ļ░Øņ▓┤ ņĀäļŗ¼ - ĻČīņ×ź)
 * {
 *   "type": "composite",
 *   "name": "Avatar",
 *   "props": {
 *     "author": "{{post.author}}",
 *     "size": "md"
 *   }
 * }
 *
 * @example
 * // authorņÖĆ Ļ░£ļ│ä props Ēś╝ĒĢ® ņé¼ņÜ® (Ļ░£ļ│ä propsĻ░Ć ņÜ░ņäĀ)
 * {
 *   "type": "composite",
 *   "name": "Avatar",
 *   "props": {
 *     "author": "{{post.author}}",
 *     "avatar": "/images/custom-avatar.png",
 *     "size": "md"
 *   }
 * }
 * // author.avatarĻ░Ć ņ×łņ¢┤ļÅä "/images/custom-avatar.png"ņØ┤ Ēæ£ņŗ£ļÉ©
 */
export const Avatar: React.FC<AvatarProps> = ({
  author,
  name,
  avatar,
  size = 'md',
  className = '',
  text,
  isWithdrawn = false,
  isGuest = false,
}) => {
  // ļ¬ģņŗ£ņĀü props > author ņČöņČ£Ļ░Æ ņł£ņä£ļĪ£ Ļ▓░ņĀĢ
  const actualAvatar = avatar ?? author?.avatar;
  const actualName = text ?? name ?? author?.name ?? '?';
  const actualIsWithdrawn = isWithdrawn || author?.status === 'withdrawn';
  const actualIsGuest = isGuest || author?.is_guest || false;

  // ņ╗©ĒģīņØ┤ļäł Ēü┤ļ×śņŖż ļ®öļ¬©ņØ┤ņĀ£ņØ┤ņģś
  const containerClasses = useMemo(() => {
    const sizeClass = SIZE_CLASSES[size] || SIZE_CLASSES.md;
    const withdrawnClass = actualIsWithdrawn ? WITHDRAWN_CLASSES : '';

    return [sizeClass, BASE_CONTAINER_CLASSES, withdrawnClass, className]
      .filter(Boolean)
      .join(' ');
  }, [size, actualIsWithdrawn, className]);

  // ņØ┤ļŗłņģ£ ļ░░Ļ▓Į Ēü┤ļ×śņŖż
  const initialBgClass = actualIsGuest
    ? INITIAL_BG_CLASSES.guest
    : actualIsWithdrawn
      ? INITIAL_BG_CLASSES.withdrawn
      : INITIAL_BG_CLASSES.normal;

  // ļ╣äĒÜīņøÉ: ņé¼ļ×ī ņŗżļŻ©ņŚŻ ņĢäņØ┤ņĮś (ņŚ░ĒĢ£ ĒÜīņāē), ĒāłĒć┤ ņé¼ņÜ®ņ×É: ņé¼ļ×ī ņŗżļŻ©ņŚŻ ņĢäņØ┤ņĮś (ņ¦äĒĢ£ ĒÜīņāē), ņØ╝ļ░ś: ņØ┤ļŗłņģ£
  const renderContent = () => {
    if (actualIsGuest) {
      return (
        <Div className={`w-full h-full flex items-center justify-center ${initialBgClass}`}>
          <Icon name="user" className="text-gray-400 dark:text-gray-500" />
        </Div>
      );
    }
    if (actualIsWithdrawn) {
      return (
        <Div className={`w-full h-full flex items-center justify-center ${initialBgClass}`}>
          <Icon name="user" className="text-gray-500 dark:text-gray-400" />
        </Div>
      );
    }
    return (
      <Div className={`w-full h-full flex items-center justify-center text-white font-semibold ${initialBgClass}`}>
        {actualName.charAt(0).toUpperCase()}
      </Div>
    );
  };

  return (
    <Div className={containerClasses}>
      {actualAvatar && !actualIsGuest && !actualIsWithdrawn ? (
        <Img
          src={actualAvatar}
          alt={actualName}
          className="w-full h-full object-cover"
        />
      ) : (
        renderContent()
      )}
    </Div>
  );
};
