import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Div } from '../basic/Div';
import { Button } from '../basic/Button';
import { Span } from '../basic/Span';
import { Icon } from '../basic/Icon';

/**
 * G7Core ļŗżĻĄŁņ¢┤ ĒŚ¼ĒŹ╝
 *
 * @param key ļŗżĻĄŁņ¢┤ Ēéż
 * @return ļ▓łņŚŁļÉ£ ļ¼Ėņ×ÉņŚ┤
 */
const t = (key: string): string =>
  (window as any).G7Core?.t?.(key) ?? key;

export interface ExpandableContentProps {
  /**
   * ņĀæĒ×ī ņāüĒā£ņØś ņĄ£ļīĆ ļåÆņØ┤ (px)
   * @default 500
   */
  maxHeight?: number;

  /**
   * ĒÄ╝ņ╣śĻĖ░ ļ▓äĒŖ╝ ĒģŹņŖżĒŖĖ
   */
  expandText?: string;

  /**
   * ņĀæĻĖ░ ļ▓äĒŖ╝ ĒģŹņŖżĒŖĖ
   */
  collapseText?: string;

  /**
   * ņé¼ņÜ®ņ×É ņĀĢņØś Ēü┤ļ×śņŖż
   */
  className?: string;

  /**
   * children ļĀīļŹöļ¦ü
   */
  children?: React.ReactNode;
}

/**
 * ExpandableContent ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * ņĮśĒģÉņĖĀĻ░Ć maxHeightļź╝ ņ┤łĻ│╝ĒĢśļ®┤ ĻĘĖļØ╝ļŹ░ņØ┤ņģś ņśżļ▓äļĀłņØ┤ņÖĆ ĒÄ╝ņ╣śĻĖ░/ņĀæĻĖ░ ļ▓äĒŖ╝ņØä Ēæ£ņŗ£ĒĢ®ļŗłļŗż.
 * ņĮśĒģÉņĖĀĻ░Ć ņ¦¦ņ£╝ļ®┤ ļ▓äĒŖ╝/ĻĘĖļØ╝ļŹ░ņØ┤ņģś ņŚåņØ┤ ņĀäņ▓┤ ņĮśĒģÉņĖĀļź╝ ĻĘĖļīĆļĪ£ Ēæ£ņŗ£ĒĢ®ļŗłļŗż.
 *
 * @example
 * // ļĀłņØ┤ņĢäņøā JSONņŚÉņä£ ņé¼ņÜ®
 * {
 *   "type": "composite",
 *   "name": "ExpandableContent",
 *   "props": { "maxHeight": 500 },
 *   "children": [
 *     {
 *       "type": "composite",
 *       "name": "HtmlContent",
 *       "props": { "content": "{{product.data?.description_localized ?? ''}}" }
 *     }
 *   ]
 * }
 */
export const ExpandableContent: React.FC<ExpandableContentProps> = ({
  maxHeight = 500,
  expandText,
  collapseText,
  className = '',
  children,
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [needsExpand, setNeedsExpand] = useState(false);
  const contentRef = useRef<HTMLDivElement>(null);

  /**
   * ņĮśĒģÉņĖĀ ļåÆņØ┤ļź╝ ņĖĪņĀĢĒĢśņŚ¼ ĒÄ╝ņ╣śĻĖ░ ļ▓äĒŖ╝ ĒĢäņÜö ņŚ¼ļČĆļź╝ Ļ▓░ņĀĢĒĢ®ļŗłļŗż.
   */
  const checkHeight = useCallback(() => {
    if (contentRef.current) {
      const scrollHeight = contentRef.current.scrollHeight;
      setNeedsExpand(scrollHeight > maxHeight);
    }
  }, [maxHeight]);

  useEffect(() => {
    checkHeight();

    // ņØ┤ļ»Ėņ¦Ć ļĪ£ļō£ Ēøä ļåÆņØ┤ ņ×¼ņĖĪņĀĢ
    const container = contentRef.current;
    if (!container) return;

    const images = container.querySelectorAll('img');
    images.forEach((img) => {
      if (!img.complete) {
        img.addEventListener('load', checkHeight);
      }
    });

    // ResizeObserverļĪ£ ļÅÖņĀü ņĮśĒģÉņĖĀ ļ│ĆĻ▓Į Ļ░Éņ¦Ć
    let observer: ResizeObserver | null = null;
    if (typeof ResizeObserver !== 'undefined') {
      observer = new ResizeObserver(checkHeight);
      observer.observe(container);
    }

    return () => {
      images.forEach((img) => {
        img.removeEventListener('load', checkHeight);
      });
      observer?.disconnect();
    };
  }, [checkHeight, children]);

  const toggleExpand = () => {
    setIsExpanded((prev) => !prev);
  };

  const resolvedExpandText = expandText || t('sirsoft-ecommerce.shop.product.expand_detail');
  const resolvedCollapseText = collapseText || t('sirsoft-ecommerce.shop.product.collapse_detail');

  return (
    <Div className={className}>
      {/* ņĮśĒģÉņĖĀ ņ╗©ĒģīņØ┤ļäł */}
      <Div className="relative">
        <Div
          ref={contentRef}
          className={
            !isExpanded && needsExpand
              ? 'overflow-hidden transition-[max-height] duration-300 ease-in-out'
              : 'transition-[max-height] duration-300 ease-in-out'
          }
          style={
            !isExpanded && needsExpand
              ? { maxHeight: `${maxHeight}px` }
              : undefined
          }
        >
          {children}
        </Div>

        {/* ĻĘĖļØ╝ļŹ░ņØ┤ņģś ņśżļ▓äļĀłņØ┤ */}
        {!isExpanded && needsExpand && (
          <Div className="absolute bottom-0 left-0 right-0 h-24 bg-gradient-to-t from-white dark:from-gray-900 to-transparent pointer-events-none" />
        )}
      </Div>

      {/* ĒÄ╝ņ╣śĻĖ░/ņĀæĻĖ░ ļ▓äĒŖ╝ (ņĀäņ▓┤ ļäłļ╣ä ļ░ö ņŖżĒāĆņØ╝) */}
      {needsExpand && (
        <Button
          type="button"
          onClick={toggleExpand}
          className="flex items-center justify-center w-full py-3.5 bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors cursor-pointer gap-1.5"
        >
          <Span className="text-sm font-semibold text-gray-600 dark:text-gray-400">
            {isExpanded ? resolvedCollapseText : resolvedExpandText}
          </Span>
          <Icon
            name={isExpanded ? 'chevron-up' : 'chevron-down'}
            size="sm"
          />
        </Button>
      )}
    </Div>
  );
};

export default ExpandableContent;
