/**
 * ņäĀĒśĖ ĒåĄĒÖö ļĪ£ļō£ ĒĢĖļōżļ¤¼
 *
 * localStorageņŚÉņä£ ņé¼ņÜ®ņ×ÉĻ░Ć ņäĀĒāØĒĢ£ ĒåĄĒÖö ņäżņĀĢņØä ļĪ£ļō£ĒĢ®ļŗłļŗż.
 */

// Logger ņäżņĀĢ (G7Core ņ┤łĻĖ░ĒÖö ņĀäņŚÉļÅä ļÅÖņ×æĒĢśļÅäļĪØ ĒÅ┤ļ░▒ ĒÅ¼ĒĢ©)
const logger = ((window as any).G7Core?.createLogger?.('Handler:Currency')) ?? {
    log: (...args: unknown[]) => console.log('[Handler:Currency]', ...args),
    warn: (...args: unknown[]) => console.warn('[Handler:Currency]', ...args),
    error: (...args: unknown[]) => console.error('[Handler:Currency]', ...args),
};

import { HandlerContext } from '../types';

const STORAGE_KEY = 'g7_preferred_currency';
const DEFAULT_CURRENCY = 'KRW';

interface LoadPreferredCurrencyParams {
  defaultCurrency?: string;
}

/**
 * localStorageņŚÉņä£ ņäĀĒśĖ ĒåĄĒÖöļź╝ ļĪ£ļō£ĒĢśņŚ¼ ņĀäņŚŁ ņāüĒā£ņŚÉ ņäżņĀĢĒĢ®ļŗłļŗż.
 *
 * @param params.defaultCurrency - ĻĖ░ļ│Ė ĒåĄĒÖö (ņäĀĒāØ, ĻĖ░ļ│ĖĻ░Æ: 'KRW')
 * @param context - ĒĢĖļōżļ¤¼ ņ╗©ĒģŹņŖżĒŖĖ
 * @returns ļĪ£ļō£ļÉ£ ĒåĄĒÖö ņĮöļō£
 *
 * @example
 * // _user_base.jsonņØś init_actionsņŚÉņä£ ņé¼ņÜ®
 * {
 *   "init_actions": [
 *     {
 *       "handler": "loadPreferredCurrency",
 *       "params": { "defaultCurrency": "KRW" }
 *     }
 *   ]
 * }
 */
export function loadPreferredCurrencyHandler(
  params: LoadPreferredCurrencyParams,
  context: HandlerContext
): string {
  const { defaultCurrency = DEFAULT_CURRENCY } = params;

  let currency = defaultCurrency;

  try {
    if (typeof window !== 'undefined' && window.localStorage) {
      const stored = localStorage.getItem(STORAGE_KEY);
      if (stored && isValidCurrency(stored)) {
        currency = stored;
      }
    }
  } catch {
    // localStorage ņĀæĻĘ╝ ļČłĻ░Ć ņŗ£ ĻĖ░ļ│ĖĻ░Æ ņé¼ņÜ®
    logger.warn('localStorage ņĀæĻĘ╝ ļČłĻ░Ć, ĻĖ░ļ│Ė ĒåĄĒÖö ņé¼ņÜ®:', defaultCurrency);
  }

  // ņĀäņŚŁ ņāüĒā£ņŚÉ ņäżņĀĢ
  context.setState('global', { preferredCurrency: currency });

  return currency;
}

/**
 * ņäĀĒśĖ ĒåĄĒÖöļź╝ localStorageņŚÉ ņĀĆņ×źĒĢ®ļŗłļŗż.
 *
 * @param currencyCode - ņĀĆņ×źĒĢĀ ĒåĄĒÖö ņĮöļō£
 * @param context - ĒĢĖļōżļ¤¼ ņ╗©ĒģŹņŖżĒŖĖ
 *
 * @example
 * // ĒåĄĒÖö ņäĀĒāØ ļō£ļĪŁļŗżņÜ┤ņŚÉņä£ ņé¼ņÜ®
 * {
 *   "actions": [
 *     {
 *       "type": "click",
 *       "handler": "savePreferredCurrency",
 *       "params": { "currencyCode": "{{currency.code}}" }
 *     }
 *   ]
 * }
 */
export function savePreferredCurrencyHandler(
  params: { currencyCode: string },
  context: HandlerContext
): void {
  const { currencyCode } = params;

  if (!isValidCurrency(currencyCode)) {
    logger.warn('ņ£ĀĒÜ©ĒĢśņ¦Ć ņĢŖņØĆ ĒåĄĒÖö ņĮöļō£:', currencyCode);
    return;
  }

  try {
    if (typeof window !== 'undefined' && window.localStorage) {
      localStorage.setItem(STORAGE_KEY, currencyCode);
    }
  } catch {
    logger.warn('localStorage ņĀĆņ×ź ņŗżĒī©');
  }

  // ņĀäņŚŁ ņāüĒā£ ņŚģļŹ░ņØ┤ĒŖĖ
  context.setState('global', { preferredCurrency: currencyCode });
}

/**
 * ņ£ĀĒÜ©ĒĢ£ ĒåĄĒÖö ņĮöļō£ņØĖņ¦Ć ĒÖĢņØĖĒĢ®ļŗłļŗż.
 */
function isValidCurrency(code: string): boolean {
  const validCurrencies = ['KRW', 'USD', 'JPY', 'CNY', 'EUR'];
  return validCurrencies.includes(code);
}
