/**
 * QuantitySelector ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * ņłśļ¤ē ņäĀĒāØņØä ņ£äĒĢ£ +/- ļ▓äĒŖ╝ ņ╗┤ĒÅ¼ļäīĒŖĖņ×ģļŗłļŗż.
 * ņāüĒÆł ņāüņäĖ ĒÄśņØ┤ņ¦Ć, ņ×źļ░öĻĄ¼ļŗł ļō▒ņŚÉņä£ ņé¼ņÜ®ļÉ®ļŗłļŗż.
 */

import React from 'react';
import { Div } from '../basic/Div';
import { Button } from '../basic/Button';
import { Input } from '../basic/Input';
import { Icon } from '../basic/Icon';

interface QuantitySelectorProps {
  /** Ēśäņ×¼ ņłśļ¤ē */
  value: number;
  /** ņĄ£ņåī ņłśļ¤ē */
  min?: number;
  /** ņĄ£ļīĆ ņłśļ¤ē */
  max?: number;
  /** ņłśļ¤ē ļ│ĆĻ▓Į ņĮ£ļ░▒ */
  onChange: (value: number) => void;
  /** ņ╗┤ĒÅ¼ļäīĒŖĖ Ēü¼ĻĖ░ */
  size?: 'sm' | 'md' | 'lg';
  /** ļ╣äĒÖ£ņä▒ĒÖö ņŚ¼ļČĆ */
  disabled?: boolean;
  /** ņČöĻ░Ć CSS Ēü┤ļ×śņŖż */
  className?: string;
}

/**
 * ņłśļ¤ē ņäĀĒāØ ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * @example
 * ```tsx
 * const [quantity, setQuantity] = useState(1);
 *
 * <QuantitySelector
 *   value={quantity}
 *   min={1}
 *   max={10}
 *   onChange={setQuantity}
 * />
 * ```
 *
 * @example
 * ```json
 * // ļĀłņØ┤ņĢäņøā JSONņŚÉņä£ ņé¼ņÜ®
 * {
 *   "type": "composite",
 *   "name": "QuantitySelector",
 *   "props": {
 *     "value": "{{item.quantity}}",
 *     "min": 1,
 *     "max": "{{item.stock}}",
 *     "size": "sm"
 *   },
 *   "actions": [{
 *     "event": "onChange",
 *     "type": "change",
 *     "handler": "updateQuantity",
 *     "params": { "itemId": "{{item.id}}", "quantity": "{{$args[0]}}" }
 *   }]
 * }
 * ```
 */
const QuantitySelector: React.FC<QuantitySelectorProps> = ({
  value,
  min = 1,
  max = 999,
  onChange,
  size = 'md',
  disabled = false,
  className = '',
}) => {
  const sizeClasses = {
    sm: {
      container: 'h-8',
      button: 'w-8 h-8 text-sm',
      input: 'w-10 text-sm',
    },
    md: {
      container: 'h-10',
      button: 'w-10 h-10',
      input: 'w-14',
    },
    lg: {
      container: 'h-12',
      button: 'w-12 h-12 text-lg',
      input: 'w-16 text-lg',
    },
  };

  const classes = sizeClasses[size];

  const handleDecrease = () => {
    if (value > min && !disabled) {
      onChange(value - 1);
    }
  };

  const handleIncrease = () => {
    if (value < max && !disabled) {
      onChange(value + 1);
    }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newValue = parseInt(e.target.value, 10);
    if (!isNaN(newValue)) {
      const clampedValue = Math.max(min, Math.min(max, newValue));
      onChange(clampedValue);
    }
  };

  const handleInputBlur = (e: React.FocusEvent<HTMLInputElement>) => {
    const newValue = parseInt(e.target.value, 10);
    if (isNaN(newValue) || newValue < min) {
      onChange(min);
    } else if (newValue > max) {
      onChange(max);
    }
  };

  const isMinDisabled = disabled || value <= min;
  const isMaxDisabled = disabled || value >= max;

  return (
    <Div
      className={`inline-flex items-center border border-gray-300 dark:border-gray-600 rounded-lg ${classes.container} ${className}`}
    >
      {/* Ļ░Éņåī ļ▓äĒŖ╝ */}
      <Button
        type="button"
        onClick={handleDecrease}
        disabled={isMinDisabled}
        className={`${classes.button} flex items-center justify-center text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-700 disabled:opacity-50 disabled:cursor-not-allowed rounded-l-lg transition-colors`}
        aria-label="ņłśļ¤ē Ļ░Éņåī"
      >
        <Icon name="minus" className="w-4 h-4" />
      </Button>

      {/* ņłśļ¤ē ņ×ģļĀź */}
      <Input
        type="number"
        value={value}
        onChange={handleInputChange}
        onBlur={handleInputBlur}
        min={min}
        max={max}
        disabled={disabled}
        className={`${classes.input} text-center border-x border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 text-gray-900 dark:text-white focus:outline-none disabled:opacity-50 disabled:cursor-not-allowed [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none`}
        aria-label="ņłśļ¤ē"
      />

      {/* ņ”ØĻ░Ć ļ▓äĒŖ╝ */}
      <Button
        type="button"
        onClick={handleIncrease}
        disabled={isMaxDisabled}
        className={`${classes.button} flex items-center justify-center text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-700 disabled:opacity-50 disabled:cursor-not-allowed rounded-r-lg transition-colors`}
        aria-label="ņłśļ¤ē ņ”ØĻ░Ć"
      >
        <Icon name="plus" className="w-4 h-4" />
      </Button>
    </Div>
  );
};

export default QuantitySelector;
