import React from 'react';
import { Section as BaseSection } from '../basic/Section';
import { Div } from '../basic/Div';
import { H2 } from '../basic/H2';
import { P } from '../basic/P';

export interface SectionLayoutProps {
  /**
   * ņä╣ņģś ņĀ£ļ¬®
   */
  title?: string;

  /**
   * ņä╣ņģś ļČĆņĀ£ļ¬®
   */
  subtitle?: string;

  /**
   * Ēī©ļö® ņĀüņÜ®
   */
  padding?: 'none' | 'sm' | 'md' | 'lg' | 'xl';

  /**
   * ļ░░Ļ▓Įņāē
   */
  background?: 'none' | 'white' | 'gray' | 'primary' | 'secondary';

  /**
   * ņĄ£ļīĆ ļäłļ╣ä ņĀ£ĒĢ£
   */
  maxWidth?: 'sm' | 'md' | 'lg' | 'xl' | '2xl' | '4xl' | '6xl' | '7xl' | 'full';

  /**
   * ņżæņĢÖ ņĀĢļĀ¼ ņŚ¼ļČĆ
   */
  centered?: boolean;

  /**
   * Ļ▓ĮĻ│äņäĀ Ēæ£ņŗ£
   */
  border?: boolean;

  /**
   * ĻĘĖļ”╝ņ×É ĒÜ©Ļ│╝
   */
  shadow?: 'none' | 'sm' | 'md' | 'lg' | 'xl';

  /**
   * ļæźĻĘ╝ ļ¬©ņä£ļ”¼
   */
  rounded?: boolean;

  /**
   * ņé¼ņÜ®ņ×É ņĀĢņØś Ēü┤ļ×śņŖż
   */
  className?: string;

  /**
   * ņØĖļØ╝ņØĖ ņŖżĒāĆņØ╝
   */
  style?: React.CSSProperties;

  /**
   * ņ×ÉņŗØ ņÜöņåī
   */
  children?: React.ReactNode;

  /**
   * Ēü┤ļ”Ł ņØ┤ļ▓żĒŖĖ ĒĢĖļōżļ¤¼
   */
  onClick?: () => void;
}

/**
 * Section ļĀłņØ┤ņĢäņøā ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * ņŗ£ļ¦©Ēŗ▒ ĻĄ¼ņŚŁ ļČäĒĢĀņØä ņ£äĒĢ£ ņä╣ņģś ņ╗┤ĒÅ¼ļäīĒŖĖņ×ģļŗłļŗż.
 * ņĀ£ļ¬®, Ēī©ļö®, ļ░░Ļ▓Įņāē ļō▒ ļŗżņ¢æĒĢ£ ņśĄņģśņØä ņĀ£Ļ│ĄĒĢ®ļŗłļŗż.
 *
 * @example
 * // ĻĖ░ļ│Ė ņä╣ņģś
 * <Section padding="md" background="white">
 *   <p>Content here</p>
 * </Section>
 *
 * @example
 * // ņĀ£ļ¬®ņØ┤ ņ×łļŖö ņä╣ņģś
 * <Section
 *   title="ņé¼ņÜ®ņ×É ņĀĢļ│┤"
 *   subtitle="Ļ░£ņØĖ ņĀĢļ│┤ļź╝ Ļ┤Ćļ”¼ĒĢ®ļŗłļŗż"
 *   padding="lg"
 *   border
 * >
 *   <p>User details</p>
 * </Section>
 */
export const SectionLayout: React.FC<SectionLayoutProps> = ({
  title,
  subtitle,
  children,
  padding = 'md',
  background = 'none',
  maxWidth,
  centered = false,
  border = false,
  shadow = 'none',
  rounded = false,
  className = '',
  style,
  onClick,
}) => {
  // Tailwind CSS Ēü┤ļ×śņŖż ņāØņä▒
  const classes: string[] = [];

  // Ēī©ļö®
  const paddingMap: Record<string, string> = {
    none: 'p-0',
    sm: 'p-2',
    md: 'p-4',
    lg: 'p-6',
    xl: 'p-8',
  }; 
  classes.push(paddingMap[padding]);

  // ļ░░Ļ▓Įņāē
  const backgroundMap: Record<string, string> = {
    none: '',
    white: 'bg-white dark:bg-gray-700',
    gray: 'bg-gray-50 dark:bg-gray-800',
    primary: 'bg-blue-50 dark:bg-blue-900/20',
    secondary: 'bg-gray-50 dark:bg-gray-800',
  };
  if (background !== 'none') {
    classes.push(backgroundMap[background]);
  }

  // ņĄ£ļīĆ ļäłļ╣ä
  if (maxWidth) {
    const maxWidthMap: Record<string, string> = {
      sm: 'max-w-sm',
      md: 'max-w-md',
      lg: 'max-w-lg',
      xl: 'max-w-xl',
      '2xl': 'max-w-2xl',
      '4xl': 'max-w-4xl',
      '6xl': 'max-w-6xl',
      '7xl': 'max-w-7xl',
      full: 'max-w-full',
    };
    classes.push(maxWidthMap[maxWidth]);
  }

  // ņżæņĢÖ ņĀĢļĀ¼
  if (centered) {
    classes.push('mx-auto');
  }

  // Ļ▓ĮĻ│äņäĀ
  if (border) {
    classes.push('border', 'border-gray-200', 'dark:border-gray-700');
  }

  // ĻĘĖļ”╝ņ×É
  const shadowMap: Record<string, string> = {
    none: '',
    sm: 'shadow-sm',
    md: 'shadow-md',
    lg: 'shadow-lg',
    xl: 'shadow-xl',
  };
  if (shadow !== 'none') {
    classes.push(shadowMap[shadow]);
  }

  // ļæźĻĘ╝ ļ¬©ņä£ļ”¼
  if (rounded) {
    classes.push('rounded-lg');
  }

  // ņé¼ņÜ®ņ×É ņĀĢņØś Ēü┤ļ×śņŖż ņČöĻ░Ć
  if (className) {
    classes.push(className);
  }

  return (
    <BaseSection className={classes.join(' ')} style={style} onClick={onClick}>
      {/* ņĀ£ļ¬® ņśüņŚŁ */}
      {(title || subtitle) && (
        <Div className="mb-4">
          {title && <H2 className="text-2xl font-bold text-gray-900 dark:text-white">{title}</H2>}
          {subtitle && <P className="mt-1 text-sm text-gray-600 dark:text-gray-400">{subtitle}</P>}
        </Div>
      )}

      {/* ņĮśĒģÉņĖĀ ņśüņŚŁ */}
      {children}
    </BaseSection>
  );
};
