/**
 * setTheme ĒĢĖļōżļ¤¼
 *
 * ņé¼ņÜ®ņ×ÉĻ░Ć ņäĀĒāØĒĢ£ Ēģīļ¦ł(auto/light/dark)ļĪ£ ļ│ĆĻ▓ĮĒĢ®ļŗłļŗż.
 * localStorageņŚÉ g7_color_scheme Ļ░ÆņØä ņĀĆņ×źĒĢśĻ│Ā ņ”ēņŗ£ ņĀüņÜ®ĒĢ®ļŗłļŗż.
 *
 * daisyUI data-theme ņåŹņä▒ņ£╝ļĪ£ Ēģīļ¦łļź╝ ņĀäĒÖśĒĢ®ļŗłļŗż.
 * ĻĖ░ņĪ┤ ļĀłņØ┤ņĢäņøā JSONņØś dark: ņĀæļæÉņé¼ ĒśĖĒÖśņØä ņ£äĒĢ┤ .dark Ēü┤ļ×śņŖżļÅä ĒĢ©Ļ╗ś ĒåĀĻĖĆĒĢ®ļŗłļŗż.
 */

// Logger ņäżņĀĢ (G7Core ņ┤łĻĖ░ĒÖö ņĀäņŚÉļÅä ļÅÖņ×æĒĢśļÅäļĪØ ĒÅ┤ļ░▒ ĒÅ¼ĒĢ©)
const logger = ((window as any).G7Core?.createLogger?.('Handler:SetTheme')) ?? {
    log: (...args: unknown[]) => console.log('[Handler:SetTheme]', ...args),
    warn: (...args: unknown[]) => console.warn('[Handler:SetTheme]', ...args),
    error: (...args: unknown[]) => console.error('[Handler:SetTheme]', ...args),
};

/**
 * Ēģīļ¦ł ļ¬©ļō£ ĒāĆņ×ģ
 */
export type ThemeMode = 'auto' | 'light' | 'dark';

/**
 * ņ£ĀĒÜ©ĒĢ£ Ēģīļ¦ł ļ¬®ļĪØ
 */
const VALID_THEMES: ThemeMode[] = ['auto', 'light', 'dark'];

/**
 * daisyUI Ēģīļ¦ł ļ¦żĒĢæ
 * light/dark ļ¬©ļō£ņŚÉ ņé¼ņÜ®ĒĢĀ daisyUI Ēģīļ¦ł ņØ┤ļ”ä
 */
const DAISY_THEME_MAP = {
  light: 'light',
  dark: 'dark',
} as const;

/**
 * localStorage Ēéż (admin Ēģ£Ēöīļ”┐Ļ│╝ ļÅÖņØ╝)
 */
const STORAGE_KEY = 'g7_color_scheme';

/**
 * ņŗżņĀ£ ņĀüņÜ®ļÉĀ Ēģīļ¦ł Ļ▓░ņĀĢ (autoņØĖ Ļ▓ĮņÜ░ ņŗ£ņŖżĒģ£ ņäżņĀĢ ļ░śņśü)
 */
const getEffectiveTheme = (mode: ThemeMode): 'light' | 'dark' => {
  if (mode === 'auto') {
    return window.matchMedia('(prefers-color-scheme: dark)').matches
      ? 'dark'
      : 'light';
  }
  return mode;
};

/**
 * Ēģīļ¦ł ņĀüņÜ®
 *
 * document.documentElementņŚÉ data-theme ņåŹņä▒Ļ│╝ dark Ēü┤ļ×śņŖżļź╝ ņäżņĀĢĒĢ®ļŗłļŗż.
 * daisyUI Ēģīļ¦ł ļ¦żĒĢæņØä ĒåĄĒĢ┤ ļØ╝ņØ┤ĒŖĖ/ļŗżĒü¼ņŚÉ Ļ░üĻ░ü ļŗżļźĖ daisyUI Ēģīļ¦łļź╝ ņĀüņÜ®ĒĢ®ļŗłļŗż.
 */
const applyTheme = (mode: ThemeMode): void => {
  const effectiveTheme = getEffectiveTheme(mode);
  const daisyTheme = DAISY_THEME_MAP[effectiveTheme];

  // daisyUI Ēģīļ¦ł ņĀüņÜ® (data-themeļ¦ī ņé¼ņÜ®)
  document.documentElement.setAttribute('data-theme', daisyTheme);

  // .dark Ēü┤ļ×śņŖżļŖö ņØśļÅäņĀüņ£╝ļĪ£ ĒåĀĻĖĆĒĢśņ¦Ć ņĢŖņØī
  // CSS ļ│Ćņłś ļ¦żĒĢæņØ┤ daisyUI Ēģīļ¦ł ļ│Ćņłśļź╝ ĒåĄĒĢ┤ ļ¬©ļōĀ ņāēņāüņØä ņ×ÉļÅÖ ņ▓śļ”¼ĒĢśļ»ĆļĪ£
  // dark: ņĀæļæÉņé¼ Ēü┤ļ×śņŖżĻ░Ć ĒÖ£ņä▒ĒÖöļÉśļ®┤ ņāēņāüņØ┤ ļ░śņĀäļÉśņ¢┤ ņČ®ļÅīĒĢ©
  document.documentElement.classList.remove('dark');
};

/**
 * ņĀĆņ×źļÉ£ Ēģīļ¦łļź╝ ļĪ£ļō£ĒĢśņŚ¼ ņĀüņÜ®ĒĢ®ļŗłļŗż.
 *
 * Ēģ£Ēöīļ”┐ ņ┤łĻĖ░ĒÖö ņŗ£ ĒśĖņČ£ļÉśņ¢┤ localStorageņŚÉ ņĀĆņ×źļÉ£ Ēģīļ¦łļź╝ ņ”ēņŗ£ ņĀüņÜ®ĒĢ®ļŗłļŗż.
 */
export function initTheme(): void {
  try {
    const savedTheme = localStorage.getItem(STORAGE_KEY) as ThemeMode | null;
    const theme = savedTheme && VALID_THEMES.includes(savedTheme) ? savedTheme : 'auto';
    applyTheme(theme);
    logger.log('Initial theme applied:', theme);
  } catch (error) {
    logger.warn('Failed to load initial theme:', error);
    applyTheme('auto');
  }
}

/**
 * initTheme ĒĢĖļōżļ¤¼
 *
 * ļĀłņØ┤ņĢäņøāņØś init_actionsņŚÉņä£ ĒśĖņČ£ļÉśņ¢┤ ņ┤łĻĖ░ Ēģīļ¦łļź╝ ņĀüņÜ®ĒĢ®ļŗłļŗż.
 * ActionDispatcherņØś ņ╗żņŖżĒģĆ ĒĢĖļōżļ¤¼ ĒśĢņŗØņØä ļö░ļ”ģļŗłļŗż.
 *
 * target ĒīīļØ╝ļ»ĖĒä░Ļ░Ć ņĀäļŗ¼ļÉśļ®┤ ĒĢ┤ļŗ╣ Ēģīļ¦łļĪ£ ņ┤łĻĖ░ĒÖöĒĢ®ļŗłļŗż.
 * targetņØ┤ ņŚåĻ▒░ļéś ņ£ĀĒÜ©ĒĢśņ¦Ć ņĢŖņ£╝ļ®┤ localStorage ļśÉļŖö 'auto'ļź╝ ņé¼ņÜ®ĒĢ®ļŗłļŗż.
 *
 * @param action ņĢĪņģś ņĀĢņØś (targetņŚÉ Ēģīļ¦ł Ļ░Æ ĒÅ¼ĒĢ© Ļ░ĆļŖź)
 * @param _context ņĢĪņģś ņ╗©ĒģŹņŖżĒŖĖ (ņé¼ņÜ®ĒĢśņ¦Ć ņĢŖņØī)
 */
export async function initThemeHandler(
  action: any,
  _context?: any
): Promise<void> {
  // action.targetņØ┤ ļ░öņØĖļö® ĒĢ┤Ļ▓░ļÉ£ Ļ░Æņ£╝ļĪ£ ņĀäļŗ¼ļÉ© (ActionDispatcherņŚÉņä£ resolveValue ĒśĖņČ£)
  const targetTheme = action?.target;

  // targetņØ┤ ņ£ĀĒÜ©ĒĢ£ Ēģīļ¦ł Ļ░ÆņØĖ Ļ▓ĮņÜ░ ĒĢ┤ļŗ╣ Ēģīļ¦ł ņĀüņÜ®
  if (targetTheme && typeof targetTheme === 'string' && VALID_THEMES.includes(targetTheme as ThemeMode)) {
    applyTheme(targetTheme as ThemeMode);
    return;
  }

  // targetņØ┤ ņŚåĻ▒░ļéś ņ£ĀĒÜ©ĒĢśņ¦Ć ņĢŖņ£╝ļ®┤ ĻĖ░ņĪ┤ ļĪ£ņ¦ü (localStorage ļśÉļŖö auto)
  initTheme();
}

/**
 * Ēģīļ¦ł ļ│ĆĻ▓Į ĒĢĖļōżļ¤¼
 *
 * ActionDispatcherļŖö handler(action, context) ĒśĢĒā£ļĪ£ ĒśĖņČ£ĒĢ®ļŗłļŗż.
 * context Ļ░Øņ▓┤ņŚÉļŖö { data, event, props, state, setState, navigate } ļō▒ņØ┤ ĒÅ¼ĒĢ©ļÉ®ļŗłļŗż.
 *
 * @param action ņĢĪņģś ņĀĢņØś
 * @param context ņĢĪņģś ņ╗©ĒģŹņŖżĒŖĖ (ActionContext ĒāĆņ×ģ)
 */
export async function setThemeHandler(
  action: any,
  _context?: any
): Promise<void> {
  // 1. Ēģīļ¦ł Ļ░Æ ņČöņČ£
  let theme: string | undefined;

  // action.targetņØ┤ ļ░öņØĖļö® ĒĢ┤Ļ▓░ļÉ£ Ļ░Æņ£╝ļĪ£ ņĀäļŗ¼ļÉ© (ActionDispatcherņŚÉņä£ resolveValue ĒśĖņČ£)
  if (action?.target && typeof action.target === 'string' && !action.target.includes('{{')) {
    theme = action.target;
  }

  // 2. ņ£ĀĒÜ©ņä▒ Ļ▓Ćņ”Ø
  if (!theme || typeof theme !== 'string') {
    logger.warn('Invalid theme:', theme);
    return;
  }

  if (!VALID_THEMES.includes(theme as ThemeMode)) {
    logger.warn('Unsupported theme:', theme);
    return;
  }

  const validTheme = theme as ThemeMode;

  // 3. localStorageņŚÉ ņĀĆņ×ź
  try {
    localStorage.setItem(STORAGE_KEY, validTheme);
  } catch (error) {
    logger.error('Failed to save theme to localStorage:', error);
    return;
  }

  // 4. Ēģīļ¦ł ņ”ēņŗ£ ņĀüņÜ® (ĒÄśņØ┤ņ¦Ć ņāłļĪ£Ļ│Āņ╣© ņŚåņØ┤)
  applyTheme(validTheme);

  logger.log('Theme changed to:', validTheme);
}
