  content?: string;
  onChange?: (event: { target: { name: string; value: string } }) => void;
  isHtml?: boolean;
  onIsHtmlChange?: (event: { target: { name: string; checked: boolean } }) => void;
  rows?: number;
  placeholder?: string;
  label?: string;
  showHtmlModeToggle?: boolean;
  contentClassName?: string;
  purifyConfig?: any;
  className?: string;
  name?: string;
