/** Ēł┤ļ░ö ĻĄ¼ļČäņäĀ */
const Sep = () => <div className="w-px h-5 bg-gray-300 dark:bg-gray-600 mx-1" />;

/** ņØ┤ļ»Ėņ¦Ć ņŚģļĪ£ļō£ ĒĢ©ņłś */
async function uploadImage(file: File, boardSlug?: string, uploadPolicy?: string): Promise<string | null> {
  const formData = new FormData();
  formData.append('image', file);
  if (boardSlug) formData.append('board_slug', boardSlug);
  if (uploadPolicy) formData.append('upload_policy', uploadPolicy);

  try {
    // G7Core ApiClient ĒåĀĒü░ (localStorage)
    const authToken = localStorage.getItem('auth_token');

    const headers: Record<string, string> = { 'Accept': 'application/json' };
    if (authToken) headers['Authorization'] = `Bearer ${authToken}`;

    const res = await fetch('/api/plugins/sirsoft-imagetools/editor-upload', {
      method: 'POST',
      headers,
      body: formData,
    });

    if (!res.ok) {
      console.error('[HtmlEditor] ņØ┤ļ»Ėņ¦Ć ņŚģļĪ£ļō£ ņŗżĒī©:', res.status);
      return null;
    }
    const data = await res.json();
    return data?.data?.url || null;
  } catch (e) {
    console.error('[HtmlEditor] ņØ┤ļ»Ėņ¦Ć ņŚģļĪ£ļō£ ņŚÉļ¤¼:', e);
    return null;
  }
}

/** Tiptap Ēł┤ļ░ö */
const Toolbar: React.FC<{ editor: any; boardSlug?: string; uploadPolicy?: string }> = ({ editor, boardSlug, uploadPolicy }) => {
  if (!editor) return null;

  const addImage = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.multiple = true;
    input.onchange = async () => {
      const files = input.files;
      if (!files) return;
      for (const file of Array.from(files)) {
        const url = await uploadImage(file, boardSlug, uploadPolicy);
        if (url) editor.chain().focus().setImage({ src: url }).run();
      }
    };
    input.click();
  };

  const addLink = () => {
    const url = window.prompt('ļ¦üĒü¼ URLņØä ņ×ģļĀźĒĢśņäĖņÜö');
    if (url) {
      editor.chain().focus().extendMarkRange('link').setLink({ href: url }).run();
    } else {
      editor.chain().focus().extendMarkRange('link').unsetLink().run();
    }
  };

  return (
    <div className="flex flex-wrap items-center gap-0.5 px-2 py-1.5 border-b border-gray-200 dark:border-gray-600 bg-gray-50 dark:bg-gray-800 rounded-t-lg">
      <ToolbarButton onClick={() => editor.chain().focus().toggleBold().run()} isActive={editor.isActive('bold')} title="ĻĄĄĻ▓ī">
        <b>B</b>
      </ToolbarButton>
      <ToolbarButton onClick={() => editor.chain().focus().toggleItalic().run()} isActive={editor.isActive('italic')} title="ĻĖ░ņÜĖņ×ä">
        <i>I</i>
      </ToolbarButton>
      <ToolbarButton onClick={() => editor.chain().focus().toggleUnderline().run()} isActive={editor.isActive('underline')} title="ļ░æņżä">
        <u>U</u>
      </ToolbarButton>
      <ToolbarButton onClick={() => editor.chain().focus().toggleStrike().run()} isActive={editor.isActive('strike')} title="ņĘ©ņåīņäĀ">
        <s>S</s>
      </ToolbarButton>

      <Sep />

      <ToolbarButton onClick={() => editor.chain().focus().toggleHeading({ level: 2 }).run()} isActive={editor.isActive('heading', { level: 2 })} title="ņĀ£ļ¬® 2">
        H2
      </ToolbarButton>
      <ToolbarButton onClick={() => editor.chain().focus().toggleHeading({ level: 3 }).run()} isActive={editor.isActive('heading', { level: 3 })} title="ņĀ£ļ¬® 3">
        H3
      </ToolbarButton>

      <Sep />

      <ToolbarButton onClick={() => editor.chain().focus().toggleBulletList().run()} isActive={editor.isActive('bulletList')} title="ļ¬®ļĪØ">
        ŌĆó
      </ToolbarButton>
      <ToolbarButton onClick={() => editor.chain().focus().toggleOrderedList().run()} isActive={editor.isActive('orderedList')} title="ņł£ņä£ ļ¬®ļĪØ">
        1.
      </ToolbarButton>
      <ToolbarButton onClick={() => editor.chain().focus().toggleBlockquote().run()} isActive={editor.isActive('blockquote')} title="ņØĖņÜ®">
        &ldquo;
      </ToolbarButton>
      <ToolbarButton onClick={() => editor.chain().focus().toggleCodeBlock().run()} isActive={editor.isActive('codeBlock')} title="ņĮöļō£ļĖöļĪØ">
        {'</>'}
      </ToolbarButton>

      <Sep />

      <ToolbarButton onClick={() => editor.chain().focus().setTextAlign('left').run()} isActive={editor.isActive({ textAlign: 'left' })} title="ņÖ╝ņ¬Į ņĀĢļĀ¼">
        ŌēĪ
      </ToolbarButton>
      <ToolbarButton onClick={() => editor.chain().focus().setTextAlign('center').run()} isActive={editor.isActive({ textAlign: 'center' })} title="Ļ░ĆņÜ┤ļŹ░ ņĀĢļĀ¼">
        ŌēĪ
      </ToolbarButton>
      <ToolbarButton onClick={() => editor.chain().focus().setTextAlign('right').run()} isActive={editor.isActive({ textAlign: 'right' })} title="ņśżļźĖņ¬Į ņĀĢļĀ¼">
        ŌēĪ
      </ToolbarButton>

      <Sep />

      <ToolbarButton onClick={addLink} isActive={editor.isActive('link')} title="ļ¦üĒü¼">
        ­¤öŚ
      </ToolbarButton>
      <ToolbarButton onClick={addImage} title="ņØ┤ļ»Ėņ¦Ć">
        ­¤¢╝
      </ToolbarButton>

      <Sep />

      <ToolbarButton onClick={() => editor.chain().focus().insertTable({ rows: 3, cols: 3, withHeaderRow: true }).run()} title="Ēæ£ ņéĮņ×ģ">
        Ō¢”
      </ToolbarButton>
      <ToolbarButton onClick={() => editor.chain().focus().setHorizontalRule().run()} title="ĻĄ¼ļČäņäĀ">
        ŌĆĢ
      </ToolbarButton>

      <Sep />

      <ToolbarButton onClick={() => editor.chain().focus().undo().run()} title="ņŗżĒ¢ēņĘ©ņåī">
        Ōå®
      </ToolbarButton>
      <ToolbarButton onClick={() => editor.chain().focus().redo().run()} title="ļŗżņŗ£ņŗżĒ¢ē">
        Ōå¬
      </ToolbarButton>
    </div>
  );
};

export const HtmlEditor: React.FC<HtmlEditorProps> = ({
  content = '',
  onChange,
  isHtml: isHtmlProp = true,
  onIsHtmlChange,
  rows = 15,
  placeholder = '',
  label,
  showHtmlModeToggle = true,
  contentClassName = '',
  purifyConfig,
  className = '',
  name = 'content',
  htmlFieldName = 'content_mode',
  readOnly = false,
  boardSlug,
  imageUploadPolicy = 'member',
}) => {
  const isHtmlPropRef = React.useRef(isHtmlProp);
  const [isHtml, setIsHtml] = useState(true);
  const [sourceMode, setSourceMode] = useState(false);
  const [localContent, setLocalContent] = useState(content);

  useEffect(() => {
    if (isHtmlPropRef.current !== isHtmlProp) {
      isHtmlPropRef.current = isHtmlProp;
      setIsHtml(isHtmlProp);
    }
  }, [isHtmlProp]);
  useEffect(() => { setLocalContent(content); }, [content]);

  // onChange ņĮ£ļ░▒ ļ░£ņāØ
  const fireChange = useCallback((value: string) => {
    setLocalContent(value);
    if (onChange) {
      const event = G7Core()?.createChangeEvent?.({ value, name, type: 'textarea' })
        ?? { target: { name, value } };
      onChange(event);
    }
  }, [onChange, name]);

  // Tiptap ņŚÉļööĒä░ (HTML ļ¬©ļō£ņØ╝ ļĢī ņé¼ņÜ®)
  const editor = useEditor({
    extensions: [
      StarterKit.configure({ heading: { levels: [1, 2, 3, 4] } }),
      Underline,
      Image.configure({ inline: true }),
      Link.configure({ openOnClick: false }),
      Placeholder.configure({ placeholder }),
      TextAlign.configure({ types: ['heading', 'paragraph'] }),
      Table.configure({ resizable: true }),
      TableRow,
      TableCell,
      TableHeader,
    ],
    content: isHtml ? content : '',
    editable: !readOnly,
    onUpdate: ({ editor: ed }) => {
      fireChange(ed.getHTML());
    },
    editorProps: {
      handleDrop: (view, event, _slice, moved) => {
        if (moved || !event.dataTransfer?.files?.length) return false;
        const files = Array.from(event.dataTransfer.files).filter(f => f.type.startsWith('image/'));
        if (!files.length) return false;
        event.preventDefault();
        files.forEach(async (file) => {
          const url = await uploadImage(file, boardSlug, imageUploadPolicy);
          if (url) view.dispatch(view.state.tr.replaceSelectionWith(
            view.state.schema.nodes.image.create({ src: url })
          ));
        });
        return true;
      },
      handlePaste: (view, event) => {
        const items = event.clipboardData?.items;
        if (!items) return false;
        const imageItems = Array.from(items).filter(i => i.type.startsWith('image/'));
        if (!imageItems.length) return false;
        event.preventDefault();
        imageItems.forEach(async (item) => {
          const file = item.getAsFile();
          if (!file) return;
          const url = await uploadImage(file, boardSlug, imageUploadPolicy);
          if (url) view.dispatch(view.state.tr.replaceSelectionWith(
            view.state.schema.nodes.image.create({ src: url })
          ));
        });
        return true;
      },
    },
  });

  // content prop ļ│ĆĻ▓Į ņŗ£ ņŚÉļööĒä░ ļÅÖĻĖ░ĒÖö
  useEffect(() => {
    if (editor && isHtml && content !== editor.getHTML()) {
      editor.commands.setContent(content || '');
    }
  }, [content, editor, isHtml]);

  // ņåīņŖż ļ¬©ļō£ Ōåö ļ╣äņŻ╝ņ¢╝ ļ¬©ļō£ ņĀäĒÖś
  const handleSourceToggle = useCallback(() => {
    if (sourceMode && editor) {
      // ņåīņŖż ŌåÆ ļ╣äņŻ╝ņ¢╝: textarea ļé┤ņÜ®ņØä ņŚÉļööĒä░ņŚÉ ļ░śņśü
      editor.commands.setContent(localContent || '');
    } else if (!sourceMode && editor) {
      // ļ╣äņŻ╝ņ¢╝ ŌåÆ ņåīņŖż: ņŚÉļööĒä░ HTMLņØä textareaņŚÉ ļ░śņśü
      setLocalContent(editor.getHTML());
    }
    setSourceMode(!sourceMode);
  }, [sourceMode, editor, localContent]);

  // HTML ļ¬©ļō£ ļ│ĆĻ▓Į
  const handleHtmlModeChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const checked = e.target.checked;
    setIsHtml(checked);
    if (!checked) setSourceMode(false);

    // HTML ļ¬©ļō£ ņ╝ż ļĢī Ēśäņ×¼ ĒģŹņŖżĒŖĖļź╝ ņŚÉļööĒä░ņŚÉ ļĪ£ļō£
    if (checked && editor) {
      editor.commands.setContent(localContent || '');
    }
    // HTML ļ¬©ļō£ ļüī ļĢī ņŚÉļööĒä░ HTMLņØä ĒģŹņŖżĒŖĖļĪ£ Ļ░ĆņĀĖņśżĻĖ░
    if (!checked && editor) {
      fireChange(editor.getHTML());
    }

    if (onIsHtmlChange) {
      const event = G7Core()?.createChangeEvent?.({ checked, name: htmlFieldName, type: 'checkbox' })
        ?? { target: { name: htmlFieldName, checked } };
      onIsHtmlChange(event);
    }
  }, [onIsHtmlChange, htmlFieldName, editor, localContent, fireChange]);

  // ĒģŹņŖżĒŖĖ ļ¬©ļō£ onChange
  const handleTextChange = useCallback((e: React.ChangeEvent<HTMLTextAreaElement>) => {
    fireChange(e.target.value);
  }, [fireChange]);

  return (
    <Div className={`space-y-2 ${className}`}>
      {/* ļØ╝ļ▓© ļ░Å ļ¬©ļō£ ĒåĀĻĖĆ */}
      <Div className="flex items-center justify-between">
        {label && (
          <Label className="block text-sm font-medium text-gray-500 dark:text-gray-400">
            {label}
          </Label>
        )}
        <Div className="flex items-center gap-3">
          {/* ņåīņŖżņĮöļō£ ļ│┤ĻĖ░ (HTML ļ¬©ļō£ņØ╝ ļĢī) */}
          {isHtml && !readOnly && (
            <Button
              type="button"
              onClick={handleSourceToggle}
              className={`px-3 py-1.5 text-xs font-bold rounded-lg focus:outline-none ${
                sourceMode
                  ? 'text-blue-600 bg-blue-50 dark:bg-blue-900/30 border border-blue-300'
                  : 'text-gray-600 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 hover:bg-gray-50'
              }`}
            >
              {sourceMode ? 'HTML' : 'ņåīņŖż'}
            </Button>
          )}

          {showHtmlModeToggle && (
            <Label className="flex items-center gap-2 p-2 cursor-pointer">
              <Input
                type="checkbox"
                name={htmlFieldName}
                checked={isHtml}
                onChange={handleHtmlModeChange}
                disabled={readOnly}
                className="w-4 h-4 text-blue-600 bg-gray-100 border-gray-300 rounded focus:ring-blue-500"
              />
              <Div className="text-sm font-medium text-gray-700 dark:text-gray-300">
                {t('common.html_mode')}
              </Div>
            </Label>
          )}
        </Div>
      </Div>

      {/* HTML ļ¬©ļō£: Tiptap WYSIWYG */}
      {isHtml && !sourceMode && (
        <Div className="border border-gray-300 dark:border-gray-600 rounded-lg overflow-hidden bg-white dark:bg-gray-800">
          <Toolbar editor={editor} boardSlug={boardSlug} uploadPolicy={imageUploadPolicy} />
          <Div className="prose dark:prose-invert max-w-none px-4 py-3 min-h-[300px] focus-within:ring-1 focus-within:ring-blue-500 [&_.ProseMirror]:outline-none [&_.ProseMirror]:min-h-[280px] [&_.ProseMirror_p.is-editor-empty:first-child::before]:text-gray-400 [&_.ProseMirror_p.is-editor-empty:first-child::before]:content-[attr(data-placeholder)] [&_.ProseMirror_p.is-editor-empty:first-child::before]:float-left [&_.ProseMirror_p.is-editor-empty:first-child::before]:h-0 [&_.ProseMirror_p.is-editor-empty:first-child::before]:pointer-events-none [&_.ProseMirror_table]:border-collapse [&_.ProseMirror_td]:border [&_.ProseMirror_td]:border-gray-300 [&_.ProseMirror_td]:p-2 [&_.ProseMirror_th]:border [&_.ProseMirror_th]:border-gray-300 [&_.ProseMirror_th]:p-2 [&_.ProseMirror_th]:bg-gray-100 [&_.ProseMirror_img]:max-w-full [&_.ProseMirror_img]:rounded">
            <EditorContent editor={editor} />
          </Div>
        </Div>
      )}

      {/* HTML ļ¬©ļō£ ņåīņŖżņĮöļō£ ĒÄĖņ¦æ */}
      {isHtml && sourceMode && (
        <Textarea
          name={name}
          value={localContent}
          onChange={handleTextChange}
          placeholder={placeholder}
          rows={rows}
          readOnly={readOnly}
          className="block w-full rounded-lg border px-3 py-2 text-sm font-mono bg-white dark:bg-gray-800 border-blue-300 dark:border-blue-600 text-gray-800 dark:text-gray-200 focus:outline-none focus:ring-1 focus:border-blue-500 focus:ring-blue-500"
        />
      )}

      {/* ĒģŹņŖżĒŖĖ ļ¬©ļō£: ĻĖ░ņĪ┤ Textarea */}
      {!isHtml && (
        <Textarea
          name={name}
          value={localContent}
          onChange={handleTextChange}
          placeholder={placeholder}
          rows={rows}
          readOnly={readOnly}
          className="block w-full rounded-lg border px-3 py-2 text-sm bg-white dark:bg-gray-800 border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white focus:outline-none focus:ring-1 focus:border-blue-500 focus:ring-blue-500"
        />
      )}
    </Div>
  );
};
