import React, { useEffect, useRef } from 'react';
import { Div } from '../basic/Div';
import { Button } from '../basic/Button';
import { Icon } from '../basic/Icon';

// G7Core.t() ļ▓łņŚŁ ĒĢ©ņłś ņ░ĖņĪ░
const t = (key: string, params?: Record<string, string | number>) =>
  (window as any).G7Core?.t?.(key, params) ?? key;

export interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title?: string;
  /**
   * ĒāĆņØ┤ĒŗĆ ņśåņŚÉ Ēæ£ņŗ£ĒĢĀ ņĢäņØ┤ņĮś ņØ┤ļ”ä (Font Awesome)
   * @example "lock", "trash", "warning"
   */
  icon?: string;
  /**
   * ņĢäņØ┤ņĮś ņāēņāü Ēü┤ļ×śņŖż (Tailwind)
   * @default "text-gray-500"
   */
  iconClassName?: string;
  /**
   * Backdrop(ņśżļ▓äļĀłņØ┤) Ēü┤ļ”Ł ņŗ£ ļ¬©ļŗ¼ ļŗ½ĻĖ░ ņŚ¼ļČĆ
   * @default true
   */
  closeOnBackdropClick?: boolean;
  /**
   * closeOnOverlayClick ļ│äņ╣Ł (ļĀłņØ┤ņĢäņøā JSON ĒśĖĒÖś)
   * @default true
   */
  closeOnOverlayClick?: boolean;
  /**
   * ĒŚżļŹö ļŗ½ĻĖ░ ļ▓äĒŖ╝ Ēæ£ņŗ£ ņŚ¼ļČĆ
   * @default true
   */
  showCloseButton?: boolean;
  /**
   * ESC ĒéżļĪ£ ļ¬©ļŗ¼ ļŗ½ĻĖ░ ĒŚłņÜ® ņŚ¼ļČĆ
   * @default true
   */
  closeOnEscape?: boolean;
  children?: React.ReactNode;
  width?: string;
  className?: string;
  style?: React.CSSProperties;
}

/**
 * Modal ņ¦æĒĢ® ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * Div + Button ĻĖ░ļ│Ė ņ╗┤ĒÅ¼ļäīĒŖĖļź╝ ņĪ░ĒĢ®ĒĢśņŚ¼ ļ¬©ļŗ¼ UIļź╝ ĻĄ¼ņä▒ĒĢ®ļŗłļŗż.
 * ESC Ēéż ļŗ½ĻĖ░, ĒÅ¼ņ╗żņŖż ĒŖĖļ×®, ņśżļ▓äļĀłņØ┤ Ēü┤ļ”Ł ļŗ½ĻĖ░ ĻĖ░ļŖźņØä ĒÅ¼ĒĢ©ĒĢ®ļŗłļŗż.
 *
 * @example
 * // ļĀłņØ┤ņĢäņøā JSON ņé¼ņÜ® ņśłņŗ£
 * {
 *   "name": "Modal",
 *   "props": {
 *     "isOpen": "{{modals.userEdit}}",
 *     "title": "ņé¼ņÜ®ņ×É ĒÄĖņ¦æ",
 *     "width": "600px"
 *   },
 *   "children": [...]
 * }
 */
export const Modal: React.FC<ModalProps> = ({
  isOpen,
  onClose,
  title,
  icon,
  iconClassName = 'text-gray-500 dark:text-gray-400',
  closeOnBackdropClick = true,
  closeOnOverlayClick,
  showCloseButton = true,
  closeOnEscape = true,
  children,
  width = '500px',
  className = '',
  style,
}) => {
  // closeOnOverlayClick ļ│äņ╣Ł ņ¦ĆņøÉ (ļĀłņØ┤ņĢäņøā JSON ĒśĖĒÖś)
  const shouldCloseOnBackdrop = closeOnOverlayClick !== undefined
    ? closeOnOverlayClick
    : closeOnBackdropClick;
  const modalRef = useRef<HTMLDivElement>(null);
  const previousFocusRef = useRef<HTMLElement | null>(null);

  // ESC ĒéżļĪ£ ļ¬©ļŗ¼ ļŗ½ĻĖ░
  useEffect(() => {
    const handleEscape = (event: KeyboardEvent) => {
      if (event.key === 'Escape' && isOpen && closeOnEscape) {
        onClose();
      }
    };

    if (isOpen && closeOnEscape) {
      document.addEventListener('keydown', handleEscape);
      return () => document.removeEventListener('keydown', handleEscape);
    }
  }, [isOpen, onClose, closeOnEscape]);

  // ĒÅ¼ņ╗żņŖż ĒŖĖļ×®
  useEffect(() => {
    if (isOpen && modalRef.current) {
      // ļ¬©ļŗ¼ ņŚ┤ļ”┤ ļĢī Ēśäņ×¼ ĒÅ¼ņ╗żņŖż ņĀĆņ×ź
      previousFocusRef.current = document.activeElement as HTMLElement;

      // ļ¬©ļŗ¼ ļé┤ļČĆ ĒÅ¼ņ╗żņŖż Ļ░ĆļŖźĒĢ£ ņÜöņåīļōż
      const focusableElements = modalRef.current.querySelectorAll(
        'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
      );

      const firstElement = focusableElements[0] as HTMLElement;
      const lastElement = focusableElements[focusableElements.length - 1] as HTMLElement;

      // ņ▓½ ļ▓łņ¦Ė ņÜöņåīņŚÉ ĒÅ¼ņ╗żņŖż
      firstElement?.focus();

      // Tab Ēéż ĒĢĖļōżļ¤¼ (ĒÅ¼ņ╗żņŖż ĒŖĖļ×®)
      const handleTab = (event: KeyboardEvent) => {
        if (event.key !== 'Tab') return;

        if (event.shiftKey) {
          // Shift + Tab
          if (document.activeElement === firstElement) {
            event.preventDefault();
            lastElement?.focus();
          }
        } else {
          // Tab
          if (document.activeElement === lastElement) {
            event.preventDefault();
            firstElement?.focus();
          }
        }
      };

      document.addEventListener('keydown', handleTab);

      return () => {
        document.removeEventListener('keydown', handleTab);
        // ļ¬©ļŗ¼ ļŗ½Ē×É ļĢī ņØ┤ņĀä ĒÅ¼ņ╗żņŖż ļ│ĄņøÉ
        previousFocusRef.current?.focus();
      };
    }
  }, [isOpen]);

  // body ņŖżĒü¼ļĪż ļ░®ņ¦Ć
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      return () => {
        document.body.style.overflow = '';
      };
    }
  }, [isOpen]);

  if (!isOpen) return null;

  // z-indexļź╝ styleņŚÉņä£ Ļ░ĆņĀĖņśżĻ▒░ļéś ĻĖ░ļ│ĖĻ░Æ 50 ņé¼ņÜ®
  const zIndex = style?.zIndex ?? 50;

  return (
    <Div
      className="fixed inset-0 flex items-center justify-center"
      style={{ zIndex }}
      onClick={shouldCloseOnBackdrop ? onClose : undefined}
    >
      {/* Overlay */}
      <Div
        className="absolute inset-0 bg-black/50"
        aria-hidden="true"
      />

      {/* Modal Content - daisyUI modal-box */}
      <Div
        ref={modalRef}
        className={`modal-box relative ${className}`}
        style={{ width, maxWidth: width, ...(style ? { ...style, zIndex: undefined } : {}) }}
        onClick={(e) => e.stopPropagation()}
        role="dialog"
        aria-modal="true"
        aria-labelledby={title ? 'modal-title' : undefined}
      >
        {/* Header */}
        {(title || icon || showCloseButton) && (
          <Div className="flex items-center justify-between mb-4">
            {(title || icon) && (
              <Div
                id="modal-title"
                className="flex items-center gap-3 text-lg font-bold"
              >
                {icon && <Icon name={icon} size="md" className={iconClassName} />}
                {title}
              </Div>
            )}
            {showCloseButton && (
              <Button
                onClick={onClose}
                className="btn btn-sm btn-circle btn-ghost ml-auto"
                aria-label={t('common.close_modal')}
              >
                <svg
                  className="w-5 h-5"
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M6 18L18 6M6 6l12 12"
                  />
                </svg>
              </Button>
            )}
          </Div>
        )}

        {/* Body */}
        <Div className="overflow-y-auto max-h-[calc(90vh-140px)]">
          {children}
        </Div>
      </Div>
    </Div>
  );
};
