import React from 'react';
import { Modal } from './Modal';
import { Div } from '../basic/Div';
import { Button } from '../basic/Button';
import { P } from '../basic/P';
import { Span } from '../basic/Span';
import { I } from '../basic/I';

// G7Core.t() ļ▓łņŚŁ ĒĢ©ņłś ņ░ĖņĪ░
const t = (key: string, params?: Record<string, string | number>) =>
  (window as any).G7Core?.t?.(key, params) ?? key;

export interface ConfirmDialogProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  message: string | React.ReactNode;
  confirmText?: string;
  cancelText?: string;
  onConfirm: () => void;
  onCancel?: () => void;
  confirmButtonVariant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  cancelButtonVariant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  width?: string;
  closeOnOverlay?: boolean;
  /** ļĪ£ļö® ņżæ ņŚ¼ļČĆ (ĒÖĢņØĖ ļ▓äĒŖ╝ ļ╣äĒÖ£ņä▒ĒÖö ļ░Å ĒģŹņŖżĒŖĖ ļ│ĆĻ▓Į) */
  isLoading?: boolean;
  /** ļĪ£ļö® ņżæ ĒÖĢņØĖ ļ▓äĒŖ╝ņŚÉ Ēæ£ņŗ£ĒĢĀ ĒģŹņŖżĒŖĖ */
  loadingText?: string;
}

/**
 * ConfirmDialog ņ¦æĒĢ® ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * Modal ĻĖ░ļ░ś ĒÖĢņØĖ/ņĘ©ņåī ļŗżņØ┤ņ¢╝ļĪ£ĻĘĖ ņ╗┤ĒÅ¼ļäīĒŖĖ.
 * ņé¼ņÜ®ņ×ÉņŚÉĻ▓ī ĒÖĢņØĖņØä ņÜöņ▓ŁĒĢśĻ│Ā ĒÖĢņØĖ/ņĘ©ņåī ņżæ ĒĢśļéśļź╝ ņäĀĒāØĒĢśļÅäļĪØ ĒĢ®ļŗłļŗż.
 *
 * ĻĖ░ļ│Ė ņ╗┤ĒÅ¼ļäīĒŖĖ ņĪ░ĒĢ®:
 * - Modal > P(message) + Button(ĒÖĢņØĖ) + Button(ņĘ©ņåī)
 *
 * @example
 * // ļĀłņØ┤ņĢäņøā JSON ņé¼ņÜ® ņśłņŗ£
 * {
 *   "name": "ConfirmDialog",
 *   "props": {
 *     "isOpen": "{{dialogs.deleteConfirm}}",
 *     "title": "ņéŁņĀ£ ĒÖĢņØĖ",
 *     "message": "ņĀĢļ¦É ņØ┤ ĒĢŁļ¬®ņØä ņéŁņĀ£ĒĢśņŗ£Ļ▓ĀņŖĄļŗłĻ╣ī?",
 *     "confirmText": "ņéŁņĀ£",
 *     "cancelText": "$t:common.cancel",
 *     "confirmButtonVariant": "danger"
 *   }
 * }
 */
export const ConfirmDialog: React.FC<ConfirmDialogProps> = ({
  isOpen,
  onClose,
  title,
  message,
  confirmText,
  cancelText,
  onConfirm,
  onCancel,
  confirmButtonVariant = 'primary',
  // cancelButtonVariantļŖö Ēśäņ×¼ Ļ│ĀņĀĢ ņŖżĒāĆņØ╝ ņé¼ņÜ®ņ£╝ļĪ£ ļ»Ėņé¼ņÜ®
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  cancelButtonVariant: _cancelButtonVariant = 'secondary',
  width = '500px',
  // closeOnOverlayļŖö ModalņŚÉņä£ ņ▓śļ”¼ĒĢśļ»ĆļĪ£ ļ»Ėņé¼ņÜ®
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  closeOnOverlay: _closeOnOverlay = true,
  isLoading = false,
  loadingText,
}) => {
  // propsļĪ£ ņĀäļŗ¼ļÉ£ Ļ░ÆņØ┤ ņŚåņ£╝ļ®┤ ļŗżĻĄŁņ¢┤ Ēéż ņé¼ņÜ®
  const resolvedConfirmText = confirmText ?? t('common.confirm');
  const resolvedCancelText = cancelText ?? t('common.cancel');
  const resolvedLoadingText = loadingText ?? t('common.loading');

  const handleConfirm = () => {
    onConfirm();
  };

  const handleCancel = () => {
    // ļĪ£ļö® ņżæņŚÉļŖö ņĘ©ņåī ļČłĻ░Ć
    if (isLoading) return;
    onCancel?.();
    onClose();
  };

  const handleClose = () => {
    // ļĪ£ļö® ņżæņŚÉļŖö ļŗ½ĻĖ░ ļČłĻ░Ć
    if (isLoading) return;
    onClose();
  };

  // ļ▓äĒŖ╝ variantļ│ä ņŖżĒāĆņØ╝ ļ¦żĒĢæ
  const confirmVariantClassMap: Record<'primary' | 'secondary' | 'danger' | 'ghost', string> = {
    primary: 'bg-blue-600 text-white hover:bg-blue-700',
    secondary: 'bg-gray-200 dark:bg-gray-700 text-gray-800 dark:text-gray-200 hover:bg-gray-300 dark:hover:bg-gray-600',
    danger: 'bg-red-600 text-white hover:bg-red-700',
    ghost: 'bg-transparent text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700',
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={handleClose}
      title={title}
      width={width}
    >
      {/* ļ│Ėļ¼Ė */}
      <Div className="py-2">
        {typeof message === 'string' ? (
          <P className="text-gray-700 dark:text-gray-300">{message}</P>
        ) : (
          message
        )}
      </Div>

      {/* ĒæĖĒä░ (ļ▓äĒŖ╝ ņśüņŚŁ) */}
      <Div className="flex justify-end gap-3 mt-6">
        {/* ņĘ©ņåī ļ▓äĒŖ╝ */}
        <Button
          onClick={handleCancel}
          disabled={isLoading}
          className="px-4 py-2 bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-300 border border-gray-300 dark:border-gray-600 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 disabled:opacity-50 disabled:cursor-not-allowed"
        >
          <Span>{resolvedCancelText}</Span>
        </Button>

        {/* ĒÖĢņØĖ ļ▓äĒŖ╝ */}
        <Button
          onClick={handleConfirm}
          disabled={isLoading}
          className={`flex items-center gap-2 px-4 py-2 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed ${confirmVariantClassMap[confirmButtonVariant]}`}
        >
          {isLoading && (
            <I className="fa-solid fa-spinner w-4 h-4 animate-spin" />
          )}
          <Span>{isLoading ? resolvedLoadingText : resolvedConfirmText}</Span>
        </Button>
      </Div>
    </Modal>
  );
};
