import React from 'react';
import { IconName, IconStyle, IconSize, iconNameMap } from './IconTypes';

export interface IconProps extends Omit<React.HTMLAttributes<HTMLElement>, 'style'> {
  /**
   * ņĢäņØ┤ņĮś ņØ┤ļ”ä (Font Awesome Ēü┤ļ×śņŖżļ¬ģ ļśÉļŖö IconName enum)
   *
   * @example
   * // ļ¼Ėņ×ÉņŚ┤ļĪ£ ņ¦üņĀæ ņ¦ĆņĀĢ
   * <Icon name="fa-user" />
   *
   * // enum ņé¼ņÜ® (ĒāĆņ×ģ ņĢłņĀä)
   * <Icon name={IconName.User} />
   */
  name: string | IconName;

  /**
   * ņĢäņØ┤ņĮś ņŖżĒāĆņØ╝ (Font Awesome 5/6)
   *
   * - solid: fas (ĻĖ░ļ│ĖĻ░Æ)
   * - regular: far
   * - light: fal
   * - duotone: fad
   * - brands: fab
   */
  iconStyle?: IconStyle;

  /**
   * CSS ņŖżĒāĆņØ╝ Ļ░Øņ▓┤ (HTML style ņåŹņä▒)
   */
  style?: React.CSSProperties;

  /**
   * ņĢäņØ┤ņĮś Ēü¼ĻĖ░
   *
   * @default 'md'
   */
  size?: IconSize;

  /**
   * ņāēņāü (Tailwind Ēü┤ļ×śņŖż ļśÉļŖö CSS ņāēņāü)
   */
  color?: string;

  /**
   * ĒÜīņĀä ņĢĀļŗłļ®öņØ┤ņģś ĒÖ£ņä▒ĒÖö
   */
  spin?: boolean;

  /**
   * ĒÄäņŖż ņĢĀļŗłļ®öņØ┤ņģś ĒÖ£ņä▒ĒÖö (8ļŗ©Ļ│ä ĒÜīņĀä)
   */
  pulse?: boolean;

  /**
   * Ļ│ĀņĀĢ ļäłļ╣ä (ņĢäņØ┤ņĮś ņĀĢļĀ¼ ņŗ£ ņ£ĀņÜ®)
   */
  fixedWidth?: boolean;

  /**
   * ņĀæĻĘ╝ņä▒ ļĀłņØ┤ļĖö (ņ×ÉļÅÖ ņāØņä▒ Ļ░ĆļŖź)
   */
  ariaLabel?: string;
}

/**
 * Font Awesome ņĢäņØ┤ņĮś ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * Font Awesome 5/6 ļ▓äņĀäĻ│╝ ĒśĖĒÖśļÉśļ®░ ļŗżņ¢æĒĢ£ propsļź╝ ņ¦ĆņøÉĒĢ®ļŗłļŗż.
 *
 * @example
 * // ĻĖ░ļ│Ė ņé¼ņÜ®
 * <Icon name="fa-user" />
 *
 * // enum ņé¼ņÜ® (ĒāĆņ×ģ ņĢłņĀä)
 * <Icon name={IconName.Search} />
 *
 * // ņŖżĒāĆņØ╝ ļ░Å Ēü¼ĻĖ░ ņ¦ĆņĀĢ
 * <Icon name={IconName.Heart} style="regular" size="2x" />
 *
 * // ņĢĀļŗłļ®öņØ┤ņģś
 * <Icon name={IconName.Spinner} spin />
 * <Icon name={IconName.CircleNotch} pulse />
 *
 * // ņāēņāü ņ¦ĆņĀĢ
 * <Icon name={IconName.Star} color="text-yellow-500" />
 *
 * // ņĀæĻĘ╝ņä▒
 * <Icon name={IconName.User} ariaLabel="ņé¼ņÜ®ņ×É ĒöäļĪ£ĒĢä" />
 */
export const Icon: React.FC<IconProps> = ({
  name,
  iconStyle = 'solid',
  size,
  color,
  spin = false,
  pulse = false,
  fixedWidth = false,
  ariaLabel,
  className = '',
  style,
  ...props
}) => {
  // Font Awesome ņŖżĒāĆņØ╝ Ēü┤ļ×śņŖż ļ¦żĒĢæ
  const styleClassMap: Record<IconStyle, string> = {
    solid: 'fas',
    regular: 'far',
    light: 'fal',
    duotone: 'fad',
    brands: 'fab',
  };

  // ņĢäņØ┤ņĮś ņØ┤ļ”ä ņ▓śļ”¼: iconNameMapņØä ņé¼ņÜ®ĒĢśņŚ¼ Lucide ņŖżĒāĆņØ╝ ņØ┤ļ”äņØä FontAwesomeņ£╝ļĪ£ ļ│ĆĒÖś
  const rawName = typeof name === 'string' ? name : String(name);
  const mappedName = iconNameMap[rawName];
  // ļ¦żĒĢæļÉ£ ņØ┤ļ”äņØ┤ ņ×łņ£╝ļ®┤ ņé¼ņÜ®, ņŚåņ£╝ļ®┤ ņøÉļ│Ė ņé¼ņÜ® Ēøä 'fa-' ņĀæļæÉņé¼ ņĀ£Ļ▒░
  const iconName = mappedName
    ? String(mappedName).replace(/^fa-/, '')
    : rawName.replace(/^fa-/, '');

  // Ēü┤ļ×śņŖż ņĪ░ĒĢ®
  const classes = [
    styleClassMap[iconStyle],
    `fa-${iconName}`,
    size && `fa-${size}`,
    spin && 'fa-spin',
    pulse && 'fa-pulse',
    fixedWidth && 'fa-fw',
    color,
    className,
  ]
    .filter(Boolean)
    .join(' ');

  // ņĀæĻĘ╝ņä▒: ariaLabelņØ┤ ņŚåņ£╝ļ®┤ nameņŚÉņä£ ņāØņä▒
  const accessibilityLabel = ariaLabel || iconName.replace(/-/g, ' ');

  return (
    <i
      className={classes}
      style={style}
      aria-label={accessibilityLabel}
      role="img"
      {...props}
    />
  );
};
