import React, { useState, useEffect, useRef } from 'react';
import { Div } from '../basic/Div';
import { Button } from '../basic/Button';
import { Icon } from '../basic/Icon';
import { IconName } from '../basic/IconTypes';
import { Span } from '../basic/Span';

/**
 * Ēģīļ¦ł ļ¬©ļō£ ĒāĆņ×ģ
 */
export type ThemeMode = 'auto' | 'light' | 'dark';

/**
 * ThemeToggle Props
 */
export interface ThemeToggleProps {
  /** Ēģīļ¦ł ļ│ĆĻ▓Į ņĮ£ļ░▒ */
  onThemeChange?: (theme: ThemeMode) => void;
  /** ņČöĻ░Ć CSS Ēü┤ļ×śņŖż */
  className?: string;
  /** ņ×ÉļÅÖ ļ¬©ļō£ ĒģŹņŖżĒŖĖ (ļŗżĻĄŁņ¢┤ Ēéż ņé¼ņÜ® ĻČīņ×ź) */
  autoText?: string;
  /** ļØ╝ņØ┤ĒŖĖ ļ¬©ļō£ ĒģŹņŖżĒŖĖ (ļŗżĻĄŁņ¢┤ Ēéż ņé¼ņÜ® ĻČīņ×ź) */
  lightText?: string;
  /** ļŗżĒü¼ ļ¬©ļō£ ĒģŹņŖżĒŖĖ (ļŗżĻĄŁņ¢┤ Ēéż ņé¼ņÜ® ĻČīņ×ź) */
  darkText?: string;
}

/**
 * ThemeToggle ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * ļŗżĒü¼/ļØ╝ņØ┤ĒŖĖ ļ¬©ļō£ ņĀäĒÖś ļ▓äĒŖ╝
 * - 3Ļ░Ćņ¦Ć ļ¬©ļō£: ņ×ÉļÅÖ(ņŗ£ņŖżĒģ£ ņäżņĀĢ ļö░ļ”ä), ļØ╝ņØ┤ĒŖĖ, ļŗżĒü¼
 * - localStorageņŚÉ 'g7_color_scheme' ĒéżļĪ£ ņĀĆņ×ź (admin Ēģ£Ēöīļ”┐Ļ│╝ ļÅÖņØ╝)
 * - ņŗ£ņŖżĒģ£ prefers-color-scheme Ļ░Éņ¦Ć ņ¦ĆņøÉ
 *
 * @example
 * ```json
 * {
 *   "type": "composite",
 *   "name": "ThemeToggle",
 *   "props": {
 *     "autoText": "$t:common.theme.auto",
 *     "lightText": "$t:common.theme.light",
 *     "darkText": "$t:common.theme.dark"
 *   }
 * }
 * ```
 */

/**
 * ņŗżņĀ£ ņĀüņÜ®ļÉĀ Ēģīļ¦ł Ļ▓░ņĀĢ (autoņØĖ Ļ▓ĮņÜ░ ņŗ£ņŖżĒģ£ ņäżņĀĢ ļ░śņśü)
 */
const getEffectiveTheme = (mode: ThemeMode): 'light' | 'dark' => {
  if (mode === 'auto') {
    return window.matchMedia('(prefers-color-scheme: dark)').matches
      ? 'dark'
      : 'light';
  }
  return mode;
};

/**
 * daisyUI Ēģīļ¦ł ļ¦żĒĢæ
 * light/dark ļ¬©ļō£ņŚÉ ņé¼ņÜ®ĒĢĀ daisyUI Ēģīļ¦ł ņØ┤ļ”ä
 */
const DAISY_THEME_MAP = {
  light: 'light',
  dark: 'dark',
} as const;

/**
 * Ēģīļ¦ł ņĀüņÜ®
 *
 * daisyUI data-theme ņåŹņä▒ņ£╝ļĪ£ Ēģīļ¦łļź╝ ņĀäĒÖśĒĢ®ļŗłļŗż.
 * CSS ļ│Ćņłś ļ¦żĒĢæņØ┤ daisyUI Ēģīļ¦ł ļ│Ćņłśļź╝ ĒåĄĒĢ┤ ļ¬©ļōĀ ņāēņāüņØä ņ×ÉļÅÖ ņ▓śļ”¼ĒĢśļ»ĆļĪ£
 * .dark Ēü┤ļ×śņŖżļŖö ņé¼ņÜ®ĒĢśņ¦Ć ņĢŖņŖĄļŗłļŗż (dark: ņĀæļæÉņé¼ņÖĆ ņČ®ļÅī ļ░®ņ¦Ć).
 */
const applyTheme = (mode: ThemeMode) => {
  const effectiveTheme = getEffectiveTheme(mode);
  const daisyTheme = DAISY_THEME_MAP[effectiveTheme];
  document.documentElement.setAttribute('data-theme', daisyTheme);
  document.documentElement.classList.remove('dark');
};

/**
 * ņ┤łĻĖ░ Ēģīļ¦ł ļĪ£ļō£ ļ░Å ņĀüņÜ® (ņ”ēņŗ£ ņŗżĒ¢ē)
 * admin Ēģ£Ēöīļ”┐Ļ│╝ ļÅÖņØ╝ĒĢ£ localStorage Ēéż ņé¼ņÜ®: 'g7_color_scheme'
 */
const getInitialTheme = (): ThemeMode => {
  const savedTheme = localStorage.getItem('g7_color_scheme') as ThemeMode | null;
  if (savedTheme && ['auto', 'light', 'dark'].includes(savedTheme)) {
    return savedTheme;
  }
  return 'auto';
};

export const ThemeToggle: React.FC<ThemeToggleProps> = ({
  onThemeChange,
  className = '',
  autoText = 'System',
  lightText = 'Light',
  darkText = 'Dark',
}) => {
  // ņ┤łĻĖ░ Ēģīļ¦łļź╝ ņ”ēņŗ£ ļĪ£ļō£ĒĢśĻ│Ā ņĀüņÜ®
  const initialTheme = getInitialTheme();
  const [currentMode, setCurrentMode] = useState<ThemeMode>(initialTheme);
  const [showMenu, setShowMenu] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  /**
   * ņ╗┤ĒÅ¼ļäīĒŖĖ ļ¦łņÜ┤ĒŖĖ ņŗ£ ņ”ēņŗ£ Ēģīļ¦ł ņĀüņÜ®
   */
  useEffect(() => {
    applyTheme(currentMode);
  }, []);

  /**
   * ņŗ£ņŖżĒģ£ Ēģīļ¦ł ļ│ĆĻ▓Į Ļ░Éņ¦Ć
   */
  useEffect(() => {
    if (currentMode !== 'auto') return;

    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
    const handleChange = () => {
      applyTheme('auto');
    };

    mediaQuery.addEventListener('change', handleChange);
    return () => mediaQuery.removeEventListener('change', handleChange);
  }, [currentMode]);

  /**
   * ņÖĖļČĆ Ēü┤ļ”Ł Ļ░Éņ¦Ć
   */
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setShowMenu(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  /**
   * Ēģīļ¦ł ļ│ĆĻ▓Į ĒĢĖļōżļ¤¼
   * admin Ēģ£Ēöīļ”┐Ļ│╝ ļÅÖņØ╝ĒĢ£ localStorage Ēéż ņé¼ņÜ®: 'g7_color_scheme'
   */
  const handleThemeChange = (mode: ThemeMode) => {
    setCurrentMode(mode);
    localStorage.setItem('g7_color_scheme', mode);
    applyTheme(mode);
    setShowMenu(false);
    onThemeChange?.(mode);
  };

  /**
   * Ēśäņ×¼ Ēæ£ņŗ£ĒĢĀ ņĢäņØ┤ņĮś Ļ▓░ņĀĢ
   */
  const getCurrentIcon = (): IconName => {
    const effectiveTheme = getEffectiveTheme(currentMode);
    return effectiveTheme === 'dark' ? IconName.Moon : IconName.Sun;
  };

  return (
    <Div ref={menuRef} className={`relative ${className}`}>
      {/* Ēģīļ¦ł ĒåĀĻĖĆ ļ▓äĒŖ╝ */}
      <Button
        onClick={() => setShowMenu(!showMenu)}
        className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-lg transition-colors text-gray-600 dark:text-gray-400"
        aria-label="Toggle theme"
      >
        <Icon
          name={getCurrentIcon()}
          className="w-5 h-5"
        />
      </Button>

      {/* Ēģīļ¦ł ņäĀĒāØ ļō£ļĪŁļŗżņÜ┤ */}
      {showMenu && (
        <Div className="absolute right-0 mt-2 w-48 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg shadow-lg z-50">
          <Div className="py-2">
            {/* ņ×ÉļÅÖ ļ¬©ļō£ */}
            <Button
              onClick={() => handleThemeChange('auto')}
              className={`
                w-full px-4 py-2 text-left hover:bg-gray-50 dark:hover:bg-gray-700 flex items-center gap-3 transition-colors
                ${currentMode === 'auto' ? 'bg-gray-50 dark:bg-gray-700' : ''}
              `}
            >
              <Icon
                name={IconName.Settings}
                className="w-5 h-5 text-gray-600 dark:text-gray-400"
              />
              <Span className="flex-1 text-left text-gray-900 dark:text-white">{autoText}</Span>
              {currentMode === 'auto' && (
                <Icon
                  name={IconName.Check}
                  className="w-4 h-4 text-blue-600 dark:text-blue-400 ml-auto"
                />
              )}
            </Button>

            {/* ļØ╝ņØ┤ĒŖĖ ļ¬©ļō£ */}
            <Button
              onClick={() => handleThemeChange('light')}
              className={`
                w-full px-4 py-2 text-left hover:bg-gray-50 dark:hover:bg-gray-700 flex items-center gap-3 transition-colors
                ${currentMode === 'light' ? 'bg-gray-50 dark:bg-gray-700' : ''}
              `}
            >
              <Icon
                name={IconName.Sun}
                className="w-5 h-5 text-gray-600 dark:text-gray-400"
              />
              <Span className="flex-1 text-left text-gray-900 dark:text-white">{lightText}</Span>
              {currentMode === 'light' && (
                <Icon
                  name={IconName.Check}
                  className="w-4 h-4 text-blue-600 dark:text-blue-400 ml-auto"
                />
              )}
            </Button>

            {/* ļŗżĒü¼ ļ¬©ļō£ */}
            <Button
              onClick={() => handleThemeChange('dark')}
              className={`
                w-full px-4 py-2 text-left hover:bg-gray-50 dark:hover:bg-gray-700 flex items-center gap-3 transition-colors
                ${currentMode === 'dark' ? 'bg-gray-50 dark:bg-gray-700' : ''}
              `}
            >
              <Icon
                name={IconName.Moon}
                className="w-5 h-5 text-gray-600 dark:text-gray-400"
              />
              <Span className="flex-1 text-left text-gray-900 dark:text-white">{darkText}</Span>
              {currentMode === 'dark' && (
                <Icon
                  name={IconName.Check}
                  className="w-4 h-4 text-blue-600 dark:text-blue-400 ml-auto"
                />
              )}
            </Button>
          </Div>
        </Div>
      )}
    </Div>
  );
};

export default ThemeToggle;
