import { HandlerContext } from '../types';

interface FormatCurrencyParams {
  value: number;
  currencyCode?: string;
  locale?: string;
}

interface CurrencyConfig {
  code: string;
  symbol: string;
  locale: string;
  decimals: number;
}

/**
 * ĒåĄĒÖöļ│ä ĻĖ░ļ│Ė ņäżņĀĢ
 */
const CURRENCY_CONFIGS: Record<string, CurrencyConfig> = {
  KRW: { code: 'KRW', symbol: 'Ōé®', locale: 'ko-KR', decimals: 0 },
  USD: { code: 'USD', symbol: '$', locale: 'en-US', decimals: 2 },
  JPY: { code: 'JPY', symbol: '┬ź', locale: 'ja-JP', decimals: 0 },
  CNY: { code: 'CNY', symbol: '┬ź', locale: 'zh-CN', decimals: 2 },
  EUR: { code: 'EUR', symbol: 'Ōé¼', locale: 'de-DE', decimals: 2 },
};

/**
 * ņł½ņ×É Ļ░ÆņØä ĒåĄĒÖö ĒśĢņŗØņ£╝ļĪ£ ĒÅ¼ļ¦ĘĒīģĒĢ®ļŗłļŗż.
 *
 * @param params.value - ĒÅ¼ļ¦ĘĒīģĒĢĀ ņł½ņ×É Ļ░Æ
 * @param params.currencyCode - ĒåĄĒÖö ņĮöļō£ (KRW, USD, JPY ļō▒)
 * @param params.locale - ļĪ£ņ╝ĆņØ╝ (ņäĀĒāØ, ļ»Ėņ¦ĆņĀĢ ņŗ£ ĒåĄĒÖö ĻĖ░ļ│Ė ļĪ£ņ╝ĆņØ╝ ņé¼ņÜ®)
 * @param context - ĒĢĖļōżļ¤¼ ņ╗©ĒģŹņŖżĒŖĖ
 * @returns ĒÅ¼ļ¦ĘĒīģļÉ£ ĒåĄĒÖö ļ¼Ėņ×ÉņŚ┤
 *
 * @example
 * formatCurrencyHandler({ value: 10000, currencyCode: 'KRW' }, context)
 * // => "Ōé®10,000" ļśÉļŖö "10,000ņøÉ"
 *
 * formatCurrencyHandler({ value: 99.99, currencyCode: 'USD' }, context)
 * // => "$99.99"
 */
export function formatCurrencyHandler(
  params: FormatCurrencyParams,
  context: HandlerContext
): string {
  const { value, currencyCode, locale: customLocale } = params;
  const currency = currencyCode || context.getState('_global.preferredCurrency') || 'KRW';

  const config = CURRENCY_CONFIGS[currency] || CURRENCY_CONFIGS.KRW;
  const locale = customLocale || config.locale;

  try {
    return new Intl.NumberFormat(locale, {
      style: 'currency',
      currency: config.code,
      minimumFractionDigits: config.decimals,
      maximumFractionDigits: config.decimals,
    }).format(value);
  } catch {
    // Intl ņ¦ĆņøÉ ņĢł ļÉśļŖö ĒÖśĻ▓Į ĒÅ┤ļ░▒
    const formatted = value.toLocaleString(undefined, {
      minimumFractionDigits: config.decimals,
      maximumFractionDigits: config.decimals,
    });
    return `${config.symbol}${formatted}`;
  }
}

/**
 * ĒåĄĒÖö ņŗ¼ļ│╝ļ¦ī ļ░śĒÖśĒĢ®ļŗłļŗż.
 *
 * @param currencyCode - ĒåĄĒÖö ņĮöļō£
 * @returns ĒåĄĒÖö ņŗ¼ļ│╝
 */
export function getCurrencySymbol(currencyCode: string): string {
  return CURRENCY_CONFIGS[currencyCode]?.symbol || currencyCode;
}
