import React, { useRef, useCallback, useState, useEffect } from 'react';

export interface TextareaProps extends React.TextareaHTMLAttributes<HTMLTextAreaElement> {
  label?: string;
  error?: string;
}

/**
 * ĻĖ░ļ│Ė ĒģŹņŖżĒŖĖ ņśüņŚŁ ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * IME(ĒĢ£ĻĖĆ ļō▒) ņĪ░ĒĢ® ņżæņŚÉļŖö ņÖĖļČĆ onChange ņØ┤ļ▓żĒŖĖļź╝ ļ░£ņāØņŗ£Ēéżņ¦Ć ņĢŖņŖĄļŗłļŗż.
 * ļé┤ļČĆ ļĪ£ņ╗¼ ņāüĒā£ļź╝ ņé¼ņÜ®ĒĢśņŚ¼ ņ×ģļĀźņØä ņ▓śļ”¼ĒĢśĻ│Ā, ņĪ░ĒĢ®ņØ┤ ņÖäļŻīļÉśļ®┤ ņÖĖļČĆņŚÉ ņĢīļ”Įļŗłļŗż.
 */
export const Textarea: React.FC<TextareaProps> = ({
  label,
  error,
  className = '',
  onChange,
  value,
  defaultValue,
  ...props
}) => {
  // IME ņĪ░ĒĢ® ņżæņØĖņ¦Ć ņČöņĀü
  const isComposingRef = useRef(false);
  // textarea ņÜöņåī ņ░ĖņĪ░
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  // ļé┤ļČĆ ļĪ£ņ╗¼ Ļ░Æ (IME ņĪ░ĒĢ® ņżæņŚÉļÅä ĒÖöļ®┤ņŚÉ Ēæ£ņŗ£ļÉ©)
  const [localValue, setLocalValue] = useState<string>(
    (value as string) ?? (defaultValue as string) ?? ''
  );

  // ņÖĖļČĆ value propņØ┤ ļ│ĆĻ▓ĮļÉśļ®┤ ļĪ£ņ╗¼ Ļ░ÆļÅä ļÅÖĻĖ░ĒÖö
  useEffect(() => {
    if (!isComposingRef.current && value !== undefined) {
      setLocalValue(value as string);
    }
  }, [value]);

  const handleCompositionStart = useCallback(() => {
    isComposingRef.current = true;
  }, []);

  const handleCompositionEnd = useCallback(
    (e: React.CompositionEvent<HTMLTextAreaElement>) => {
      isComposingRef.current = false;
      // ņĪ░ĒĢ® ņÖäļŻī Ēøä onChange ņØ┤ļ▓żĒŖĖ ļ░£ņāØ
      if (onChange) {
        // Ēśäņ×¼ textareaņØś ņŗżņĀ£ Ļ░ÆņØä ņé¼ņÜ®
        const currentValue = (e.target as HTMLTextAreaElement).value;
        setLocalValue(currentValue);

        // ņāłļĪ£ņÜ┤ ChangeEvent ņāØņä▒
        const changeEvent = new Event('change', { bubbles: true }) as unknown as React.ChangeEvent<HTMLTextAreaElement>;
        Object.defineProperty(changeEvent, 'target', {
          writable: false,
          value: { value: currentValue },
        });
        Object.defineProperty(changeEvent, 'currentTarget', {
          writable: false,
          value: { value: currentValue },
        });

        onChange(changeEvent);
      }
    },
    [onChange]
  );

  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLTextAreaElement>) => {
      const newValue = e.target.value;
      // ĒĢŁņāü ļĪ£ņ╗¼ Ļ░ÆņØĆ ņŚģļŹ░ņØ┤ĒŖĖ (ĒÖöļ®┤ņŚÉ ņ×ģļĀźņØ┤ ļ│┤ņØ┤ļÅäļĪØ)
      setLocalValue(newValue);

      // IME ņĪ░ĒĢ® ņżæņØ┤ļ®┤ ņÖĖļČĆ onChangeļź╝ ĒśĖņČ£ĒĢśņ¦Ć ņĢŖņØī
      if (isComposingRef.current) {
        return;
      }
      if (onChange) {
        onChange(e);
      }
    },
    [onChange]
  );

  // HTML Ēæ£ņżĆ ņåŹņä▒ņØ┤ ņĢäļŗī Ļ▓āļōżņØä ĒĢäĒä░ļ¦ü (Ēģ£Ēöīļ”┐ ņŚöņ¦ä ļé┤ļČĆ ņåŹņä▒)
  const { loadingactions, formdata, ...validProps } = props as any;

  // controlled/uncontrolled ĻĄ¼ļČä
  const textareaValueProps = value !== undefined
    ? { value: localValue }
    : { defaultValue };

  return (
    <textarea
      ref={textareaRef}
      className={className}
      onChange={handleChange}
      onCompositionStart={handleCompositionStart}
      onCompositionEnd={handleCompositionEnd}
      {...textareaValueProps}
      {...validProps}
    />
  );
};
