import React, { useRef, useCallback, useState, useEffect, forwardRef, useImperativeHandle } from 'react';

export interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label?: string;
  error?: string;
}

/**
 * ĻĖ░ļ│Ė ņ×ģļĀź ĒĢäļō£ ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * IME(ĒĢ£ĻĖĆ ļō▒) ņĪ░ĒĢ® ņżæņŚÉļŖö ņÖĖļČĆ onChange ņØ┤ļ▓żĒŖĖļź╝ ļ░£ņāØņŗ£Ēéżņ¦Ć ņĢŖņŖĄļŗłļŗż.
 * ļé┤ļČĆ ļĪ£ņ╗¼ ņāüĒā£ļź╝ ņé¼ņÜ®ĒĢśņŚ¼ ņ×ģļĀźņØä ņ▓śļ”¼ĒĢśĻ│Ā, ņĪ░ĒĢ®ņØ┤ ņÖäļŻīļÉśļ®┤ ņÖĖļČĆņŚÉ ņĢīļ”Įļŗłļŗż.
 *
 * forwardRefļź╝ ņé¼ņÜ®ĒĢśņŚ¼ ņÖĖļČĆņŚÉņä£ refļĪ£ input ņÜöņåīņŚÉ ņĀæĻĘ╝ĒĢĀ ņłś ņ×łņŖĄļŗłļŗż.
 * ņśł: indeterminate ņāüĒā£ ņäżņĀĢ ņŗ£ ref.current.indeterminate = true
 */
export const Input = forwardRef<HTMLInputElement, InputProps>(({
  label,
  error,
  className = '',
  onChange,
  onKeyPress,
  value,
  defaultValue,
  type = 'text',
  checked,
  defaultChecked,
  ...props
}, ref) => {
  // radio/checkbox ĒāĆņ×ģņØĖņ¦Ć ĒÖĢņØĖ
  const isCheckableType = type === 'radio' || type === 'checkbox';

  // IME ņĪ░ĒĢ® ņżæņØĖņ¦Ć ņČöņĀü (text inputņŚÉļ¦ī ĒĢäņÜö)
  const isComposingRef = useRef(false);
  // input ņÜöņåī ņ░ĖņĪ░
  const internalRef = useRef<HTMLInputElement>(null);

  // ņÖĖļČĆ refņÖĆ ļé┤ļČĆ refļź╝ ņŚ░Ļ▓░
  useImperativeHandle(ref, () => internalRef.current as HTMLInputElement);

  // ļé┤ļČĆ ļĪ£ņ╗¼ Ļ░Æ (IME ņĪ░ĒĢ® ņżæņŚÉļÅä ĒÖöļ®┤ņŚÉ Ēæ£ņŗ£ļÉ©) - text inputņŚÉļ¦ī ņé¼ņÜ®
  const [localValue, setLocalValue] = useState<string>(
    (value as string) ?? (defaultValue as string) ?? ''
  );

  // ņÖĖļČĆ value propņØ┤ ļ│ĆĻ▓ĮļÉśļ®┤ ļĪ£ņ╗¼ Ļ░ÆļÅä ļÅÖĻĖ░ĒÖö (text inputņŚÉļ¦ī ņĀüņÜ®)
  useEffect(() => {
    if (!isCheckableType && !isComposingRef.current && value !== undefined) {
      setLocalValue(value as string);
    }
  }, [value, isCheckableType]);

  const handleCompositionStart = useCallback(() => {
    isComposingRef.current = true;
  }, []);

  const handleCompositionEnd = useCallback(
    (e: React.CompositionEvent<HTMLInputElement>) => {
      isComposingRef.current = false;
      // ņĪ░ĒĢ® ņÖäļŻī Ēøä onChange ņØ┤ļ▓żĒŖĖ ļ░£ņāØ
      if (onChange) {
        // Ēśäņ×¼ inputņØś ņŗżņĀ£ Ļ░ÆņØä ņé¼ņÜ®
        const currentValue = (e.target as HTMLInputElement).value;
        setLocalValue(currentValue);

        // ņāłļĪ£ņÜ┤ ChangeEvent ņāØņä▒
        const changeEvent = new Event('change', { bubbles: true }) as unknown as React.ChangeEvent<HTMLInputElement>;
        Object.defineProperty(changeEvent, 'target', {
          writable: false,
          value: { value: currentValue },
        });
        Object.defineProperty(changeEvent, 'currentTarget', {
          writable: false,
          value: { value: currentValue },
        });

        onChange(changeEvent);
      }
    },
    [onChange]
  );

  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const newValue = e.target.value;
      // ĒĢŁņāü ļĪ£ņ╗¼ Ļ░ÆņØĆ ņŚģļŹ░ņØ┤ĒŖĖ (ĒÖöļ®┤ņŚÉ ņ×ģļĀźņØ┤ ļ│┤ņØ┤ļÅäļĪØ)
      setLocalValue(newValue);

      // IME ņĪ░ĒĢ® ņżæņØ┤ļ®┤ ņÖĖļČĆ onChangeļź╝ ĒśĖņČ£ĒĢśņ¦Ć ņĢŖņØī
      if (isComposingRef.current) {
        return;
      }
      if (onChange) {
        onChange(e);
      }
    },
    [onChange]
  );

  const handleKeyPress = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      // IME ņĪ░ĒĢ® ņżæņØ┤ļ®┤ keypress ļ¼┤ņŗ£ (Enter ļō▒)
      if (isComposingRef.current) {
        return;
      }
      if (onKeyPress) {
        onKeyPress(e);
      }
    },
    [onKeyPress]
  );

  // HTML Ēæ£ņżĆ ņåŹņä▒ņØ┤ ņĢäļŗī Ļ▓āļōżņØä ĒĢäĒä░ļ¦ü (Ēģ£Ēöīļ”┐ ņŚöņ¦ä ļé┤ļČĆ ņåŹņä▒)
  const { loadingactions, formdata, ...validProps } = props as any;

  // radio/checkbox: checked ņåŹņä▒ ņé¼ņÜ®
  // text input: value ņåŹņä▒ ņé¼ņÜ® (IME ņ▓śļ”¼ ĒÅ¼ĒĢ©)
  if (isCheckableType) {
    return (
      <input
        ref={internalRef}
        type={type}
        className={className}
        onChange={onChange}
        checked={checked}
        defaultChecked={defaultChecked}
        value={value}
        {...validProps}
      />
    );
  }

  // text input: controlled/uncontrolled ĻĄ¼ļČä
  const inputProps = value !== undefined
    ? { value: localValue }
    : { defaultValue };

  return (
    <input
      ref={internalRef}
      type={type}
      className={className}
      onChange={handleChange}
      onKeyPress={handleKeyPress}
      onCompositionStart={handleCompositionStart}
      onCompositionEnd={handleCompositionEnd}
      {...inputProps}
      {...validProps}
    />
  );
});

// displayName ņäżņĀĢ (React DevToolsņŚÉņä£ ņ╗┤ĒÅ¼ļäīĒŖĖ ņØ┤ļ”ä Ēæ£ņŗ£)
Input.displayName = 'Input';