/**
 * Ēģ£Ēöīļ”┐ ļ®öĒāĆļŹ░ņØ┤Ēä░ export
 *
 * template.json ĒīīņØ╝ņØś ļé┤ņÜ®ņØä ļ▓łļōżņŚÉ ĒÅ¼ĒĢ©ņŗ£ņ╝£ API ĒśĖņČ£ ņŚåņØ┤
 * ņĮöņ¢┤ ņŚöņ¦äņŚÉņä£ ņ¦üņĀæ ņĀæĻĘ╝ Ļ░ĆļŖźĒĢśļÅäļĪØ ĒĢ®ļŗłļŗż.
 */
export { templateMetadata };

/**
 * Ēģ£Ēöīļ”┐ ņ┤łĻĖ░ĒÖö ĒĢ©ņłś
 *
 * ņĮöņ¢┤ ņŚöņ¦äņŚÉ ņ╗żņŖżĒģĆ ĒĢĖļōżļ¤¼ļź╝ ļō▒ļĪØĒĢ®ļŗłļŗż.
 */
export function initTemplate(): void {
  // ActionDispatcherĻ░Ć ļĪ£ļō£ļÉĀ ļĢīĻ╣īņ¦Ć ļīĆĻĖ░ Ēøä ĒĢĖļōżļ¤¼ ļō▒ļĪØ
  if (typeof window !== 'undefined') {
    let retryCount = 0;
    const maxRetries = 50; // ņĄ£ļīĆ 5ņ┤ł ļīĆĻĖ░ (50 * 100ms)

    const registerHandlers = () => {
      const actionDispatcher = (window as any).G7Core?.getActionDispatcher?.();

      if (actionDispatcher) {
        // handlerMapņØś ļ¬©ļōĀ ĒĢĖļōżļ¤¼ļź╝ ņ×ÉļÅÖņ£╝ļĪ£ ļō▒ļĪØ
        Object.entries(handlerMap).forEach(([name, handler]) => {
          actionDispatcher.registerHandler(name, handler);
        });

        logger.log(`${Object.keys(handlerMap).length} custom handler(s) registered:`, Object.keys(handlerMap));
      } else {
        retryCount++;
        if (retryCount <= maxRetries) {
          logger.warn(`ActionDispatcher not found, retrying... (${retryCount}/${maxRetries})`);
          setTimeout(registerHandlers, 100);
        } else {
          logger.error('Failed to register handlers: ActionDispatcher not available after maximum retries');
        }
      }
    };

    // window.load ņØ┤ļ▓żĒŖĖ ņé¼ņÜ® (ļ¬©ļōĀ ļ”¼ņåīņŖż ļĪ£ļō£ ņÖäļŻī Ēøä)
    if (document.readyState === 'complete') {
      registerHandlers();
    } else {
      window.addEventListener('load', registerHandlers);
    }
  }
}

// Ēģ£Ēöīļ”┐ ņ┤łĻĖ░ĒÖö ņ×ÉļÅÖ ņŗżĒ¢ē
initTemplate();
