import React, { useEffect, useState, useCallback } from 'react';
import { Div } from '../basic/Div';
import { Span } from '../basic/Span';
import { Button } from '../basic/Button';
import { Icon } from '../basic/Icon';
import { IconName } from '../basic/IconTypes';

/**
 * G7Core.t() ļ▓łņŚŁ ĒĢ©ņłś ņ░ĖņĪ░
 * ļ¤░ĒāĆņ×äņŚÉ G7Core.tļź╝ ņĀæĻĘ╝ĒĢśņŚ¼ ĒģīņŖżĒŖĖ ĒÖśĻ▓ĮņŚÉņä£ļÅä ļ¬©Ēé╣ņØ┤ ņĀüņÜ®ļÉśļÅäļĪØ ĒĢ©
 */
const getTranslation = (key: string, params?: Record<string, string | number>) => {
  const G7Core = (window as any).G7Core;
  return G7Core?.t?.(key, params) ?? key;
};

export type ToastType = 'success' | 'error' | 'warning' | 'info';
export type ToastPosition =
  | 'top-left'
  | 'top-center'
  | 'top-right'
  | 'bottom-left'
  | 'bottom-center'
  | 'bottom-right';

export interface ToastItem {
  id: string | number;
  type: ToastType;
  message: string;
  /** ņ╗żņŖżĒģĆ ņĢäņØ┤ņĮś ņØ┤ļ”ä (ņ¦ĆņĀĢĒĢśņ¦Ć ņĢŖņ£╝ļ®┤ ĒāĆņ×ģļ│ä ĻĖ░ļ│Ė ņĢäņØ┤ņĮś ņé¼ņÜ®) */
  icon?: string;
  /** Ļ░£ļ│ä ĒåĀņŖżĒŖĖ ņ×ÉļÅÖ ļŗ½Ē×ś ņŗ£Ļ░ä (ms) */
  duration?: number;
}

export interface ToastProps {
  /** ĒåĀņŖżĒŖĖ ļ░░ņŚ┤ (ņĀäņŚŁ ņāüĒā£ _global.toasts) */
  toasts?: ToastItem[] | null;
  /** ĒåĀņŖżĒŖĖ Ēæ£ņŗ£ ņ£äņ╣ś */
  position?: ToastPosition;
  /** ĻĖ░ļ│Ė ņ×ÉļÅÖ ļŗ½Ē×ś ņŗ£Ļ░ä (ms, ĻĖ░ļ│Ė 3000) */
  duration?: number;
  /** ĒåĀņŖżĒŖĖ ņĀ£Ļ▒░ ņĮ£ļ░▒ (ņĀäņŚŁ ņāüĒā£ ņŚģļŹ░ņØ┤ĒŖĖņÜ®) */
  onRemove?: (id: string | number) => void;
}

// ĒāĆņ×ģļ│ä ĻĖ░ļ│Ė ņĢäņØ┤ņĮś ļ¦żĒĢæ
const defaultIconMap: Record<ToastType, IconName> = {
  success: IconName.CheckCircle,
  error: IconName.XCircle,
  warning: IconName.ExclamationTriangle,
  info: IconName.InfoCircle,
};

// ĒāĆņ×ģļ│ä daisyUI alert ņŖżĒāĆņØ╝ ļ¦żĒĢæ
const typeStyleMap: Record<ToastType, { bg: string; text: string }> = {
  success: {
    bg: 'alert-success',
    text: '',
  },
  error: {
    bg: 'alert-error',
    text: '',
  },
  warning: {
    bg: 'alert-warning',
    text: '',
  },
  info: {
    bg: 'alert-info',
    text: '',
  },
};

// positionļ│ä ņŖżĒāĆņØ╝ ļ¦żĒĢæ
const positionClassMap: Record<ToastPosition, string> = {
  'top-left': 'top-4 left-4',
  'top-center': 'top-4 left-1/2 -translate-x-1/2',
  'top-right': 'top-4 right-4',
  'bottom-left': 'bottom-4 left-4',
  'bottom-center': 'bottom-4 left-1/2 -translate-x-1/2',
  'bottom-right': 'bottom-4 right-4',
};

/**
 * Toast ņ╗┤ĒÅ¼ļäīĒŖĖ
 *
 * ņĀäņŚŁ ņāüĒā£(_global.toasts)ļź╝ ĻĄ¼ļÅģĒĢśņŚ¼ ĒåĀņŖżĒŖĖ ņĢīļ”╝ņØä ņŖżĒāØņ£╝ļĪ£ Ēæ£ņŗ£ĒĢśļŖö ņ╗┤ĒÅ¼ļäīĒŖĖ.
 * ActionDispatcherņØś toast ĒĢĖļōżļ¤¼ņÖĆ ņŚ░ļÅÖļÉ®ļŗłļŗż.
 *
 * ĻĖ░ļŖź:
 * - ļŗżņżæ ĒåĀņŖżĒŖĖ ņŖżĒāØ ņ¦ĆņøÉ
 * - ĒāĆņ×ģļ│ä ņŖżĒāĆņØ╝ (success, error, warning, info)
 * - ņ╗żņŖżĒģĆ ņĢäņØ┤ņĮś ņ¦ĆņĀĢ Ļ░ĆļŖź
 * - Ļ░£ļ│ä ĒåĀņŖżĒŖĖ ņ×ÉļÅÖ ļŗ½Ē×ś ņŗ£Ļ░ä ņäżņĀĢ
 * - ņłśļÅÖ ļŗ½ĻĖ░ ļ▓äĒŖ╝
 *
 * @example
 * // ļĀłņØ┤ņĢäņøā JSON ņé¼ņÜ® ņśłņŗ£ (_user_base.json)
 * {
 *   "id": "global_toast",
 *   "type": "composite",
 *   "name": "Toast",
 *   "props": {
 *     "toasts": "{{_global.toasts}}",
 *     "position": "bottom-center",
 *     "duration": 3000
 *   }
 * }
 *
 * @example
 * // toast ĒĢĖļōżļ¤¼ ĒśĖņČ£ ņśłņŗ£ (ļĀłņØ┤ņĢäņøā JSON)
 * {
 *   "handler": "toast",
 *   "params": {
 *     "type": "success",
 *     "message": "$t:common.save_success",
 *     "icon": "check",
 *     "duration": 5000
 *   }
 * }
 */
export const Toast: React.FC<ToastProps> = ({
  toasts,
  position = 'bottom-center',
  duration = 3000,
  onRemove,
}) => {
  // ļé┤ļČĆņĀüņ£╝ļĪ£ Ēæ£ņŗ£ĒĢĀ ĒåĀņŖżĒŖĖ ņāüĒā£ Ļ┤Ćļ”¼ (ņĢĀļŗłļ®öņØ┤ņģśņÜ®)
  const [visibleToasts, setVisibleToasts] = useState<Map<string | number, boolean>>(new Map());

  // ĒåĀņŖżĒŖĖ ņĀ£Ļ▒░ ĒĢĖļōżļ¤¼
  const handleRemove = useCallback((id: string | number) => {
    // ļ©╝ņĀĆ ņł©Ļ╣Ć ņĢĀļŗłļ®öņØ┤ņģś ņŗ£ņ×æ
    setVisibleToasts(prev => {
      const next = new Map(prev);
      next.set(id, false);
      return next;
    });

    // ņĢĀļŗłļ®öņØ┤ņģś Ēøä ņŗżņĀ£ ņĀ£Ļ▒░
    setTimeout(() => {
      if (onRemove) {
        onRemove(id);
      } else {
        // onRemoveĻ░Ć ņŚåņ£╝ļ®┤ G7Core.state.updateļź╝ ĒåĄĒĢ┤ ņĀäņŚŁ ņāüĒā£ ņŚģļŹ░ņØ┤ĒŖĖ
        const G7Core = (window as any).G7Core;
        if (G7Core?.state?.update) {
          G7Core.state.update((prevState: Record<string, any>) => {
            const currentToasts = Array.isArray(prevState.toasts) ? prevState.toasts : [];
            return {
              toasts: currentToasts.filter((t: ToastItem) => t.id !== id),
            };
          });
        }
      }
    }, 300);
  }, [onRemove]);

  // ņāł ĒåĀņŖżĒŖĖĻ░Ć ņČöĻ░ĆļÉśļ®┤ visible ņāüĒā£ ņäżņĀĢ ļ░Å ņ×ÉļÅÖ ņĀ£Ļ▒░ ĒāĆņØ┤ļ©Ė ņäżņĀĢ
  useEffect(() => {
    if (!toasts || toasts.length === 0) return;

    toasts.forEach(toast => {
      // ņØ┤ļ»Ė ņ▓śļ”¼ļÉ£ ĒåĀņŖżĒŖĖļŖö Ļ▒┤ļäłļ£Ć
      if (visibleToasts.has(toast.id)) return;

      // visible ņāüĒā£ ņČöĻ░Ć
      setVisibleToasts(prev => {
        const next = new Map(prev);
        next.set(toast.id, true);
        return next;
      });

      // ņ×ÉļÅÖ ņĀ£Ļ▒░ ĒāĆņØ┤ļ©Ė ņäżņĀĢ
      const effectiveDuration = toast.duration || duration;
      if (effectiveDuration > 0) {
        setTimeout(() => {
          handleRemove(toast.id);
        }, effectiveDuration);
      }
    });
  }, [toasts, duration, handleRemove, visibleToasts]);

  // ĒåĀņŖżĒŖĖĻ░Ć ņŚåņ£╝ļ®┤ ļĀīļŹöļ¦üĒĢśņ¦Ć ņĢŖņØī
  if (!toasts || toasts.length === 0) {
    return null;
  }

  return (
    <Div
      className={`fixed z-[9999] flex flex-col gap-2 ${positionClassMap[position]}`}
      aria-live="polite"
      aria-atomic="true"
    >
      {toasts.map((toast) => (
        <ToastItemComponent
          key={toast.id}
          toast={toast}
          position={position}
          isVisible={visibleToasts.get(toast.id) ?? true}
          onClose={() => handleRemove(toast.id)}
        />
      ))}
    </Div>
  );
};

interface ToastItemComponentProps {
  toast: ToastItem;
  position: ToastPosition;
  isVisible: boolean;
  onClose: () => void;
}

const ToastItemComponent: React.FC<ToastItemComponentProps> = ({ toast, position, isVisible, onClose }) => {
  const typeStyle = typeStyleMap[toast.type] || typeStyleMap.info;

  // ņĢäņØ┤ņĮś Ļ▓░ņĀĢ: ņ╗żņŖżĒģĆ ņĢäņØ┤ņĮś > ĒāĆņ×ģļ│ä ĻĖ░ļ│Ė ņĢäņØ┤ņĮś
  const iconName = toast.icon
    ? (toast.icon as IconName)
    : defaultIconMap[toast.type];

  // positionņŚÉ ļö░ļØ╝ ņł©Ļ╣Ć ņĢĀļŗłļ®öņØ┤ņģś ļ░®Ē¢ź Ļ▓░ņĀĢ (top ŌåÆ ņ£äļĪ£, bottom ŌåÆ ņĢäļ×śļĪ£)
  const hideTranslate = position.startsWith('bottom') ? 'translate-y-2' : '-translate-y-2';

  return (
    <Div
      className={`
        alert shadow-lg
        min-w-[300px] max-w-md
        transition-all duration-300
        ${typeStyle.bg}
        ${isVisible ? 'opacity-100 translate-y-0' : `opacity-0 ${hideTranslate}`}
      `}
      role="alert"
    >
      <Icon
        name={iconName}
        className={`w-5 h-5 flex-shrink-0 ${typeStyle.text}`}
      />
      <Span className="flex-1 text-sm font-medium">
        {toast.message}
      </Span>
      <Button
        onClick={onClose}
        className="btn btn-sm btn-ghost btn-circle flex-shrink-0"
        aria-label={getTranslation('common.close')}
      >
        <Icon name={IconName.Times} className="w-4 h-4" />
      </Button>
    </Div>
  );
};

export default Toast;
